-- Poems batch 358
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('679a7573-28d7-429d-9cfb-43d04b20adc9','三月二十八日棗柏大士生辰二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','大千微塵偈，章句妙難求。',120,'全唐诗/poet.song.75000.json','["大千微塵偈，章句妙難求。", "公爲疏通之，如海決江流。", "堂堂鬚垂膺，漆點横清秋。", "十虚圓當念，三世集毛頭。", "平生說禪口，想見光迸浮。", "世間眼久滅，法寶空海洲。", "年年春欲暮，禪室清香留。", "迷途指南車，戴恩負山邱。", "願從清涼山，威光作依投。", "行當方山見，跬步披衣裘。"]'),
('93859d4c-1d5e-4e2c-aa12-b52633f4adf5','三月二十八日棗柏大士生辰二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','思慮不及處，但曰刹那際。',120,'全唐诗/poet.song.75000.json','["思慮不及處，但曰刹那際。", "不曰刹那際，寧當有三世。", "於此刹那中，尚不容擬議。", "安得有死生，一切諸怖畏。", "苦樂欣厭情，及分心境異。", "是名顛倒想，不名隨順智。", "如人游夢中，所歷經千歲。", "及其夢覺已，不過食頃耳。", "稽首願悲幢，發此不傳祕。", "願分無盡燈，酬此四弘誓。"]'),
('4550295c-a151-4307-b952-8b89ce12e5c9','送常上人歸黄龍省侍昭默老','釋德洪','宋','宋诗','song-poetry','','[]','心花發明照十方，死生窟宅無隱藏。',128,'全唐诗/poet.song.75000.json','["心花發明照十方，死生窟宅無隱藏。", "此老唾笑生馨香，法中骨髓僧中王。", "平生一子傳餘芳，譬如少林有神光。", "只今孤憤昭默堂，天魔外道走且僵。", "夢寐想見猶清涼，況子徑歸侍其傍。", "明日扁舟浮渺茫，我不得俱空歎傷。", "但餘一句煩寄將，幕阜山前爲舉揚。", "仰山久不見臨濟，瘦損法身三尺長。"]'),
('4d45ce33-6775-4afa-afdc-952c1dda1ca2','運禪人求偈','釋德洪','宋','宋诗','song-poetry','','[]','石室如仄磬，春雲如翠被。',144,'全唐诗/poet.song.75000.json','["石室如仄磬，春雲如翠被。", "翛然無事僧，來此時枕臂。", "無求即無憂，有身還有累。", "永懷彭尊宿，一席曾遁世。", "天子不得臣，公卿不敢致。", "高風不可攀，百世猶興起。", "運禪佳少年，杖錫成戾止。", "偶從城郭來，衣裓滿空翠。", "覓歸如子規，掉頭須去耳。", "山林與聚落，蜜無中邊味。", "子心有分别，動息若差異。", "錄以贈其行，不語開笑齒。"]'),
('a0195b2f-543c-4f31-bb5b-39a9e0ed5bf1','餞枯木成老赴南華之命','釋德洪','宋','宋诗','song-poetry','','[]','正中妙叶如何會，羅仙隱身露衣带。',160,'全唐诗/poet.song.75000.json','["正中妙叶如何會，羅仙隱身露衣带。", "芙蓉克家桐城孫，海上閒名聞至尊。", "天書夜到道林宫，大鐘横撞山𤤮瓏。", "山容光澤鳥聲樂，一番佳氣生巖叢。", "曹溪寶林甲天下，樓觀翔空盤萬瓦。", "夢中先已逢祖師，異世曾同香火社。", "人言骨清辟瘴霧，隘詞一律撩人怒。", "大陽直裰果有靈，所至自有天龍護。", "寄語山頭錫杖泉，久枯遽湧寧非天。", "老師不作奇特想，已脱聖凡情量纏。"]'),
('0bd34d7b-ffd8-401c-a8b5-d2e2cfc6e711','送禮禪歸臨川','釋德洪','宋','宋诗','song-poetry','','[]','已披出世衣，影莫落塵俗。',120,'全唐诗/poet.song.75000.json','["已披出世衣，影莫落塵俗。", "何山無叢林，棲息一枝足。", "奈何清淨心，甘受熱惱毒。", "譬如伏櫪馬，心不忘馳逐。", "又如火鐵丸，氣燄不可觸。", "禮禪客湘山，山翠在眉目。", "蓋嘗視此輩，高笑一捧腹。", "今亦欲還鄉，當戒前車覆。", "吾聞真實心，不受罪與福。", "精進緣不懈，此語君勿恧。"]'),
('288c9d2a-59e4-49ed-903d-bc419bcf3a7e','送顓街坊','釋德洪','宋','宋诗','song-poetry','','[]','水西南臺小精廬，名雖是律禪者居。',80,'全唐诗/poet.song.75000.json','["水西南臺小精廬，名雖是律禪者居。", "粥魚茶板如指呼，履聲童首鳧鴈趨。", "分身香積太闊迂，食時至則當持盂。", "養師反哺如烏雛，荷衆司更如鴈奴。", "逢人若問明白老，爲言病起加清癯。"]'),
('a6780c94-c16f-4bde-9ba1-a7ed976ba33a','寄南昌黄次山','釋德洪','宋','宋诗','song-poetry','','[]','次山心地平如鏡，照海照毛無少賸。',144,'全唐诗/poet.song.75000.json','["次山心地平如鏡，照海照毛無少賸。", "劉公訶之昏霧蒙，張公磨之復清瑩。", "張劉皆是善知識，大黄甘草各醫病。", "驚起荷山大字遂，𤤮瓏撞鐘山答應。", "夜燈午梵賽心願，望歸引領如鶴頸。", "一朝骨祖在面前，笑不成聲兩目瞪。", "小兒化去聊折災，婦翁告殂適其命。", "但得夫妻各身健，回觀閣中夜鳴磬。", "欲知成佛妙法門，不與人爭是捷徑。"]'),
('73f360a6-9759-4f03-8363-a29ea7b0a31e','寄題紫府普照寺滿上人桃花軒','釋德洪','宋','宋诗','song-poetry','','[]','武陵源深並溪入，無數桃花閙春色。',144,'全唐诗/poet.song.75000.json','["武陵源深並溪入，無數桃花閙春色。", "水面紅雲欲崩壞，波間爛錦光相射。", "昔人誤行偶見之，歸來醉眼眩紅碧。", "秦時雞犬不聞聲，但覺曉窗煙霧白。", "那知紫府亦仙源，此華萬樹燒晴川。", "少年苾芻誰教汝，照花作意開幽軒。", "靈雲說悟被花笑，南泉欺客花不言。", "何如睡足無一事，倚欄紅雨春風顛。", "愁來想見故山路，未歸先作山中篇。"]'),
('6073f811-fb0e-45bb-8f47-117f42b1480e','宋迪作八境絕妙人謂之無聲句演上人戲余曰道人能作有聲畫乎因爲之各賦一首 平沙落鴈','釋德洪','宋','宋诗','song-poetry','','[]','湖容秋色磨青銅，夕陽沙白光濛濛。',64,'全唐诗/poet.song.75000.json','["湖容秋色磨青銅，夕陽沙白光濛濛。", "翩翻欲下更嘔軋，十十五五依蘆叢。", "西興未歸愁欲老，日暮無雲天似掃。", "一聲風笛忽驚飛，羲之書空作行草。"]'),
('424c3347-be9e-4564-ab7d-5213f01e8fe5','宋迪作八境絕妙人謂之無聲句演上人戲余曰道人能作有聲畫乎因爲之各賦一首 遠浦歸帆','釋德洪','宋','宋诗','song-poetry','','[]','東風忽作羊角轉，坐看波面纖羅卷。',64,'全唐诗/poet.song.75000.json','["東風忽作羊角轉，坐看波面纖羅卷。", "日脚明邊白島横，江勢吞空客帆遠。", "倚欄心緒風絲亂，蒼茫初見疑鳧鴈。", "漸覺危檣隱映來，此時增損憑詩眼。"]'),
('217b01f6-8ff9-4a71-af87-af3d78306077','宋迪作八境絕妙人謂之無聲句演上人戲余曰道人能作有聲畫乎因爲之各賦一首 山市晴嵐','釋德洪','宋','宋诗','song-poetry','','[]','宿雨初收山氣重，炊煙日影林光動。',64,'全唐诗/poet.song.75000.json','["宿雨初收山氣重，炊煙日影林光動。", "蠶市漸休人已稀，市橋官柳金絲弄。", "隔谿誰家花滿畦，滑唇黄鳥春風啼。", "酒旗漠漠望可見，知在柘岡村路西。"]'),
('f6c4edca-178c-45bd-9a72-bae16de15cf7','宋迪作八境絕妙人謂之無聲句演上人戲余曰道人能作有聲畫乎因爲之各賦一首 江天暮雪','釋德洪','宋','宋诗','song-poetry','','[]','潑墨雲濃歸鳥滅，魂清忽作江天雪。',64,'全唐诗/poet.song.75000.json','["潑墨雲濃歸鳥滅，魂清忽作江天雪。", "一川秀發浩零亂，萬樹無聲寒妥帖。", "孤舟卧聽打窗扉，起看宵晴月正暉。", "忽驚盡卷青山去，更覺重攜春色歸。"]'),
('185ef8bd-d8ab-427e-9427-eacfa41bf107','宋迪作八境絕妙人謂之無聲句演上人戲余曰道人能作有聲畫乎因爲之各賦一首 洞庭秋月','釋德洪','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','橘香浦浦青黄出，維舟日暮柴荆側。',64,'全唐诗/poet.song.75000.json','["橘香浦浦青黄出，維舟日暮柴荆側。", "湧波好月如佳人，矜誇似弄嬋娟色。", "夜深河漢正無雲，風高掠水白紛紛。", "五更何處吹畫角，披衣起看低金盆。"]'),
('15be060e-ac5c-4572-8e28-8bb2e035b8bc','宋迪作八境絕妙人謂之無聲句演上人戲余曰道人能作有聲畫乎因爲之各賦一首 瀟湘夜雨','釋德洪','宋','宋诗','song-poetry','','[]','嶽麓軒窗方在目，雲生忽收圖畫軸。',64,'全唐诗/poet.song.75000.json','["嶽麓軒窗方在目，雲生忽收圖畫軸。", "軟風爲作白頭波，倒帆斷岸漁村宿。", "燈火荻叢營夜炊，波心應作出魚兒。", "絕憐清境平生事，蓬漏孤吟曉不知。"]'),
('f4ff9dcd-32bf-4105-9bc7-8f8fb0c99c33','宋迪作八境絕妙人謂之無聲句演上人戲余曰道人能作有聲畫乎因爲之各賦一首 烟寺晚鐘','釋德洪','宋','宋诗','song-poetry','','[]','十年車馬黄塵路，歲晚客心紛萬緒。',64,'全唐诗/poet.song.75000.json','["十年車馬黄塵路，歲晚客心紛萬緒。", "猛省一聲何處鐘，寺在烟村最深處。", "隔谿脩竹露人家，扁舟欲喚無人渡。", "紫藤瘦倚背西風，歸僧自入烟蘿去。"]'),
('28058752-4539-4d91-9f50-09fc3e537759','宋迪作八境絕妙人謂之無聲句演上人戲余曰道人能作有聲畫乎因爲之各賦一首 漁村落照','釋德洪','宋','宋诗','song-poetry','','[]','碧葦蕭蕭風淅瀝，村巷沙光潑殘日。',64,'全唐诗/poet.song.75000.json','["碧葦蕭蕭風淅瀝，村巷沙光潑殘日。", "隔籬炊黍香浮浮，對門登網銀戢戢。", "刺舟漸近桃花店，破鼻香來覺醇釅。", "舉籃就儂博一醉，卧看江山紅綠眩。"]'),
('53b40b1e-2f33-42f1-863f-5e0d947f6501','汪履道家觀雪鴈圖','釋德洪','宋','宋诗','song-poetry','','[]','水落陰湖洲渚生，風折敗荷枯葦莖。',64,'全唐诗/poet.song.75000.json','["水落陰湖洲渚生，風折敗荷枯葦莖。", "白沙鑿鑿墨雲重，熟視滿空翻玉英。", "湖邊兩鴈誰教汝，穩卧自多高世情。", "惠崇逸想巧圖畫，定應愛汝夢漏清。"]'),
('48431b11-54e1-40d1-b0a9-c7bbe75ea5ff','穎皋楚山堂秋景兩圖絕妙二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','一鷗低飛落平湖，一鷗驚顧行烱如。',64,'全唐诗/poet.song.75000.json','["一鷗低飛落平湖，一鷗驚顧行烱如。", "紅衣脱盡蓮蓬綠，翠蓋凋殘荷柄枯。", "更有數蓬癯已老，無人折之欲傾倒。", "陌上殘紅空自好，爲誰點綴湖邊草。"]'),
('fe2be072-923e-4b1b-b487-daccb0beac38','穎皋楚山堂秋景兩圖絕妙二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','溪邊兩鴨自夫婦，生而能言似相語。',64,'全唐诗/poet.song.75000.json','["溪邊兩鴨自夫婦，生而能言似相語。", "婦先浮波喜轉顧，夫欲隨之竟先去。", "水際清蘋各占叢，風撼荷花已退紅。", "不見清香雲錦段，空餘霜葉伴枯蓬。"]'),
('f5365997-56c9-4342-9392-d3259032d9b7','和李令祈雪分韻得麓字','釋德洪','宋','宋诗','song-poetry','','[]','何處軥輈叫雲木，植杖松間逢白足。',64,'全唐诗/poet.song.75000.json','["何處軥輈叫雲木，植杖松間逢白足。", "一牛鳴地兩禪叢，窗户青紅照林麓。", "江寒雲怒相摹胡，雪意欲作先停蓄。", "連空推下翻玉英，想見軒渠笑捧腹。"]'),
('99f978ce-96ce-4b8f-996d-da18a7623362','和李班叔戲彩堂','釋德洪','宋','宋诗','song-poetry','','[]','李侯何以悦其親，戲著彩衣覓梨棗。',64,'全唐诗/poet.song.75000.json','["李侯何以悦其親，戲著彩衣覓梨棗。", "閑騎竹馬畫堂前，慈顔一笑自忘老。", "毛義捧檄難忘客，茆容殺雞終得道。", "愛公純孝配古人，甚欲卜鄰安井竈。"]'),
('74d4ec3a-c17a-4fb6-84bd-616f25f7c39a','送隆上人歸長沙','釋德洪','宋','宋诗','song-poetry','','[]','湘中樂哉山水國，道人歸去正秋色。',64,'全唐诗/poet.song.75000.json','["湘中樂哉山水國，道人歸去正秋色。", "拭目重看雲蓋雲，搓手新嘗橘洲橘。", "湘西幽居多故人，松下相逢應倚策。", "開軒萬頃鴨頭青，睡起一聲風月箔。"]'),
('bb71fe2e-8c95-4533-b79e-93d0c2698bea','六月十五日夜大雨夢瑩中','釋德洪','宋','宋诗','song-poetry','','[]','希夷先生海門住，久不見之想眉宇。',64,'全唐诗/poet.song.75000.json','["希夷先生海門住，久不見之想眉宇。", "夢中相見荔枝村，覺來一枕芭蕉雨。", "行藏顧影應自笑，世事吞聲不容數。", "從欲若士爲遠遊，莫作雲中隱身去。"]'),
('7403efa8-b295-489d-80d9-d871f9b1b1bb','予作海棠詩曰一株柳外墻頭見勝却千叢著雨時寓居百丈春晴上南原縱望萬株浩如海追前詩之失言相隨苾芻請記其事','釋德洪','宋','宋诗','song-poetry','','[]','□□積雨分陰晦，林光山色生精彩。',64,'全唐诗/poet.song.75000.json','["□□積雨分陰晦，林光山色生精彩。", "閑上南原看野棠，一川零亂紅如海。", "柳外一株何足道，戲語謗花今日悔。", "道人請我重賦詩，倉卒煩詞爲刪改。"]'),
('50b52dea-1dc1-4235-bc2e-fec4e4b3df4f','山寺早秋','釋德洪','宋','宋诗','song-poetry','','[]','千本蒼杉俱合抱，夕陰相映寒蟬噪。',64,'全唐诗/poet.song.75000.json','["千本蒼杉俱合抱，夕陰相映寒蟬噪。", "殘僧獨歸清入晝，秋色滿庭濃可掃。", "霜鐘初歇月未生，但覺篝燈一點明。", "階除環珮走流水，樓閣誦經童子聲。"]'),
('c03b091a-834d-4282-be21-7123beadf9d1','送僧歸雲巖','釋德洪','宋','宋诗','song-poetry','','[]','和氣津津出眉宇，平生快活隨緣住。',64,'全唐诗/poet.song.75000.json','["和氣津津出眉宇，平生快活隨緣住。", "憶昨思山林下來，如今却向城中去。", "燕子初飛簾幕風，海棠睡重清明雨。", "重唱龍山諸佛機，紅塵動處雲成縷。"]'),
('f9860ccc-4070-4551-ac4a-b38172a4ceb1','至撫州崇仁縣寄彭思禹奉議兄四首  其一','釋德洪','宋','宋诗','song-poetry','','[]','去年歲饑民減口，晨無炊煙閒甑缶。',64,'全唐诗/poet.song.75000.json','["去年歲饑民減口，晨無炊煙閒甑缶。", "面餘菜色短氣中，經營有錢易升斗。", "抱孫買鋤今歲豐，黄雲𥝧稏村村同。", "東林鼓聲是誰致，聰明慈惠隴西公。"]'),
('479b8461-2afd-4957-897a-44a38764db5c','至撫州崇仁縣寄彭思禹奉議兄四首  其二','釋德洪','宋','宋诗','song-poetry','','[]','吏姦今古同一律，邇來間見復層出。',64,'全唐诗/poet.song.75000.json','["吏姦今古同一律，邇來間見復層出。", "一邑雀息行鏡中，公則生明無别術。", "放衙下簾調索絃，來禽青李浴清泉。", "吾儕呈押日課辦，亦作岸巾相對眠。"]'),
('a7b417f3-e504-429b-ab19-621538b2e6bd','至撫州崇仁縣寄彭思禹奉議兄四首  其三','釋德洪','宋','宋诗','song-poetry','','[]','我年政如牧民術，敗羣者去羊蕃息。',64,'全唐诗/poet.song.75000.json','["我年政如牧民術，敗羣者去羊蕃息。", "向來盗竊如有盟，飛躡垣墻度窗隙。", "下車夜户民不閉，終夕四鄰無犬吠。", "一懽醉倒不須歸，以塼支頭路傍睡。"]'),
('51848203-f7b4-4905-9c44-369d7f0fcbef','至撫州崇仁縣寄彭思禹奉議兄四首  其四','釋德洪','宋','宋诗','song-poetry','','[]','爭歌來爲民父母，百里民心始安堵。',64,'全唐诗/poet.song.75000.json','["爭歌來爲民父母，百里民心始安堵。", "外臺選才第薦之，何必知賢奪而去。", "當持馬足卧車轍，報汝百年終有别。", "蹄涔不著横海鯨，簿書那容萬人傑。"]'),
('4efa2a6a-78a0-4454-9f2e-b3e8813e548e','余還自海外至崇仁見思禹以四詩先焉既别又有太原之行已而幸歸石門復次前韻寄之以致山中之信云  其一','釋德洪','宋','宋诗','song-poetry','','[]','北去憂如會澠口，危甚相如跪瓦缶。',64,'全唐诗/poet.song.75000.json','["北去憂如會澠口，危甚相如跪瓦缶。", "南歸喜勝脱鴻門，那卹范增撞玉斗。", "筠谿野寺鄰新豐，亦與叢林魚鼓同。", "懸知他日君念我，定作少陵尋贊公。"]'),
('fb941f67-b6e8-4158-9f79-78b4f00dd3e2','余還自海外至崇仁見思禹以四詩先焉既别又有太原之行已而幸歸石門復次前韻寄之以致山中之信云  其二','釋德洪','宋','宋诗','song-poetry','','[]','脱梏寧知縛禪律，但欲閉門長不出。',64,'全唐诗/poet.song.75000.json','["脱梏寧知縛禪律，但欲閉門長不出。", "死禍平生九蹈之，痛恨防身苦無術。", "此言了如意在絃，此心烱如月臨泉。", "山中樂可驕稚世，一榻暑風清晝眠。"]'),
('258f9d6c-2e45-4bde-8189-3881167c101c','余還自海外至崇仁見思禹以四詩先焉既别又有太原之行已而幸歸石門復次前韻寄之以致山中之信云  其三','釋德洪','宋','宋诗','song-poetry','','[]','平生心懷濟時術，百未一施空歎息。',64,'全唐诗/poet.song.75000.json','["平生心懷濟時術，百未一施空歎息。", "庭閒晝永僧至門，心回酒醒月窺隙。", "東方先生語開閉，投骨心知致羣吠。", "千金珠在九重淵，儻能得之必龍睡。"]'),
('67678d78-4f03-4cc8-9c96-dd9e587f8c6d','余還自海外至崇仁見思禹以四詩先焉既别又有太原之行已而幸歸石門復次前韻寄之以致山中之信云  其四','釋德洪','宋','宋诗','song-poetry','','[]','飄零乳兒失慈母，來歸家山在阿堵。',64,'全唐诗/poet.song.75000.json','["飄零乳兒失慈母，來歸家山在阿堵。", "瘴痾烝洗百念空，但有詩情磨未去。", "虚名實禍車覆轍，道鄉端與人間别。", "膝穿木榻五十年，君看此翁亦雄傑。"]'),
('4502eab9-8f6a-4d7c-82f5-fbe425e6afe9','信上人自東林來請海印禪師過余湘上以贈之','釋德洪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','五湖東歸風轉柂，柔櫓聲中飛鳥過。',64,'全唐诗/poet.song.75000.json','["五湖東歸風轉柂，柔櫓聲中飛鳥過。", "開蓬不信是廬山，忽驚落瀑從空墮。", "道人箇中三十秋，那知今始載歸舟。", "白藕池邊月初吐，應對鄰房說舊遊。"]'),
('59ba947c-2e6d-4e42-b173-86d5a5770bda','忠子移居','釋德洪','宋','宋诗','song-poetry','','[]','忠子壁觀永皇暇，移居自提雙不借。',64,'全唐诗/poet.song.75000.json','["忠子壁觀永皇暇，移居自提雙不借。", "借車祭竈非我事，可聽夜舂響西舍。", "人言渠儂大類我，試手作詩便聲價。", "我詞勿學郊島寒，謫仙筆端能造化。"]'),
('026f18f2-9b09-4783-80e3-f24c1b4f8085','楞伽端介然見訪余以病未及謝先此寄之','釋德洪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','楞伽劇談喜高笑，一鉢安巢在雲杪。',64,'全唐诗/poet.song.75000.json','["楞伽劇談喜高笑，一鉢安巢在雲杪。", "我游廬山二十年，聞名常多識面少。", "道林過我古南臺，路逢泥軟手提□。", "臺輿瓦合今果爾，更呼鄰僧相與來。"]'),
('3cd61040-6f79-49b9-81e5-e8329b2f2905','次韻雲居寺','釋德洪','宋','宋诗','song-poetry','','[]','行盡崇岡與峻嶺，今朝又入緣雲徑。',64,'全唐诗/poet.song.75000.json','["行盡崇岡與峻嶺，今朝又入緣雲徑。", "世塵已覺蜕埃輕，道心遂作燖雞淨。", "小軒容膝俯千里，磨錢作鏡江山映。", "平生林壑竟成癖，南來獨覺兹遊勝。"]'),
('0f971e58-5e2c-43a1-a65e-d3bd9457d1c2','無學點茶乞詩','釋德洪','宋','宋诗','song-poetry','','[]','政和官焙來何處，雪後晴窗欣共煮。',64,'全唐诗/poet.song.75000.json','["政和官焙來何處，雪後晴窗欣共煮。", "銀缾瑟瑟過風雨，漸覺羊腸挽聲度。", "盞深扣之看浮乳，點茶三昧須饒汝。", "鷓鴣班中吸春露，□□□□□□□。"]'),
('21d16997-13e1-4fcc-9c0d-36fef75ac42e','巴川衲子求詩','釋德洪','宋','宋诗','song-poetry','','[]','水西南臺底氣象，綠疏青瑣湘江上。',64,'全唐诗/poet.song.75000.json','["水西南臺底氣象，綠疏青瑣湘江上。", "門人俯檻看諸方，笑聲散落千巖響。", "巴音衲子夜椎門，要識汾陽五世孫。", "問渠何所見而去，峰高難宿孤飛雲。"]'),
('fe339390-4a24-4454-a4cd-8d18fcbf6c92','十月桃','釋德洪','宋','宋诗','song-poetry','','[]','雪中桃花夜來折，兒稚犯寒爭欲摘。',48,'全唐诗/poet.song.75000.json','["雪中桃花夜來折，兒稚犯寒爭欲摘。", "老仙呵手撚吟筆，指以謂余還歎息。", "已作匆匆十月開，人間安得千年枝。"]'),
('1acbfe04-50b0-4d5a-afc0-567aad995ba5','李端叔誕辰','釋德洪','宋','宋诗','song-poetry','','[]','未見犯寒梅，已有催春雨。',52,'全唐诗/poet.song.75000.json','["未見犯寒梅，已有催春雨。", "催春春未歸，却有曇花飛。", "飛香塞世間，何人知鼻處。", "遙知與世且同波，隨分盤餐付兒女。"]'),
('40e7cc58-eda5-4b4f-85e0-c6f394282429','雨後得無象新詩次韻','釋德洪','宋','宋诗','song-poetry','','[]','雨餘步林幽，松風初到面。',52,'全唐诗/poet.song.75000.json','["雨餘步林幽，松風初到面。", "寒蟬相應鳴，小立無人見。", "但愛東南山，色作旋螺轉。", "入門庭院度飛螢，梵放哀聲滿深殿。"]'),
('c0d62229-aca4-4dae-bed2-4067d1ee038d','用韻寄誼叟','釋德洪','宋','宋诗','song-poetry','','[]','識君童牙中，豈止論半面。',52,'全唐诗/poet.song.75000.json','["識君童牙中，豈止論半面。", "雖同萬頃山，經年不相見。", "平生草頭露，蚌月跳珠轉。", "永懷終夜不成眠，但見突兀遊霄殿。"]'),
('15da1e30-a570-42d8-95d6-33b8c3f99e84','任价玉館東園十題 涵月亭','釋德洪','宋','宋诗','song-poetry','','[]','亭外物清曠，人間多熱惱。',48,'全唐诗/poet.song.75000.json','["亭外物清曠，人間多熱惱。", "夜晴登此亭，水月相媚皓。", "多君心鏡空，光明寫懷抱。", "憑誰持此意，舉似寒山老。"]'),
('34ceb284-2251-4e14-b7d0-5ee649dcb173','任价玉館東園十題 覽秀亭','釋德洪','宋','宋诗','song-poetry','','[]','尚記登臨時，風日初盎盎。',48,'全唐诗/poet.song.75000.json','["尚記登臨時，風日初盎盎。", "忽驚無邊春，登我眉睫上。", "情歡鳥聲樂，意適游絲放。", "我非連眉郎，搜詩聊植杖。"]'),
('8f1b7621-e9e2-4534-9f54-c7f1c2178167','任价玉館東園十題 四可亭','釋德洪','宋','宋诗','song-poetry','','[]','四注開野亭，面面可人意。',48,'全唐诗/poet.song.75000.json','["四注開野亭，面面可人意。", "我來俯危欄，蹇傲成縱倚。", "應接迷向背，轉顧風掠耳。", "鄰寺一聲鐘，墟落孤煙起。"]'),
('566ebf2c-7a77-4f82-9b99-4ffda02aff72','任价玉館東園十題 第一軒','釋德洪','宋','宋诗','song-poetry','','[]','名園富家致，此軒冠羣目。',48,'全唐诗/poet.song.75000.json','["名園富家致，此軒冠羣目。", "檻次狀元紅，窗横尊者竹。", "坐客定無雙，試茶谷簾綠。", "願聞聖諦義，飛辯横麈玉。"]'),
('b25ecefd-862d-4025-a543-4e7f19b4ba3e','任价玉館東園十題 如春軒','釋德洪','宋','宋诗','song-poetry','','[]','檻前揺綠玉，杯面吹紅鱗。',48,'全唐诗/poet.song.75000.json','["檻前揺綠玉，杯面吹紅鱗。", "主人飽談笑，和風熏坐賓。", "但覺天宇迥，塵滓欲清辰。", "雖非曲水會，自是斜川人。"]'),
('c836a893-11d9-4973-8ae7-02084ae0258f','任价玉館東園十題 寒亭','釋德洪','宋','宋诗','song-poetry','','[]','欲問春消息，蒼茫嫩日斜。',48,'全唐诗/poet.song.75000.json','["欲問春消息，蒼茫嫩日斜。", "茅簷聚喧雀，栗林棲暮鴉。", "絮袍褁足坐，得句往往佳。", "忽起步微月，呵手抝梅花。"]'),
('dd8b29bd-5311-42bc-aa38-8a05643a9b19','任价玉館東園十題 浩庵','釋德洪','宋','宋诗','song-poetry','','[]','水勝萬斛舟，至剛柔繞指。',48,'全唐诗/poet.song.75000.json','["水勝萬斛舟，至剛柔繞指。", "丈夫養浩然，其略蓋如此。", "朝登青雲上，正色決大事。", "暮歸卧此庵，捫虱口如耳。"]'),
('4fbdee90-8810-4e26-ab36-0d220db02ce6','任价玉館東園十題 方便堂','釋德洪','宋','宋诗','song-poetry','','[]','虚空亦何有，領略四時事。',48,'全唐诗/poet.song.75000.json','["虚空亦何有，領略四時事。", "君看繁盛時，中有凋零意。", "然省可自觀，那作明日計。", "當游無所還，自住三摩地。"]'),
('bfc6d06b-c834-4247-882b-2e5770acc2e9','任价玉館東園十題 覺庵','釋德洪','宋','宋诗','song-poetry','','[]','念起則爲凡，覺之則爲聖。',48,'全唐诗/poet.song.75000.json','["念起則爲凡，覺之則爲聖。", "人言此爲覺，此覺未真正。", "但了一切空，聖凡皆幻影。", "宴坐不言中，心波如古井。"]'),
('14e43cf9-d37d-4c44-84af-d9a767c0f8fb','任价玉館東園十題 鑒止軒','釋德洪','宋','宋诗','song-poetry','','[]','小軒臨止水，一泓湛寒碧。',48,'全唐诗/poet.song.75000.json','["小軒臨止水，一泓湛寒碧。", "瞭然見眉須，洞徹塵不隔。", "夫子作止觀，涇渭不相入。", "跏趺學僧禪，諦視鼻端白。"]'),
('cb203cbd-33f3-4f0b-b6a5-d60eeb867b3f','任价玉館東園十題 書華光墨梅','釋德洪','宋','宋诗','song-poetry','','[]','一枝已清妍，交枝更媚嫵。',48,'全唐诗/poet.song.75000.json','["一枝已清妍，交枝更媚嫵。", "見之已愁絕，那復隔煙雨。", "錢塘千頃春，想見西津渡。", "他日到南屏，莫忘孤山路。"]'),
('16a959de-4c27-47db-8e51-62841330480a','惠侍者清夢軒','釋德洪','宋','宋诗','song-poetry','','[]','小軒面層崖，叢蕉手自種。',48,'全唐诗/poet.song.75000.json','["小軒面層崖，叢蕉手自種。", "高風追二朗，生涯與師共。", "默坐毎觀身，爐煙作雲湧。", "蕭蕭半夜雨，亦足清君夢。"]'),
('c09bf84c-d194-407f-b9cb-8f32d798e60c','次韻性之','釋德洪','宋','宋诗','song-poetry','','[]','一笑形骸外，便能携手行。',48,'全唐诗/poet.song.75000.json','["一笑形骸外，便能携手行。", "雲容與山靨，今日眼偏明。", "共坐松下石，仰聽松上聲。", "古人亦何遠，安用社中名。"]'),
('402974c9-9523-4ed4-ad52-b72cf3fb5dbf','筠谿晚望','釋德洪','宋','宋诗','song-poetry','','[]','小谿倚春漲，攘我釣月灣。',48,'全唐诗/poet.song.75000.json','["小谿倚春漲，攘我釣月灣。", "新晴爲不平，約束晚來還。", "銀梭時撥刺，破碎波中山。", "整鈎背落日，一葉軟紅間。"]'),
('16481ab3-7947-4a54-ba27-1cbbcecd9d86','和杜撫勾古意六首  其一','釋德洪','宋','宋诗','song-poetry','','[]','一尾掣電去，萬蹄讓雄長。',48,'全唐诗/poet.song.75000.json','["一尾掣電去，萬蹄讓雄長。", "邇來隨磨驢，驅逐付厮養。", "頓塵忽驕嘶，逸韻發奇想。", "公眼如支遁，神駿蒙擊賞。"]'),
('d50b4b5b-7c11-42fb-912c-148ca7e032a1','和杜撫勾古意六首  其二','釋德洪','宋','宋诗','song-poetry','','[]','歲月走舟壑，不能老喬松。',48,'全唐诗/poet.song.75000.json','["歲月走舟壑，不能老喬松。", "何如取塵劫，安置彈指中。", "我老世不要，閉關師道蹤。", "自欣方得計，人笑伎之窮。"]'),
('4d8a76c7-abe1-49b6-b308-bd7de71493d4','和杜撫勾古意六首  其三','釋德洪','宋','宋诗','song-poetry','','[]','長松援丈蘿，無事登青冥。',48,'全唐诗/poet.song.75000.json','["長松援丈蘿，無事登青冥。", "因緣偶然爾，初非出經營。", "我受氣類似，掄材置勿聽。", "翟公亦癡絕，書門議交情。"]'),
('76291e83-4024-42e0-93f3-7e794e12ddfe','和杜撫勾古意六首  其四','釋德洪','宋','宋诗','song-poetry','','[]','午夢清斷續，殷鬢飛蚊鳴。',48,'全唐诗/poet.song.75000.json','["午夢清斷續，殷鬢飛蚊鳴。", "微風亦見戲，故掩讀殘經。", "相見洞天曉，霧重花冥冥。", "秀句吐奇麗，乃爾未忘情。"]'),
('1adc5e56-befc-4901-939c-63f031b5ee7e','和杜撫勾古意六首  其五','釋德洪','宋','宋诗','song-poetry','','[]','秋晚凋紅翠，幽懷到眉峰。',48,'全唐诗/poet.song.75000.json','["秋晚凋紅翠，幽懷到眉峰。", "玉纖弄彩筆，落紙翩驚鴻。", "道山歸計好，高情付疏慵。", "何獨謝夫人，特有林下風。"]'),
('8b7c66db-1705-4637-b329-fbba35ff80c7','和杜撫勾古意六首  其六','釋德洪','宋','宋诗','song-poetry','','[]','暮年一杯春，愁邊賴開拓。',48,'全唐诗/poet.song.75000.json','["暮年一杯春，愁邊賴開拓。", "醉鄉歸路穩，城郭見隱約。", "萬事付頽然，破幘風墮落。", "胸次竟何有，八窗洞空廓。"]'),
('b6d971df-ecd3-4936-a3c6-cea741435a7e','了翁有書與謝無逸云覺範真是比丘','釋德洪','宋','宋诗','song-poetry','','[]','墮馬哭淮王，牧羊仗漢節。',48,'全唐诗/poet.song.75000.json','["墮馬哭淮王，牧羊仗漢節。", "古人守忠義，視死如棄禊。", "吾是真比丘，死生見窟宅。", "一飯不願餘，孤坐閲歲月。"]'),
('03fcedd4-4e36-491e-ad3d-2b828eef9c5c','題延福寺壁','釋德洪','宋','宋诗','song-poetry','','[]','在山爲遠志，出山爲小草。',48,'全唐诗/poet.song.75000.json','["在山爲遠志，出山爲小草。", "龍潛蟠則神，雞雌伏知道。", "人情難把玩，過眼如電掃。", "留雲峰下寺，白髪歸去好。"]'),
('488e2895-ccf1-4653-8008-552468e1bfaa','棗柏大士生辰因讀易豫卦有感作此','釋德洪','宋','宋诗','song-poetry','','[]','人間解纕沙，開視兒眼前。',48,'全唐诗/poet.song.75000.json','["人間解纕沙，開視兒眼前。", "鉢飯度永日，一裘支十年。", "月巖與雲壑，佳處輒留連。", "誰云道林黠，猶覓買山錢。"]'),
('7d34928e-7646-4cda-bb8b-d759a675f9ad','次韻周達道運句','釋德洪','宋','宋诗','song-poetry','','[]','大澤深壑間，難藏舟與山。',48,'全唐诗/poet.song.75000.json','["大澤深壑間，難藏舟與山。", "此身唾霧中，安得長朱顔。", "講公如夙昔，婁永嘗追攀。", "定作甕中畫，磨衲映青綸。"]'),
('8236aa66-b34d-4dd7-80c8-3183f5386344','次韻遊水簾洞','釋德洪','宋','宋诗','song-poetry','','[]','清夜讀君詩，思豁神亦傾。',48,'全唐诗/poet.song.75000.json','["清夜讀君詩，思豁神亦傾。", "豈惟折幔幢，要已倒降旌。", "重哦水簾句，纖穠開畫屏。", "想見落筆時，遶紙走風霆。"]'),
('83fd29c3-b3df-4637-9db7-97f7c1297eb8','游廬山簡寂觀三首  其一','釋德洪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山覺未老，儼然舊風姿。',48,'全唐诗/poet.song.75000.json','["廬山覺未老，儼然舊風姿。", "樹石亦仙骨，逢春更華滋。", "爪分煙翠層，千丈垂白霓。", "貪看讓爭席，舍者爾爲誰。"]'),
('eb6a037a-9b02-4bad-83e7-924964d8d532','游廬山簡寂觀三首  其二','釋德洪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','蒼石大如屋，古木出虬枝。',48,'全唐诗/poet.song.75000.json','["蒼石大如屋，古木出虬枝。", "四注陰其下，地坐黄冠師。", "山行倦日永，聚話遂忘疲。", "行看洞中境，都是寂音詩。"]'),
('11cfd4b3-6b7a-46b0-88e7-b383b0ee8021','游廬山簡寂觀三首  其三','釋德洪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','怒龍鬬未已，角尾相攀牽。',48,'全唐诗/poet.song.75000.json','["怒龍鬬未已，角尾相攀牽。", "巨石爲解紛，背腹遭虬纏。", "千年毒不死，槎牙带雲煙。", "樹間宜畫我，乞與人間傳。"]'),
('2a7fdbbc-27fe-4fd6-9e2c-1d60d3ee7d50','送人','釋德洪','宋','宋诗','song-poetry','','[]','相送復相别，不異雲間月。',48,'全唐诗/poet.song.75000.json','["相送復相别，不異雲間月。", "無心去復來，有魄圓還缺。", "此别興何如，西風秋月初。", "暮鴻千里至，能寄八行書。"]'),
('69f7b961-ac7f-4b34-9711-ad9e72a3e1c0','别人','釋德洪','宋','宋诗','song-poetry','','[]','尺水未到海，兹行多嗚咽。',48,'全唐诗/poet.song.75000.json','["尺水未到海，兹行多嗚咽。", "病客未還家，回腸藴千結。", "水有到海期，病客歸何時。", "臨岐一揚袂，落日寒風悲。"]'),
('b60a2504-f3f3-4f3a-b443-4025b682606a','信師相别','釋德洪','宋','宋诗','song-poetry','','[]','子昔送我日，出岫雲無心。',48,'全唐诗/poet.song.75000.json','["子昔送我日，出岫雲無心。", "今我捨子行，窮猿瞑投林。", "勿歌行路難，勿效兒女泣。", "處處得逢渠，千江共一月。"]'),
('ec2846f8-3206-43ce-bae2-679d6f4833fb','白日有閒吏青原無惰民爲韻奉寄李成德十首  其一','釋德洪','宋','宋诗','song-poetry','','[]','李侯端自重，不肯下南璧。',36,'全唐诗/poet.song.75000.json','["李侯端自重，不肯下南璧。", "君看英特氣，自可凌太白。", "小邑試牛刀，乃有政和色。"]'),
('b34b71d6-ccd3-4640-9897-83d0a00372bb','白日有閒吏青原無惰民爲韻奉寄李成德十首  其二','釋德洪','宋','宋诗','song-poetry','','[]','舉筆濡大千，揮斤隘八極。',36,'全唐诗/poet.song.75000.json','["舉筆濡大千，揮斤隘八極。", "置之卧病軒，翻身觸破壁。", "起來一調笑，庭樹掛斜日。"]'),
('7433f26d-2745-49b8-8003-155f70e9a3e2','白日有閒吏青原無惰民爲韻奉寄李成德十首  其三','釋德洪','宋','宋诗','song-poetry','','[]','地生金色光，女作師子吼。',36,'全唐诗/poet.song.75000.json','["地生金色光，女作師子吼。", "此軒初不然，風日穿窗牖。", "莫作兩頭看，空花竟何有。"]'),
('56255278-9d98-46ea-905d-a6c7d8e57270','白日有閒吏青原無惰民爲韻奉寄李成德十首  其四','釋德洪','宋','宋诗','song-poetry','','[]','客來清對榻，客去閉深關。',36,'全唐诗/poet.song.75000.json','["客來清對榻，客去閉深關。", "聊爲文字飲，酬唱相往還。", "朝來公事少，白日吏長閒。"]'),
('80a7640d-e091-4c1f-928f-c6bed46b7534','白日有閒吏青原無惰民爲韻奉寄李成德十首  其五','釋德洪','宋','宋诗','song-poetry','','[]','少年韻如春，才可供十吏。',36,'全唐诗/poet.song.75000.json','["少年韻如春，才可供十吏。", "故人半青雲，隱几肘門寐。", "行看登玉堂，清坐追陸贄。"]'),
('9d3e7685-18e7-4c15-a9fe-64d79adee141','白日有閒吏青原無惰民爲韻奉寄李成德十首  其六','釋德洪','宋','宋诗','song-poetry','','[]','朅來民訟少，槐影覆閒庭。',36,'全唐诗/poet.song.75000.json','["朅來民訟少，槐影覆閒庭。", "看山久成癖，詩眼耐空青。", "長憐謝安石，箇中著娉婷。"]'),
('225d5d9d-df6c-4320-84cd-cf2588bd7143','白日有閒吏青原無惰民爲韻奉寄李成德十首  其七','釋德洪','宋','宋诗','song-poetry','','[]','花光浮縣郭，麥浪漲郊原。',36,'全唐诗/poet.song.75000.json','["花光浮縣郭，麥浪漲郊原。", "吏散僧投謁，詩成月上軒。", "何妨横麈尾，相對兩忘言。"]'),
('a9f79ed2-a0c1-4cd4-ad21-ce452f6b5597','白日有閒吏青原無惰民爲韻奉寄李成德十首  其八','釋德洪','宋','宋诗','song-poetry','','[]','密室調絃索，晴軒較畫圖。',36,'全唐诗/poet.song.75000.json','["密室調絃索，晴軒較畫圖。", "撿書憑錦瑟，背句遣奚奴。", "一懽同煮茗，此興不能無。"]'),
('7c270492-19b1-4558-9d2d-2bc6347b8f8e','白日有閒吏青原無惰民爲韻奉寄李成德十首  其九','釋德洪','宋','宋诗','song-poetry','','[]','深原曉犁耕，隔谿夜舂簸。',36,'全唐诗/poet.song.75000.json','["深原曉犁耕，隔谿夜舂簸。", "竹間伊余行，童稚供日課。", "入境觀化風，親視民勤惰。"]'),
('e5cf0932-1113-4635-b7a2-4570030cd4a4','白日有閒吏青原無惰民爲韻奉寄李成德十首  其一○','釋德洪','宋','宋诗','song-poetry','','[]','單衣試嫩寒，花下愛清晨。',36,'全唐诗/poet.song.75000.json','["單衣試嫩寒，花下愛清晨。", "不恨簿書惡，何妨閒岸巾。", "定應懸睿想，憂樂自同民。"]'),
('8926f270-2df4-4792-9f68-f5e647e044e8','雨中聞端叔敦素飲作此寄之','釋德洪','宋','宋诗','song-poetry','','[]','但見杯中春潑面，不知門外雨翻盆。',96,'全唐诗/poet.song.75000.json','["但見杯中春潑面，不知門外雨翻盆。", "人間萬事一虻蚊，正恐卷氈爲鼈飲。", "何妨跨項作猿蹲，此生隨處有乾坤。", "短李貌和髯似棘，王郎耳熱氣如霓。", "不知今日是何時，醉鄉城郭無關鑰。", "世路風波太嶮巇，且看相枕爛如泥。"]'),
('96287fe4-4f85-4a44-8bf2-26064eb7edf3','端叔見和次韻答之','釋德洪','宋','宋诗','song-poetry','','[]','俊詞方覺春照眼，秀句忽驚絲出盆。',96,'全唐诗/poet.song.75000.json','["俊詞方覺春照眼，秀句忽驚絲出盆。", "睡餘兩鬢尚殷蚊，行樂風軒須痛飲。", "窮吟空屋笑愁蹲，筆端浩蕩吐乾坤。", "落筆新詩敏風雨，撚鬚豪氣劃虹霓。", "侍兒扶掖醉吟時，靖節田園尋窈窕。", "謫仙風味自嶔巇，何如春甕掲黄泥。"]'),
('453cf750-9da2-4279-b2ff-9eaaa03539a3','再和復答','釋德洪','宋','宋诗','song-poetry','','[]','道鄉是宅扶歸路，法喜爲妻笑鼓盆。',96,'全唐诗/poet.song.75000.json','["道鄉是宅扶歸路，法喜爲妻笑鼓盆。", "蟭螟膽大敢巢蚊，遊戲秋毫鋒際立。", "卷藏法界眼中蹲，自然函蓋合乾坤。", "醉裏兩篇開爛錦，雨前千丈挂彎霓。", "楊梅盧橘恰嘗時，自笑此生真逆旅。", "人情何處不同巇，禪心且作絮沾泥。"]'),
('a3a52388-d75a-406d-a90a-7775273ac12a','睡起又得和篇','釋德洪','宋','宋诗','song-poetry','','[]','幽夢驚回煙霧帳，清泉起弄雪花盆。',96,'全唐诗/poet.song.75000.json','["幽夢驚回煙霧帳，清泉起弄雪花盆。", "風簷斜日一區蚊，淮水雨開縈練淨。", "鍾山雲卷露龍蹲，癡禪剛道屬乾坤。", "綠髪筆端能吐鳳，雪髯胸次尚盤霓。", "道山歸去定何時，身外聲名徒暴曜。", "夢中憂患自臨巇，烏靴長恨涴塵泥。"]'),
('f764794f-9cc5-406f-9cbf-293e1e3db3ff','復次韻','釋德洪','宋','宋诗','song-poetry','','[]','句健未須纏法律，飲豪那暇較瓶盆。',96,'全唐诗/poet.song.75000.json','["句健未須纏法律，飲豪那暇較瓶盆。", "疾雷破柱一聲蚊，吟狂不覺跨驢穩。", "醉卧都忘對虎蹲，箇中别是一乾坤。", "八篇俊逸狂時語，五色光芒雨後霓。", "清吟要不負明時，嗟我拙詞傷弄巧。", "愛君難韻解平巇，且歌滑路雨成泥。"]'),
('9bcb1c3e-4844-4e33-9695-77b381a4b7c6','晚歸自西崦復得再和二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','人歸西崦步翠麓，月出東峰湧玉盆。',96,'全唐诗/poet.song.75000.json','["人歸西崦步翠麓，月出東峰湧玉盆。", "詩如琥珀妙藏蚊，摩頭長詠笑自語。", "劃席冥搜卧復蹲，筆端三昧撼乾坤。", "衆人俯看旋磨蟻，忠義平生貫日霓。", "也知用舍各由時，顯處山川非設險。", "笑中陷穽却藏巇，此時擬議轢中泥。"]'),
('cbcc3b85-fba7-4ec2-9828-3b640a71daed','晚歸自西崦復得再和二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','世事回頭驚破甑，年華脱手墮空盆。',96,'全唐诗/poet.song.75000.json','["世事回頭驚破甑，年華脱手墮空盆。", "機鋒火聚不容蚊，持帆未欲乘風去。", "捫虱閑爲抱膝蹲，掌中訶子是乾坤。", "壓寨詞鋒盤屈劍，吸川酒膽倒垂霓。", "脱巾露頂笑狂時，任意清閒饑得食。", "關心名利醉登巇，濁流心念已澄泥。"]'),
('f772c03c-7cc8-4a6a-b3b1-2a816a77bf0d','肇上人居京華甚久别余歸閩作此送之','釋德洪','宋','宋诗','song-poetry','','[]','毳帽駝裘一尾輕，半開便面氣如春。',96,'全唐诗/poet.song.75000.json','["毳帽駝裘一尾輕，半開便面氣如春。", "醉歸穿市月隨人，此境要非吾輩事。", "摩頭忽憶海山濱，蕨芽荔肉齒生津。", "十分春壓能眠柳，一再風撩解笑花。", "故山應摘雨前茶，從我覓詩如觸鹿。", "爲君肥字作棲鴉，句中有眼莫驚嗟。"]'),
('faea2481-828d-44b4-a12e-82530b46f90e','送因覺先','釋德洪','宋','宋诗','song-poetry','','[]','南澗茶香咲語新，西洲春漲小舟横。',48,'全唐诗/poet.song.75000.json','["南澗茶香咲語新，西洲春漲小舟横。", "困頓人歸爛熳晴，天迥游絲長百尺。", "日高飛絮滿重城，一番花信近清明。"]'),
('76e40c85-0990-462f-9e3d-79321312ee6d','妙高墨梅','釋德洪','宋','宋诗','song-poetry','','[]','日暮江空船自流，誰家院落近滄洲。',48,'全唐诗/poet.song.75000.json','["日暮江空船自流，誰家院落近滄洲。", "一枝閒暇出墻頭，數朵幽香和月暗。", "十分歸意爲春留，風撩片片是閑愁。"]'),
('4d426591-2f2b-448f-a17e-4c3e68b2cadb','次韻曾侯見寄','釋德洪','宋','宋诗','song-poetry','','[]','客食石門寺，而今僅兩年。',144,'全唐诗/poet.song.75000.json','["客食石門寺，而今僅兩年。", "衰遲嗟我老，邂逅識君賢。", "聖域人稱亞，儒林秀譽先。", "未揎攀桂手，已許買山錢。", "壟麥秋期近，庭槐晝影圓。", "方思歸去日，忽得寄來篇。", "意合蒙推奬，情親出愛憐。", "格幽凌雪勁，詞錦照人鮮。", "把玩欣無厭，行吟却悵然。", "句追工部袂，氣拍翰林肩。", "世已驚殊異，名宜改半千。", "永懷風露重，遶徧舊池蓮。"]'),
('bebaf442-09ea-4157-ba6b-0d5e3c5373a6','王舍人路分生辰','釋德洪','宋','宋诗','song-poetry','','[]','貴出賢王裔，宗連母后因。',144,'全唐诗/poet.song.75000.json','["貴出賢王裔，宗連母后因。", "秋容漱毛骨，春色照簪紳。", "報國忠誠著，驚人句法新。", "慣看青禁月，屢夢玉關塵。", "博古知無敵，窮經亦絕倫。", "後宵通七夕，今日是生辰。", "佳氣凌湘浦，非煙壓楚闉。", "綠醽浮白螘，綺席繞花輪。", "壽綴諸天獻，詞容野客陳。", "不凋蟾窟桂，難老海山春。", "已作瞻雙闕，行看據要津。", "功名先入手，圖畫在麒麟。"]'),
('eb4bb098-48da-4012-91d0-5ed70f5dc5f9','閻資欽提舉生辰','釋德洪','宋','宋诗','song-poetry','','[]','節序春將半，風光過上旬。',168,'全唐诗/poet.song.75000.json','["節序春將半，風光過上旬。", "人間識英物，地上見麒麟。", "凍雨晴還暗，非煙夜達晨。", "懽聲動湘楚，和氣滿簪紳。", "孝友疑無比，恢疏亦絕倫。", "一身渾是德，終日不違仁。", "夢已游青禁，行當侍紫宸。", "立朝知大體，博古見全醇。", "詩妙終聯鼎，文高類過秦。", "公廉清似玉，剛正凛如神。", "幙下名流集，堂中綺宴陳。", "貫珠歌白雪，浮蟻皺紅鱗。", "自幸承顔舊，仍容造膝頻。", "何時渡弱水，同看十洲春。"]'),
('a334d279-01d3-4f74-8c88-3db4ac9ee509','陳奉議生辰','釋德洪','宋','宋诗','song-poetry','','[]','華國生賢俊，江山孕秀靈。',192,'全唐诗/poet.song.75000.json','["華國生賢俊，江山孕秀靈。", "鴨頭淦水綠，螺髻玉筒青。", "敏捷收科第，奇豪見典刑。", "咲談回暖律，詩句挾風霆。", "官偶求彭澤，才宜在漢庭。", "麒麟横逆氣，鸑鷟歛修翎。", "民訟多閒日，棠陰自滿亭。", "浪傳書課奏，須看鼎彞銘。", "仲夏逢佳節，非煙聚杳冥。", "數蓂餘一葉，推道間千齡。", "阡陌登豐後，笙歌爛熳聽。", "綺筵環妙麗，壽斝捧娉婷。", "歡洽連更燭，情高促畫屏。", "九衢花照夜，萬井月開扃。", "風颭銀河動，天驚玉露零。", "三台星密處，旁有老人星。"]'),
('b091a766-6eb9-4c58-ba6b-d381a9fc503e','次韻曾伯容哭夏均父','釋德洪','宋','宋诗','song-poetry','','[]','青松傲霜雪，事悞亦迍邅。',216,'全唐诗/poet.song.75000.json','["青松傲霜雪，事悞亦迍邅。", "或脱斧斤厄，則遭藤蔓纏。", "北渠材砢礧，聳壑色芳鮮。", "不作千楹棟，終爲萬斛船。", "那知過華屋，長慟搖空鞭。", "增擊疑仙去，超搖棄我先。", "但餘殷枕淚，無復對牀眠。", "憶昨游湓浦，曾同上紫烟。", "春光隨杖履，咲響落雲泉。", "尚想登臨處，仍哦唱和篇。", "暗驚生死隔，默數十三年。", "臺憲登羣彦，秋風吹一鸇。", "誅姦志未舍，謀國疏空傳。", "醉馭毛車度，誰推日轂旋。", "歲時嗟易得，力命古難全。", "報施徒云爾，功名信偶然。", "清忠光竹帛，英氣歛山川。", "哭子如臨敵，當勾失短鋋。"]'),
('f25350f7-6727-4ed5-b44f-efdf60fee700','湘上閒居','釋德洪','宋','宋诗','song-poetry','','[]','夜清暑雨過，四壁草蟲鳴。',48,'全唐诗/poet.song.75000.json','["夜清暑雨過，四壁草蟲鳴。", "一枕幽人夢，半窗閒月明。", "摧頹宏法志，老大住山情。", "忽憶陳尊宿，編蒲度此生。"]'),
('310fd395-a8d6-458a-915f-23b576a3105b','西齋晝卧','釋德洪','宋','宋诗','song-poetry','','[]','餘生已無累，古寺寄閑房。',48,'全唐诗/poet.song.75000.json','["餘生已無累，古寺寄閑房。", "睡足無來客，窗空又夕陽。", "叢蕉高出屋，病葉偶飄廊。", "起探風簷立，飛蚊閙晚涼。"]'),
('fe2ea4f3-d520-4842-8eec-24bf9f4f7101','秋夕示超然','釋德洪','宋','宋诗','song-poetry','','[]','夜色已可掬，林光翻欲流。',48,'全唐诗/poet.song.75000.json','["夜色已可掬，林光翻欲流。", "一鈎窺隙月，數葉攪眠秋。", "清境扶歸夢，殘缸替客愁。", "搜詩時畫席，忽覺此生浮。"]'),
('df6a220b-9ee9-450d-aead-396a43926a2d','早春','釋德洪','宋','宋诗','song-poetry','','[]','山中春尚淺，風物麗煙光。',48,'全唐诗/poet.song.75000.json','["山中春尚淺，風物麗煙光。", "澗草殷勤綠，巖花造次香。", "浮根爭附絡，細葉正商量。", "好在幽蘭徑，無人亦自芳。"]'),
('5663a0ea-b2e8-47ef-93d6-7792107c4f86','送僧還長沙','釋德洪','宋','宋诗','song-poetry','','[]','去袂不容挽，子規真滑唇。',48,'全唐诗/poet.song.75000.json','["去袂不容挽，子規真滑唇。", "烟村相送處，風物更撩人。", "麥浪空翻日，花房尚鎖春。", "遙知到湘浦，盧橘恰嘗新。"]'),
('de3737ac-57ee-4249-b995-54e7349b73df','次韻真覺大師瑞香花','釋德洪','宋','宋诗','song-poetry','','[]','淺色閙花堂，清寒熏夜香。',48,'全唐诗/poet.song.75000.json','["淺色閙花堂，清寒熏夜香。", "應持燕尾剪，破此麝臍囊。", "有恨成春睡，無人見洗粧。", "故山煙雨裏，寂寞爲誰芳。"]'),
('54cc1d48-e6f7-49a0-8e2d-bc3bb678d167','次韻誼叟悼性上人','釋德洪','宋','宋诗','song-poetry','','[]','井美泉先竭，犀殘角有通。',48,'全唐诗/poet.song.75000.json','["井美泉先竭，犀殘角有通。", "斯人難再得，陳迹已成空。", "麈尾夢應寄，楞伽寫未終。", "平生說禪口，不見怒號風。"]'),
('d1bba426-ebea-4918-a321-6de75709ae89','除夕和津汝楫','釋德洪','宋','宋诗','song-poetry','','[]','今夕亦常夕，人偏故國思。',48,'全唐诗/poet.song.75000.json','["今夕亦常夕，人偏故國思。", "不堪搓凍耳，聽誦未歸詩。", "家室誼譁後，深簷雨雪時。", "爐香待清旦，此意有誰知。"]'),
('b187a169-aaac-4c81-aacc-1d30eb434eb0','啓明軒次朗上人韻','釋德洪','宋','宋诗','song-poetry','','[]','澄滓動精色，開軒萬象分。',48,'全唐诗/poet.song.75000.json','["澄滓動精色，開軒萬象分。", "光無回避處，眼自覆藏君。", "霞縷縈經軸，煙絲減篆文。", "個中無膡語，題目是先聞。"]'),
('a240c977-0742-4b48-9a35-e1d3265aef91','回光軒','釋德洪','宋','宋诗','song-poetry','','[]','暮色眩紅碧，登臨聊倚欄。',48,'全唐诗/poet.song.75000.json','["暮色眩紅碧，登臨聊倚欄。", "日終猶返照，坐穩可深觀。", "夢幻諸緣寂，圓明一顆寒。", "洞然無向背，莫作轉頭看。"]'),
('cf220b21-5227-43a3-9fee-9d77349e5230','次韻黄元明','釋德洪','宋','宋诗','song-poetry','','[]','靜室依清几，開書映隙光。',48,'全唐诗/poet.song.75000.json','["靜室依清几，開書映隙光。", "悟迷初不隔，語默故難藏。", "妙可忘情會，深無以意量。", "臨機辨神駿，正要略玄黄。"]'),
('38fa0707-2c85-46dd-aa9d-7e93ae84976d','寓鍾山','釋德洪','宋','宋诗','song-poetry','','[]','生涯如倦鳥，栖息此山中。',48,'全唐诗/poet.song.75000.json','["生涯如倦鳥，栖息此山中。", "睡足誰呼覺，烟消篆已空。", "翻經欺眼力，斜日借窗紅。", "卧聽銅瓶泣，青松萬壑風。"]'),
('585d99fd-2036-4601-b98f-d4eccdb8caa8','讀中觀論','釋德洪','宋','宋诗','song-poetry','','[]','平生智眼濁，塵劫著心深。',48,'全唐诗/poet.song.75000.json','["平生智眼濁，塵劫著心深。", "長向環輪上，空將始末尋。", "十方真寂滅，一念去來今。", "妙絕調琴指，知誰解賞音。"]'),
('ddb42bc9-6499-49a0-8014-f53e24bc5db7','對雪嘗水餅','釋德洪','宋','宋诗','song-poetry','','[]','雪粲羅敷喜，報春呈舞腰。',48,'全唐诗/poet.song.75000.json','["雪粲羅敷喜，報春呈舞腰。", "旋風寒正密，到地暖還消。", "輕薄凌梅蘂，蹁躚攪柳條。", "幽欣嘗水餅，舉箸一長謠。"]'),
('dbcffc3e-3645-4bb0-8d15-547bca62111d','清明前一日聞杜宇示清道芬','釋德洪','宋','宋诗','song-poetry','','[]','籬外花如海，閒軒小寢驚。',48,'全唐诗/poet.song.75000.json','["籬外花如海，閒軒小寢驚。", "最先聞杜宇，更覺近清明。", "雲怒必爲雨，風和抝得晴。", "阿芬甘劣我，笑裏恰詩成。"]'),
('68729406-5055-4871-90e5-45f586fb896f','閒門','釋德洪','宋','宋诗','song-poetry','','[]','杯飯終永日，一裘支千秋。',48,'全唐诗/poet.song.75000.json','["杯飯終永日，一裘支千秋。", "餘生已無累，此外復何求。", "懶出門常閉，欣眠榻可休。", "抛書方手倦，啼鳥破深幽。"]'),
('ecc122f4-427d-46bc-aafd-61a456e8565b','四月十一日書壁','釋德洪','宋','宋诗','song-poetry','','[]','夜久茅齋靜，階泉遶珮鳴。',48,'全唐诗/poet.song.75000.json','["夜久茅齋靜，階泉遶珮鳴。", "行高人莫識，道遠自深明。", "掃榻酬閑味，依蒲任性情。", "叢林終不負，一衲傲平生。"]'),
('d9fb3c29-9965-42cf-9b8e-446d3d04b430','次韻雲庵老人題妙用軒','釋德洪','宋','宋诗','song-poetry','','[]','開軒閒隱几，萬象競趨陪。',48,'全唐诗/poet.song.75000.json','["開軒閒隱几，萬象競趨陪。", "風掲松聲去，雲推山色來。", "觀身真作夢，視世一浮埃。", "日暮庭陰轉，幽禽接趐回。"]'),
('a3f98247-31b5-4539-8a93-82fcf73f4934','讀瑜伽論','釋德洪','宋','宋诗','song-poetry','','[]','此生已無累，一席可窮年。',48,'全唐诗/poet.song.75000.json','["此生已無累，一席可窮年。", "細嚼寶公飯，飽參彌勒禪。", "懶修精進定，愛作吉祥眠。", "夜久山空寂，唯聞遶砌泉。"]'),
('22930dfc-baf7-4e31-97ff-f99ef40273d0','鍾山有花如比丘狀出穠葉間王文公名爲羅漢花僧請賦詩','釋德洪','宋','宋诗','song-poetry','','[]','通力元無礙，隨緣自應真。',48,'全唐诗/poet.song.75000.json','["通力元無礙，隨緣自應真。", "此生花上露，故現葉間身。", "知見幽香在，伽梨翠色新。", "一枝聊把玩，未愧鷲峰人。"]'),
('c7e796cf-0a5e-4ed6-9638-9ed494a41ec3','寄題行林寺照堂','釋德洪','宋','宋诗','song-poetry','','[]','聞說行林寺，杳然叢秀間。',48,'全唐诗/poet.song.75000.json','["聞說行林寺，杳然叢秀間。", "堂清開水鏡，山好理烟鬟。", "有霧窗呵暗，無塵扉自關。", "人牛今不見，蓑苙兩俱閑。"]'),
('a730b70d-6f88-460a-baa7-3c9deae36eb3','與性之','釋德洪','宋','宋诗','song-poetry','','[]','物外不可必，相看一笑休。',48,'全唐诗/poet.song.75000.json','["物外不可必，相看一笑休。", "好山終入手，墮甑懶回頭。", "知復何時見，聊爲此日留。", "定難瞞道眼，得喪兩浮漚。"]'),
('d6ec910d-75c7-4fc2-9b55-6716c5d0556f','僧求曉披晚清二軒詩二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','披衣汲南澗，落葉在庭除。',48,'全唐诗/poet.song.75000.json','["披衣汲南澗，落葉在庭除。", "獨立無人見，幽行偏自如。", "嫩寒冰齒頰，精色到衣裾。", "却倚蒲輪坐，横看貝葉書。"]'),
('8a167615-c698-430a-93f5-5c5bbce26bbf','僧求曉披晚清二軒詩二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','旋螺堆空青，重疊不容數。',48,'全唐诗/poet.song.75000.json','["旋螺堆空青，重疊不容數。", "夕陽穿貫之，濃薄自呈露。", "數點沒煙鴻，一聲伐雲斧。", "殷牀鐘未消，流螢自開户。"]'),
('29e7f2b3-6689-4090-9fd2-3c0a3a6042c2','春日谿行','釋德洪','宋','宋诗','song-poetry','','[]','側布寶坊地，白沙楊柳灣。',48,'全唐诗/poet.song.75000.json','["側布寶坊地，白沙楊柳灣。", "憶曾嬰死禍，不自意生還。", "已覺無鄉夢，今真是故山。", "谿花眠霧雨，春在有無間。"]'),
('cf9be122-37e0-4bf9-913f-ad5f35ce298a','送僧歸故廬','釋德洪','宋','宋诗','song-poetry','','[]','投名新入社，卧病偶思歸。',48,'全唐诗/poet.song.75000.json','["投名新入社，卧病偶思歸。", "渡澗脱芒屨，扶藤下翠微。", "寒松猶带雨，瘦骨不勝衣。", "若見翁鑽紙，當施百丈機。"]'),
('32c3b775-779f-4288-bd9d-66b6fa5362d4','焦山贈僧二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','白下門連寺，清游入夢中。',48,'全唐诗/poet.song.75000.json','["白下門連寺，清游入夢中。", "骨驚誰囓指，世事謾書空。", "梵行芙蕖淨，天寒晝火紅。", "曉窗應破夢，卧聽鳥呼風。"]'),
('50bc56bf-15a4-4644-a60d-5dfc9b987050','焦山贈僧二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','對牀聽夜雨，佳約是當年。',48,'全唐诗/poet.song.75000.json','["對牀聽夜雨，佳約是當年。", "放曠隨緣去，閑心不習禪。", "倚蒲趺足坐，擁衲蓋頭眠。", "今識君歸處，齋餘有澗泉。"]'),
('8563c4ad-0e29-4759-ad05-8f878a6ae420','題反身軒','釋德洪','宋','宋诗','song-poetry','','[]','盡力覓不得，歸來題反身。',48,'全唐诗/poet.song.75000.json','["盡力覓不得，歸來題反身。", "平生未解沒，寧解救滔人。", "有累路岐遠，無求滋味親。", "養心唯寡欲，妙物久如神。"]'),
('a2a741e4-88bc-4ae8-befc-571bd0d47d96','宿本覺寺','釋德洪','宋','宋诗','song-poetry','','[]','一宿路旁寺，霜清夢亦寒。',48,'全唐诗/poet.song.75000.json','["一宿路旁寺，霜清夢亦寒。", "憶曾游覽處，來覓舊題看。", "病衲成新塔，層樓隱敗垣。", "青山猶不老，千疊似翔鸞。"]'),
('b38112ec-f87b-44cf-ad92-90e66a60de38','題芝軒','釋德洪','宋','宋诗','song-poetry','','[]','軒下亦何有，靈芝駢秀生。',48,'全唐诗/poet.song.75000.json','["軒下亦何有，靈芝駢秀生。", "山川呈美瑞，草木被光榮。", "清甚紫檀露，色深黄菊英。", "武陵續遺事，應著此軒名。"]'),
('358790e1-150b-4afd-85bf-3d134814a361','次韻王安道節推過雲蓋','釋德洪','宋','宋诗','song-poetry','','[]','秀傑長沙幕，高才自敏强。',48,'全唐诗/poet.song.75000.json','["秀傑長沙幕，高才自敏强。", "同僚推俊逸，黼坐畏剛方。", "慣吐珠璣句，宜便宴寢香。", "秋來能過我，聽雨夜連牀。"]'),
('1f435170-bc89-4abc-965a-1b65f519a448','題含容室','釋德洪','宋','宋诗','song-poetry','','[]','歛足脱雙履，閑房倚瘦藤。',48,'全唐诗/poet.song.75000.json','["歛足脱雙履，閑房倚瘦藤。", "百川朝巨浸，一室納千燈。", "至味寧分别，常光絕減增。", "刹塵彰帝網，妙觀現層層。"]'),
('46d9b3d9-ff75-4905-be4e-55bb5b7f2ea3','人日雪二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','今年人日雪，更在末山巖。',48,'全唐诗/poet.song.75000.json','["今年人日雪，更在末山巖。", "瀉行想堆垛，打窗時兩三。", "夢回清語默，寒重壓衣衫。", "面壁孤風坐，知誰繼夜參。"]'),
('1f0e605b-d558-4487-8103-79b5d215df85','人日雪二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','律管未回暖，春先到曉巖。',48,'全唐诗/poet.song.75000.json','["律管未回暖，春先到曉巖。", "與君清作對，得月便成三。", "秀色報虚幌，幽欣宜衲衫。", "相看超語默，覿露不須參。"]'),
('7299d587-2172-47d2-b155-98140f2f5601','次韻周運句見寄','釋德洪','宋','宋诗','song-poetry','','[]','頑鈍世推鄙，而君偏切磋。',48,'全唐诗/poet.song.75000.json','["頑鈍世推鄙，而君偏切磋。", "借神觀有漏，騎氣到無何。", "昔共飲臨汝，今同家汩羅。", "衡門似長吉，軒蓋幾時過。"]'),
('a52b3ca9-ef38-4e96-8bca-103cedafe7b9','重會雲叟禪師','釋德洪','宋','宋诗','song-poetry','','[]','氣味似前輩，見之長眼明。',48,'全唐诗/poet.song.75000.json','["氣味似前輩，見之長眼明。", "閑須研法味，老不減詩情。", "草聖因蛇鬬，禪枝解虎爭。", "一堂聊寄傲，疏快餞餘生。"]'),
('95ca671c-fe92-4d4a-aa6e-b00b5df87741','次忠子韻二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','湘雲刺世眼，獨可著閑蹤。',48,'全唐诗/poet.song.75000.json','["湘雲刺世眼，獨可著閑蹤。", "鷗迥千尋雨，江寒一再風。", "旋鑽新火後，初脱夾衣重。", "坐客經年别，蘭芽茁舊叢。"]'),
('be1b80c9-128a-4e38-b5cc-eaa1cea3ca92','次忠子韻二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','新秧翻翠浪，青子退紅英。',48,'全唐诗/poet.song.75000.json','["新秧翻翠浪，青子退紅英。", "穫麥風光近，絡絲歡笑聲。", "瞢騰幽夢破，醖造小詩成。", "好在歸來燕，營巢占畫楹。"]'),
('a23451be-3a1e-47d9-86d1-6f851c600a62','和曾逢原待制觀雪','釋德洪','宋','宋诗','song-poetry','','[]','魂清寒妥貼，寺近汨羅江。',48,'全唐诗/poet.song.75000.json','["魂清寒妥貼，寺近汨羅江。", "夜迥疑生月，夢驚聞打窗。", "地罏無宿火，經閣有殘缸。", "起望兜綿界，誰推墮陋邦。"]'),
('ee89767f-caa4-4b7f-b00c-e08194a0d84e','初過海自號甘露滅','釋德洪','宋','宋诗','song-poetry','','[]','本是甘露滅，浪名無垢稱。',48,'全唐诗/poet.song.75000.json','["本是甘露滅，浪名無垢稱。", "欲知遭鎖禁，正坐忽規繩。", "海上垂鬚佛，軍中有髪僧。", "生涯何所似，崖略類騰騰。"]'),
('9f77c99f-373a-4a17-b2b1-11a16860dcd3','早登澄邁西四十里宿臨皋亭補東坡遺','釋德洪','宋','宋诗','song-poetry','','[]','天下至窮處，風烟觸地愁。',48,'全唐诗/poet.song.75000.json','["天下至窮處，風烟觸地愁。", "村囂聞捉拗，岸汁忽西流。", "鳥道通儋耳，鯨波隔萬州。", "趁雞行落月，悽斷在蠻謳。"]'),
('912c09a5-2b18-4f20-bfed-ea8d9f2713d4','過淩水縣','釋德洪','宋','宋诗','song-poetry','','[]','野徑如遺索，縈紆到縣門。',48,'全唐诗/poet.song.75000.json','["野徑如遺索，縈紆到縣門。", "犁人趁牛日，蜑户聚魚村。", "籬落春潮退，桑麻曉瘴昏。", "題詩驚萬里，折意一消魂。"]'),
('c901a8de-3932-4822-9e29-819a63ebf487','楊文中將北渡何武翼出妓作會文中清狂不喜武人徑飲三盃不揖坐客上馬馳去索詩送行作此','釋德洪','宋','宋诗','song-poetry','','[]','蘭叢聚貴客，花輪環侍兒。',48,'全唐诗/poet.song.75000.json','["蘭叢聚貴客，花輪環侍兒。", "三盃吾徑醉，四座汝爲誰。", "但覺眩紅碧，了不聞歌吹。", "翩然上馬去，海月解相隨。"]'),
('b55245f2-5ce1-4a6e-a146-c732e39bd365','渡海','釋德洪','宋','宋诗','song-poetry','','[]','萬里來償債，三年墮瘴鄉。',48,'全唐诗/poet.song.75000.json','["萬里來償債，三年墮瘴鄉。", "逃禪解羊負，破律醉檳榔。", "瘦盡聲音在，病殘鬚鬢荒。", "餘生實天幸，今日上歸艎。"]'),
('c7064682-fe7f-47a8-baa5-f7a3ace756d2','夜坐分題得廊字','釋德洪','宋','宋诗','song-poetry','','[]','一雨餞殘暑，瘴痾蘇簟涼。',48,'全唐诗/poet.song.75000.json','["一雨餞殘暑，瘴痾蘇簟涼。", "卧聞山果落，起覺斛蘭香。", "幌內水螢入，階除露葉光。", "知誰愛清境，步屧響修廊。"]'),
('b076bd7b-9664-4438-aacc-9e091d0ca171','出獄李生來謁出百丈汾陽二像爲示因而摹之作此時即欲還谷山','釋德洪','宋','宋诗','song-poetry','','[]','一鉢寄城市，皤然鬚鬢長。',48,'全唐诗/poet.song.75000.json','["一鉢寄城市，皤然鬚鬢長。", "風埃窮百丈，翰墨老汾陽。", "家在青松岸，門連白鳥行。", "知誰施舟尾，載我下沅湘。"]'),
('899a3327-e315-4370-93da-5598b92d7a3c','次韻周倅大雪見寄二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','萬瓦粲清曉，披衣挂北窗。',48,'全唐诗/poet.song.75000.json','["萬瓦粲清曉，披衣挂北窗。", "春先歸楚國，誰獨釣湘江。", "瘴熟甘欺得，詩嚴合受降。", "更憐風絮比，想見髻鬟雙。"]'),
('5619dce2-b32d-451d-956e-c47be61dd50f','次韻周倅大雪見寄二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','白晝通紅火，蕭蕭驚打窗。',48,'全唐诗/poet.song.75000.json','["白晝通紅火，蕭蕭驚打窗。", "折綿寒未透，兀夢睡先降。", "那敢犯詩壘，自然摧慢幢。", "重看寄來句，呵手剔殘缸。"]'),
('f8429193-13ca-4b42-884f-3b1205f1fdc8','次韻郤子中學句出巡','釋德洪','宋','宋诗','song-poetry','','[]','安石性夷粹，公今亦重遲。',48,'全唐诗/poet.song.75000.json','["安石性夷粹，公今亦重遲。", "追惟理髪處，領略辦裝時。", "高節貫終始，寸田齊坦巇。", "功名恐未免，才業係安危。"]'),
('671ca46e-743a-4b58-ab5b-c97cc0c6b1d3','次韻鄧公閣睡起','釋德洪','宋','宋诗','song-poetry','','[]','歸計寛爲約，山行短作程。',48,'全唐诗/poet.song.75000.json','["歸計寛爲約，山行短作程。", "旅亭驚午夢，布穀正催耕。", "翰墨堪華國，雲泉負此生。", "一篇叙閑適，細味有餘情。"]'),
('070f6056-a00d-4928-9867-381d6c7a98e8','次韻衡山道中','釋德洪','宋','宋诗','song-poetry','','["\u8861\u5c71"]','嶽色堕馬首，嵐光忽滿襟。',48,'全唐诗/poet.song.75000.json','["嶽色堕馬首，嵐光忽滿襟。", "眼寒知意適，句苦覺愁侵。", "沃野獻新綠，殘睛釀晚陰。", "天涯驚去鴈，料理欲歸心。"]'),
('da3eb025-1234-4907-811a-c5bc5e8a90be','贈鄒顔徒','釋德洪','宋','宋诗','song-poetry','','[]','肉眼倒皮相，高才多陸沉。',48,'全唐诗/poet.song.75000.json','["肉眼倒皮相，高才多陸沉。", "火知三日玉，貧試一生心。", "世路多追逐，雲山獨見尋。", "聖賢酌古力，勸子手勤斟。"]'),
('d4b02b2b-a806-4dfa-b895-e6d7849bbbbd','投老庵讀雲庵舊題拜次其韻二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','但覺意清淨，不知山淺深。',48,'全唐诗/poet.song.75000.json','["但覺意清淨，不知山淺深。", "年華暗凋落，老境已侵尋。", "三世樓鐘舊，一生香火心。", "高風難補綴，永愧壁間吟。"]'),
('66608963-3091-4b81-ada6-0f7e0e0ec789','投老庵讀雲庵舊題拜次其韻二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','道鄉歸路晚，世迹陷泥深。',48,'全唐诗/poet.song.75000.json','["道鄉歸路晚，世迹陷泥深。", "老死先通耗，病衰今見尋。", "規模高世意，料理住山心。", "月在孤峰頂，凍猿時一吟。"]'),
('e4dd37c0-2307-4ed7-a012-12d6c232b136','熏上人歸雲溪','釋德洪','宋','宋诗','song-poetry','','[]','聞道衡峰北，寺當猿叫村。',48,'全唐诗/poet.song.75000.json','["聞道衡峰北，寺當猿叫村。", "夜樓千嶂月，書榻一溪雲。", "我慣蹈憂患，君方蜕垢紛。", "莫嫌林下石，蘚涴褶衣裙。"]'),
('06fc0c6a-a851-4d77-8976-6ba229814595','題使臺後圃八首 諦觀室','釋德洪','宋','宋诗','song-poetry','','[]','優入聖賢域，湛然觀道真。',48,'全唐诗/poet.song.75000.json','["優入聖賢域，湛然觀道真。", "一身渾是德，終日不違仁。", "深靜啼林鳥，虚明見隙塵。", "篆畦凝碧縷，紅燼白灰新。"]'),
('298ad3e5-9ef3-42f7-b390-28d28e9278c3','題使臺後圃八首 賞趣堂','釋德洪','宋','宋诗','song-poetry','','[]','胸次有丘壑，笑談無俗氛。',48,'全唐诗/poet.song.75000.json','["胸次有丘壑，笑談無俗氛。", "幽懷常自得，佳趣與誰論。", "曳履尋花圃，扶筇卓蘚痕。", "地嚴賓謁少，却坐看罏熏。"]'),
('8d95e180-bf0b-441b-bc2a-c12915f14af1','題使臺後圃八首 會心堂','釋德洪','宋','宋诗','song-poetry','','[]','稱意有余樂，幽歡常會心。',48,'全唐诗/poet.song.75000.json','["稱意有余樂，幽歡常會心。", "小山供賦詠，危榭毎登臨。", "下視千峰月，聊揮一弄琴。", "尚嫌閑適少，富貴苦相尋。"]'),
('5d78a302-74f9-4268-9ca3-d91352ee617d','題使臺後圃八首 阜安堂','釋德洪','宋','宋诗','song-poetry','','[]','禮義成風俗，豐登民阜安。',48,'全唐诗/poet.song.75000.json','["禮義成風俗，豐登民阜安。", "此堂共僚屬，把酒聽吹彈。", "地富湖山美，宵晴風月寒。", "勝游無俗韻，意適有余歡。"]'),
('51e37a7b-d99e-4764-af0f-a17c3699aee2','題使臺後圃八首 戲綵堂','釋德洪','宋','宋诗','song-poetry','','[]','承顔忘勢位，喜懼兩遲迴。',48,'全唐诗/poet.song.75000.json','["承顔忘勢位，喜懼兩遲迴。", "堂上綵衣舞，樽前笑靨開。", "金鐶應學探，竹馬欲相陪。", "未必稱純孝，高風獨老萊。"]'),
('2b586633-9efb-4cd8-9348-e353f02fdb2e','題使臺後圃八首 獨秀堂','釋德洪','宋','宋诗','song-poetry','','[]','天質自奇峻，千尋紫翠重。',48,'全唐诗/poet.song.75000.json','["天質自奇峻，千尋紫翠重。", "謾煩君獨秀，不願掩羣峰。", "與客共秋晚，搜詩到暮鐘。", "夕陰寒欲滴，倚檻見纖穠。"]'),
('d182b3d4-e1b5-4261-be5a-63f6835d3e83','題使臺後圃八首 清音樓','釋德洪','宋','宋诗','song-poetry','','[]','霧暗軒窗失，風高簾幕低。',48,'全唐诗/poet.song.75000.json','["霧暗軒窗失，風高簾幕低。", "夜晴湘笛起，樓迥嶺猿啼。", "憑檻人如玉，搜詩氣吐霓。", "還驚一聲鴈，翻影月平西。"]'),
('e8c0557f-2f16-4487-9045-2e7313ac3008','題使臺後圃八首 蒙齋','釋德洪','宋','宋诗','song-poetry','','[]','妙物雜而著，深藏一默中。',48,'全唐诗/poet.song.75000.json','["妙物雜而著，深藏一默中。", "誠爲反身樂，蒙亦聖人功。", "客至風生麈，吟餘月挂空。", "莊周稱社櫟，神拙意無窮。"]'),
('be7d4628-aa57-448c-b411-77312d5d5fe1','次韻李方叔游衡山僧舍','釋德洪','宋','宋诗','song-poetry','','["\u8861\u5c71"]','道鄉見城郭，世路謾升沉。',48,'全唐诗/poet.song.75000.json','["道鄉見城郭，世路謾升沉。", "寺勝增佳氣，壁間餘醉吟。", "僧殘過客少，山好爲誰深。", "寧識通泉尉，獨懷經濟心。"]'),
('bd590701-5134-4d59-b43c-f0dace5cb461','次韻謁子美祠堂','釋德洪','宋','宋诗','song-poetry','','[]','顛沛干戈際，心常系洛陽。',48,'全唐诗/poet.song.75000.json','["顛沛干戈際，心常系洛陽。", "愛君臣子分，傾日露葵芳。", "醉眼蓋千古，詩名動八荒。", "壞祠湘水上，烟樹晚微茫。"]'),
('ca2765b0-4c27-4f29-8ff7-87e3952c5ce5','次韻達臣知縣祈雪遊嶽麓寺分韻得遊字','釋德洪','宋','宋诗','song-poetry','','[]','叢祠香火罷，山寺偶同遊。',48,'全唐诗/poet.song.75000.json','["叢祠香火罷，山寺偶同遊。", "鑪撥紅金湧，窗空碧縷浮。", "旋敷白㲲布，暖甚紫茸裘。", "試作吉祥卧，夢清如素秋。"]'),
('53c7e1d5-d3e2-40bf-9f99-665ca6714899','題夢清軒','釋德洪','宋','宋诗','song-poetry','','[]','小軒人不到，脩竹過墻生。',48,'全唐诗/poet.song.75000.json','["小軒人不到，脩竹過墻生。", "眼倦經長掩，身閑夢亦清。", "微風吹篆縷，活火發茶鐺。", "遙想佳眠夕，蕭蕭雨葉聲。"]'),
('8c170717-7505-48ac-b16f-d941ae0bf5d9','題一擊軒','釋德洪','宋','宋诗','song-poetry','','[]','閒把松枝篲，掃除門徑塵。',48,'全唐诗/poet.song.75000.json','["閒把松枝篲，掃除門徑塵。", "驚聞一擊竹，頓見十方身。", "烟翠連窗暗，霜筠解籜新。", "老禪搆軒意，應欲悟來人。"]'),
('7c082c4a-59dd-46da-9a37-a1850e3c4ad5','次韻胥學士','釋德洪','宋','宋诗','song-poetry','','[]','筆下慣生春，年高句法新。',48,'全唐诗/poet.song.75000.json','["筆下慣生春，年高句法新。", "還將吐鳳語，來寄牧牛人。", "敏若盤珠妙，深如社櫟神。", "長哦答清境，璧月上重闉。"]'),
('e4ba6064-9447-4632-b5f0-79792649e990','題曾逢原醉經堂','釋德洪','宋','宋诗','song-poetry','','[]','酌古有深意，開編中聖人。',48,'全唐诗/poet.song.75000.json','["酌古有深意，開編中聖人。", "百家笑糟粕，六藝飲全醇。", "兀若墜車適，盎如浮盞春。", "淳于吞一石，同味不同塵。"]'),
('05965e23-3df4-41b1-9a03-8eae45ec3b44','隱山照上人求詩','釋德洪','宋','宋诗','song-poetry','','[]','落髪道林寺，隨師家隱山。',48,'全唐诗/poet.song.75000.json','["落髪道林寺，隨師家隱山。", "萬緣都放捨，一衲遂安閒。", "璧月照宵定，金風掩晝關。", "平生無媿業，塵世許誰攀。"]'),
('b840b869-2161-4e03-98d5-948d93e2e150','龍山亦名隱山余宣和五年十一月中澣日過焉有淛道人鴻公乞偈爲作','釋德洪','宋','宋诗','song-poetry','','[]','迷路不知遠，但知寒日斜。',48,'全唐诗/poet.song.75000.json','["迷路不知遠，但知寒日斜。", "過溪逢菜葉，西崦有人家。", "斫額驚來客，拄鋤方種畬。", "鴻禪効古者，當効此生涯。"]'),
('c35927ec-3cd8-498d-89fb-4ebcb550b8f0','游靈泉贈正悟大師','釋德洪','宋','宋诗','song-poetry','','[]','支徑入山寺，雲林如見招。',48,'全唐诗/poet.song.75000.json','["支徑入山寺，雲林如見招。", "小軒臨絕壑，危閣礙層霄。", "瓶泣地罏暖，屋睛巖雪消。", "大師京國舊，放意話州橋。"]'),
('20484488-5fc7-4dc8-b43e-a282809c3d25','七月初九夜坐西軒雨止月出不勝清絕','釋德洪','宋','宋诗','song-poetry','','[]','夜雨止還作，小軒清有餘。',48,'全唐诗/poet.song.75000.json','["夜雨止還作，小軒清有餘。", "暴寒吹客夢，殘響滴階除。", "明滅青燈在，簾櫳璧月孤。", "故山歸未得，千里漫平蕪。"]'),
('2505f98d-6833-4656-aa87-57c70f3115a2','甲辰十一月十二日往湘陰馬上和季長見寄小春二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','雨暗書雲節，梅偷破臘春。',48,'全唐诗/poet.song.75000.json','["雨暗書雲節，梅偷破臘春。", "里閭相餽餉，風物近袁筠。", "吳語知無伴，楚衣聊試新。", "忽驚身是客，流落老湘濱。"]'),
('fb51b57b-79d0-4144-a0fb-614a7aad1cf1','甲辰十一月十二日往湘陰馬上和季長見寄小春二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','風埃九十里，霧雨濕駝裘。',48,'全唐诗/poet.song.75000.json','["風埃九十里，霧雨濕駝裘。", "鴈過回詩眼，江寒聚晚愁。", "魂清方怯雪，句冷更含秋。", "殘岸連孤嶼，依稀似橘洲。"]'),
('52ad0839-b7ba-4331-9bf5-896329754852','題閲世軒','釋德洪','宋','宋诗','song-poetry','','[]','江水似人世，倚欄歸思多。',48,'全唐诗/poet.song.75000.json','["江水似人世，倚欄歸思多。", "無窮流歲月，可畏易風波。", "□與老僧看，不妨閑客過。", "爲君聊借榻，清夢到無何。"]'),
('6548a6c4-769d-46ee-9c19-cb3990f92b32','雲庵生辰','釋德洪','宋','宋诗','song-poetry','','[]','探手取空劫，爪分破一塵。',48,'全唐诗/poet.song.75000.json','["探手取空劫，爪分破一塵。", "洞然無空缺，獨立不鮮陳。", "試問聲前見，何如頂後親。", "死生浪遮掩，漏洩是今辰。"]'),
('a2b92aae-31e0-4cd1-b79d-63f3cc6e302a','次韻濟之和劉元老偶成之句','釋德洪','宋','宋诗','song-poetry','','[]','世亂驚流落，名高子可依。',48,'全唐诗/poet.song.75000.json','["世亂驚流落，名高子可依。", "元龍謝襁負，叔冶冒重闈。", "黄屋方回望，青山敢問歸。", "三橋伏道几，應嘆眼中稀。"]'),
('aafb5dd3-fe1a-419f-93c1-1f0fc06568ef','贈成上人之雲居','釋德洪','宋','宋诗','song-poetry','','[]','天上歐峰寺，人間無事僧。',48,'全唐诗/poet.song.75000.json','["天上歐峰寺，人間無事僧。", "偶從白沙岸，步入碧螺層。", "服匿連空鉢，敷羅挂瘦藤。", "遙知雲起處，一室掩香燈。"]'),
('743a1b72-b3c4-4447-8433-a1e64985f685','四月二十五日智俱侍者生日戲作此授之','釋德洪','宋','宋诗','song-poetry','','[]','與佛同生月，猶遲十八朝。',48,'全唐诗/poet.song.75000.json','["與佛同生月，猶遲十八朝。", "參禪唯自肯，求法轉相遼。", "谷響千斤重，虚空五采描。", "布毛吹起處，豁爾萬緣消。"]'),
('ca9426dd-2cb5-45a1-8f0f-ca1f1c040bd0','謝大潙空印禪師惠茶','釋德洪','宋','宋诗','song-poetry','','[]','鐘鼓五千指，翔空樓殿開。',48,'全唐诗/poet.song.75000.json','["鐘鼓五千指，翔空樓殿開。", "不知大潙水，何爾小南臺。", "讓子鈯斧信，閒禪春露杯。", "故應念岑寂，先寄出山來。"]'),
('feb4b5de-df75-4ccb-a85e-fcd4e5db030a','愈崇二子求偈歸江南','釋德洪','宋','宋诗','song-poetry','','[]','人笑南臺小，難安十八僧。',48,'全唐诗/poet.song.75000.json','["人笑南臺小，難安十八僧。", "日貧因日富，宜減不宜增。", "忽去兩禪衲，如分一室燈。", "牀寛齊頂禮，睡快免相憎。"]'),
('edf072bf-ad2b-499c-965f-aac634b05854','曹教授夫人挽詞','釋德洪','宋','宋诗','song-poetry','','[]','禮敬良天性，求賢比孟光。',48,'全唐诗/poet.song.75000.json','["禮敬良天性，求賢比孟光。", "搢紳聞懿淑，閭里發慈祥。", "饌按今誰舉，山衣尚篋藏。", "榮名增史牒，有子類鸞皇。"]'),
('2f445f26-1f18-45c3-9eb4-49a670801534','贈尼昩上人','釋德洪','宋','宋诗','song-poetry','','[]','不著包頭絹，能披壞墨衣。',48,'全唐诗/poet.song.75000.json','["不著包頭絹，能披壞墨衣。", "愧無灌溪辯，敢對末山機。", "未肯題紅葉，終期老翠微。", "余今倦行役，投杖夢煙扉。"]'),
('effe64ba-d85e-47b7-93dc-eeac9382ce1a','興闌','釋德洪','宋','宋诗','song-poetry','','[]','春晚忽憑檻，滿眸佳景來。',48,'全唐诗/poet.song.75000.json','["春晚忽憑檻，滿眸佳景來。", "鴨頭波蕩漾，螺髻色崔嵬。", "苔嫩錢無數，花殘錦作堆。", "一甌雙井釅，何必酒盈杯。"]'),
('80aba76d-0e80-4830-86c2-ab36394dbdd7','與海兄','釋德洪','宋','宋诗','song-poetry','','[]','春寒真料峭，久客厭江城。',48,'全唐诗/poet.song.75000.json','["春寒真料峭，久客厭江城。", "雲重欲爲雨，風和尚未晴。", "意隨飛鳥去，事逐亂埃輕。", "畢竟閒居好，煩君念此情。"]'),
('2ce70a65-209f-4974-8100-255ad838c62b','題靈鷲山','釋德洪','宋','宋诗','song-poetry','','[]','側徑入招提，回峰據極西。',48,'全唐诗/poet.song.75000.json','["側徑入招提，回峰據極西。", "雲虚籠殿閣，地僻絕輪蹄。", "啼鳥棲高木，飛花泛碧溪。", "誰當學龍濟，垂手接羣迷。"]'),
('3b2c6d5f-f1b8-4a37-9b29-ee898ad5ce1f','燈花偶書','釋德洪','宋','宋诗','song-poetry','','[]','岑寂一閑僧，春宵清興增。',48,'全唐诗/poet.song.75000.json','["岑寂一閑僧，春宵清興增。", "竹窗催夢雨，蘭室對祥燈。", "世事知虚幻，人情剪愛憎。", "短長都分定，不恨百無能。"]'),
('d2175d3b-184d-4c04-b061-b6a344f2a150','懷友人','釋德洪','宋','宋诗','song-poetry','','[]','不見鄰峰友，還同楚越遙。',48,'全唐诗/poet.song.75000.json','["不見鄰峰友，還同楚越遙。", "毎勞孤枕夢，時過小溪橋。", "憑檻疏簾卷，臨風細雨飄。", "何當奉一笑，令我此情消。"]'),
('e98d8232-56b4-4ef8-822d-b198bf4365e1','賦竹','釋德洪','宋','宋诗','song-poetry','','[]','龍孫盈檻秀，天柱聳雲奇。',48,'全唐诗/poet.song.75000.json','["龍孫盈檻秀，天柱聳雲奇。", "陰鎖安禪石，根侵洗硯池。", "瓏璁伸粉節，偃蹇鬱虯枝。", "敢謂桃兼李，羞鄰雪後姿。"]'),
('6893b183-0bb2-4648-aa82-8faa4f6d5d89','早行','釋德洪','宋','宋诗','song-poetry','','[]','失枕驚先起，人家半夢中。',48,'全唐诗/poet.song.75000.json','["失枕驚先起，人家半夢中。", "聞雞憑早晏，占斗辨西東。", "轡濕知行路，衣單怯曉風。", "秋陽弄光影，忽吐半林紅。"]'),
('b0451a50-921b-4f91-89d5-e0bd9df79fef','賢上人覓偈','釋德洪','宋','宋诗','song-poetry','','[]','懶修枯骨觀，愛學文字禪。',48,'全唐诗/poet.song.75000.json','["懶修枯骨觀，愛學文字禪。", "江山助佳興，時有題葉篇。", "相逢未暇語，輒復一粲然。", "豈須究所學，覓偈亦自賢。"]'),
('99d6c973-ad0a-4d81-abdb-3062bb111e8b','黄蘗佛智','釋德洪','宋','宋诗','song-poetry','','[]','道譽聞寰宇，光華照錦江。',48,'全唐诗/poet.song.75000.json','["道譽聞寰宇，光華照錦江。", "祗園居第一，佛智果無雙。", "鳳闕帝恩厚，柏庭禪將降。", "僧中真領袖，傳法瑞堯邦。"]'),
('9f24d581-0ad4-4846-87bd-b97cebf448c3','題潙源','釋德洪','宋','宋诗','song-poetry','','[]','臨機不墮照，如水已知源。',48,'全唐诗/poet.song.75000.json','["臨機不墮照，如水已知源。", "從此常流出，其聲離語言。", "筭沙嗟意馬，捉月笑情猨。", "若解提空印，休登立雪軒。"]'),
('1787f281-3b9f-4e16-8035-fe0c770e5784','十五日立春','釋德洪','宋','宋诗','song-poetry','','[]','千年像教唐朝寺，雪後新年晴復陰。',64,'全唐诗/poet.song.75000.json','["千年像教唐朝寺，雪後新年晴復陰。", "殘僧無事春又至，游客不來山自深。", "長廊掃葉望空翠，小閣卷經横水沉。", "三生白業有言說，一念淨心無古今。"]'),
('5ddf274e-d44f-4e6a-96d2-835120816b3e','晚步歸西崦','釋德洪','宋','宋诗','song-poetry','','[]','屋除有路入深壑，曳履翛然獨往還。',64,'全唐诗/poet.song.75000.json','["屋除有路入深壑，曳履翛然獨往還。", "播穀風光寒日近，摘茶時節亂山間。", "花枝重少人甘老，燕子空忙春自閒。", "歸晚斷橋逢野水，更能揎手弄潺顔。"]'),
('9a31950d-9034-49c6-b79e-15b98aa8f30e','宗公以蘭見遺風葉蕭散蘭芽並茁一榦雙花鬬開宗以爲瑞乞詩記其事','釋德洪','宋','宋诗','song-poetry','','[]','深林忽見蘭芽茁，不謂無人亦自賢。',64,'全唐诗/poet.song.75000.json','["深林忽見蘭芽茁，不謂無人亦自賢。", "數葉横風作纖瘦，雙花含雪吐明鮮。", "照人秀色雖堪畫，入骨真香不可傳。", "今日東君應擇壻，誰家兄弟鬬清妍。"]'),
('3c432794-db6c-4860-af3f-a6697175ad6f','黄幼安適過予所居題詩草聖甚妙','釋德洪','宋','宋诗','song-poetry','','[]','懷袖功名手未探，亂頭睡美厭朝參。',64,'全唐诗/poet.song.75000.json','["懷袖功名手未探，亂頭睡美厭朝參。", "筆端五色藻萬象，胸次大千供劇談。", "山寺尋僧宿風雨，水軒見月出東南。", "題詩滿壁龍蛇動，盛事他年說草庵。"]'),
('94844cec-3339-4109-9be9-645495a90056','元夕讀書罷假寐','釋德洪','宋','宋诗','song-poetry','','[]','燈下文章已倦看，欲憑詩苦洗辛酸。',64,'全唐诗/poet.song.75000.json','["燈下文章已倦看，欲憑詩苦洗辛酸。", "世途忽起風波易，富貴不忘貧賤難。", "桃塢路迷安石塚，桐川水落子陵灘。", "卧聞屐響東廊靜，催粥華鯨吼夜殘。"]'),
('4b5d5894-8514-41d3-b2d5-4d026cfd24ea','示忠子','釋德洪','宋','宋诗','song-poetry','','[]','夢冷寒庭半夜雨，幽欣臨曉一番晴。',64,'全唐诗/poet.song.75000.json','["夢冷寒庭半夜雨，幽欣臨曉一番晴。", "柳嬌困頓欲眠去，禽作清圓喚起聲。", "曳履點殘山寺靜，開經拾得紙窗明。", "去年今日岐亭路，吹鬢塵埃趼足行。"]'),
('a3701ae5-f94a-4e1f-aba2-2e57fdb822aa','訪鑒師不遇書其壁','釋德洪','宋','宋诗','song-poetry','','[]','獨自來游微雨後，道人乞食及清晨。',64,'全唐诗/poet.song.75000.json','["獨自來游微雨後，道人乞食及清晨。", "應門童子能迎客，滿地榆錢欲買春。", "花醉發狂風日釅，柳眠喚起語音真。", "政當借榻酬無事，熟鼾從教聒四鄰。"]'),
('4b909985-399b-4f91-9391-7eb7a6800a3f','資國寺春晚','釋德洪','宋','宋诗','song-poetry','','[]','龍鄉戒曉月空斜，喚起清圓響絡車。',64,'全唐诗/poet.song.75000.json','["龍鄉戒曉月空斜，喚起清圓響絡車。", "燒筍餉田村窕窈，拾薪煮繭語諠譁。", "美忻崖蜜嘗新果，香識山樊稱意花。", "歸去路迷光已夕，浸門春水一池蛙。"]'),
('4e662475-346f-4b89-bc8f-6b2415ae769a','聞龔德莊入山先一日作詩迎之','釋德洪','宋','宋诗','song-poetry','','[]','夢暖不知窗霧白，眼寒初愛縠羅輕。',64,'全唐诗/poet.song.75000.json','["夢暖不知窗霧白，眼寒初愛縠羅輕。", "欣聞明日一龔至，想見隨軒二李行。", "夜雨曉晴寒食近，水流花發子規聲。", "披襟散坐青林下，依約斜川萬古情。"]'),
('ab5cb26b-5d26-4f84-b48c-f25a5fea9bf9','晚秋溪行','釋德洪','宋','宋诗','song-poetry','','[]','熟路沿溪過石橋，掃除秋晚淨迢迢。',64,'全唐诗/poet.song.75000.json','["熟路沿溪過石橋，掃除秋晚淨迢迢。", "幽尋忽見蘭芽茁，小立仍逢柿葉飄。", "撲摝水飛雙去鳥，𤤮瓏山響一聲樵。", "歸來半掩殘經在，燕寢香凝碧未消。"]'),
('79e3055c-7704-4943-aa73-bd18d7feb2c2','張氏快軒','釋德洪','宋','宋诗','song-poetry','','[]','草樹分明天遠大，酒闌登賞更從容。',64,'全唐诗/poet.song.75000.json','["草樹分明天遠大，酒闌登賞更從容。", "眼寒數點鴈横雨，耳熱一窗風度松。", "光滑紙開秋色闊，淋漓墨潑暮煙濃。", "欲傾蛟室瓊詞句，試借温江卓筆峰。"]'),
('baf6899b-5601-487d-82ce-1a2056e2b97e','秋晚同超然山行','釋德洪','宋','宋诗','song-poetry','','[]','諸方游徧渾如夢，古寺歸來獨掩扃。',64,'全唐诗/poet.song.75000.json','["諸方游徧渾如夢，古寺歸來獨掩扃。", "無復詩篇雲錦段，但餘心境木蛇形。", "高秋霜葉魚顋赤，落日遠山螺髻青。", "步盡松陰忽回首，綠蘿疏處見谿亭。"]'),
('5cc3911b-41f6-4dd1-9af9-347bc6eaa4a6','送淨心大師住温州江心寺','釋德洪','宋','宋诗','song-poetry','','[]','萬鍛爐中百怨門，哲人雖往典刑存。',64,'全唐诗/poet.song.75000.json','["萬鍛爐中百怨門，哲人雖往典刑存。", "掃除臨濟實頭謗，稱賞黄龍的骨孫。", "夢澤於菟三口視，丹山雛鳳九苞文。", "還鄉妙曲誰能聽，一笛波心兩岸聞。"]'),
('0534db38-708f-4427-9c7f-d9226606ec9f','和清上人','釋德洪','宋','宋诗','song-poetry','','[]','駒兒墮地已汗血，毛骨蕭森落眼中。',64,'全唐诗/poet.song.75000.json','["駒兒墮地已汗血，毛骨蕭森落眼中。", "今見馬羣方弄影，會看雷電疾追風。", "媒龍何止十倍價，凡馬終當一洗空。", "我是道林能賞駿，識君語妙到無同。"]'),
('c19114b5-9059-40c9-92d3-8b12a204a3c1','升上人過石門','釋德洪','宋','宋诗','song-poetry','','[]','門巷榆錢疊紫苔，十年心事首重回。',64,'全唐诗/poet.song.75000.json','["門巷榆錢疊紫苔，十年心事首重回。", "暑風院落書籖響，煙雨江村畫牒開。", "瓦枕藤牀初破睡，蔗漿冰椀欲生埃。", "風簷獨立看遺照，忽有溪僧犯犬來。"]'),
('61f368cf-1c02-4b7c-b0a3-2b3c0abff8f6','夏日偶書二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','碧縷横斜試水沉，紅腮甘冷嚼來禽。',64,'全唐诗/poet.song.75000.json','["碧縷横斜試水沉，紅腮甘冷嚼來禽。", "含風廣殿聞棋響，轉日回廊暗柳陰。", "強撚冰紈餘睡色，倦憑棐几適閒心。", "攀翻涴衲黄塵事，過眼雲蹤不可尋。"]'),
('30b629dc-eaaf-462c-b3af-d1930dffd239','夏日偶書二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','偏地知誰柳際門，消閑自掃竹西軒。',64,'全唐诗/poet.song.75000.json','["偏地知誰柳際門，消閑自掃竹西軒。", "井花曉汲聞餘滴，篆燒風摧覓舊痕。", "夢境消磨驚歲月，道鄉彷彿見藩垣。", "寶書半摺山房寂，卧聽嬌鶯說怨恩。"]'),
('af52581f-ac9e-45db-95aa-4da226ac0e68','鄒必東竹枕','釋德洪','宋','宋诗','song-poetry','','[]','黑甜誰欲當閒味，此枕令人穩稱心。',64,'全唐诗/poet.song.75000.json','["黑甜誰欲當閒味，此枕令人穩稱心。", "風骨子猷居處竹，典刑元亮醉時琴。", "宜籠霧鬢清圓語，聽學朱絃發越音。", "不用製囊裁古錦，春寒長搭閙花衾。"]'),
('27e38563-6234-435b-939b-e008791e3b85','竹爐','釋德洪','宋','宋诗','song-poetry','','[]','博山沉水覺塵埃，旋斫凌雲綠玉材。',64,'全唐诗/poet.song.75000.json','["博山沉水覺塵埃，旋斫凌雲綠玉材。", "自拭錦䙀含淚粉，要焚銀葉返魂梅。", "意消未掩黄庭卷，火冷空餘白雪灰。", "應把熏衣閉深閣，流蘇想見畫屏開。"]'),
('e7724e07-cd17-4b59-a2dc-6475d6d1e2a9','七月四日晝夢雲庵和尚教誨久之而覺作此示超然','釋德洪','宋','宋诗','song-poetry','','[]','夏窗午睡誰呼覺，院靜惟聞遶砌泉。',64,'全唐诗/poet.song.75000.json','["夏窗午睡誰呼覺，院靜惟聞遶砌泉。", "夢裏緒言猶可記，壁間遺像尚依然。", "襯珠定使拳披見，坐榻當令膝處穿。", "塔在層峰衰眼力，何時同汝掃頽塼。"]'),
('7bddc569-73ca-499d-9a41-a4aee952e3e1','雲庵塔有雙桐作此寄因姪','釋德洪','宋','宋诗','song-poetry','','[]','十年不掃先師塔，聞有雙桐護石根。',64,'全唐诗/poet.song.75000.json','["十年不掃先師塔，聞有雙桐護石根。", "多寶佛應分半座，主林神對現前身。", "詩成坐對南州祖，寫寄山中玉澗因。", "他日就陰當縛屋，歲時香火願爲鄰。"]'),
('05065f2c-3b6e-40d6-8dfa-2a82f2a9a9d1','中秋對月','釋德洪','宋','宋诗','song-poetry','','[]','好天涼夕病衰餘，散步中庭瘦策扶。',64,'全唐诗/poet.song.75000.json','["好天涼夕病衰餘，散步中庭瘦策扶。", "禪客相逢宿山寺，玉輪同看上雲衢。", "十分歸思懸江國，一半秋光入鬢鬚。", "草露濕衣香霧重，更將毛骨洗冰壺。"]'),
('d0d5b1e2-08e1-47d0-962d-ef85815a2cdd','至上高謁李先甲會淵才德修','釋德洪','宋','宋诗','song-poetry','','[]','先甲志大性重遲，是中可築平生基。',64,'全唐诗/poet.song.75000.json','["先甲志大性重遲，是中可築平生基。", "心期功名定不赦，未識所與游從誰。", "淵才人間汗血驥，德修天上麒麟兒。", "知君懷中有卿相，探手但未忙取之。"]'),
('7296809e-e56e-46dd-8d46-9581d0adade1','次韻睿廓然送僧還東吳','釋德洪','宋','宋诗','song-poetry','','[]','征夫應爲指柴扉，湖水當門可濯衣。',64,'全唐诗/poet.song.75000.json','["征夫應爲指柴扉，湖水當門可濯衣。", "飛鳥已知今日倦，舊鄰那悟昔人非。", "山情已作燖雞淨，世味真如嚼蠟微。", "遙想夜航無管束，棹歌應載月明歸。"]'),
('85d315cd-3ced-4b96-b158-3c1ff9a39eda','送瑩上人游衡嶽','釋德洪','宋','宋诗','song-poetry','','[]','紫蓋峰頭樓閣生，朱靈洞口水雲晴。',64,'全唐诗/poet.song.75000.json','["紫蓋峰頭樓閣生，朱靈洞口水雲晴。", "盤空路作驚蛇去，落日人如凍蟻行。", "重郭老師今健否，藏年珍木但聞名。", "定應自掃巖邊石，時發披雲嘯月聲。"]'),
('399a6b06-c16a-43ae-966a-bbd614b0d518','寄草堂上人','釋德洪','宋','宋诗','song-poetry','','[]','首夏年芳尚可尋，興來芒履恣登臨。',64,'全唐诗/poet.song.75000.json','["首夏年芳尚可尋，興來芒履恣登臨。", "回頭故國煙波闊，分袂幽人歲月深。", "落日杜鵑山館靜，薫風芳草柳塘陰。", "知君宴坐忘機地，謾寄新詩話此心。"]'),
('c8cb2974-b6de-4778-8dd6-250a1b828958','酬潛上人','釋德洪','宋','宋诗','song-poetry','','[]','滿鈎疏箔卷簷楹，秋靜江天刮眼明。',64,'全唐诗/poet.song.75000.json','["滿鈎疏箔卷簷楹，秋靜江天刮眼明。", "梵册已翻千偈妙，爐香未散一堂清。", "沾衣菊露情□□，□□松聲夢不成。", "我與道人緣分熟，可能朝夕厭逢迎。"]'),
('6604fcbe-c4e4-4edf-bb71-0046b894acd1','贈爲上人游方昭默之子也','釋德洪','宋','宋诗','song-poetry','','[]','年少辭師作遠游，人言虎穴不生彪。',64,'全唐诗/poet.song.75000.json','["年少辭師作遠游，人言虎穴不生彪。", "家聲自古能名世，氣宇如今已食牛。", "奪得我機方肯住，從教棒打不回頭。", "雲山萬疊翛然去，江漢無風一葉舟。"]'),
('16ebc2cc-a6e4-46c4-9a5b-f3a710e2ec36','鄧秀才就武舉作詩美之','釋德洪','宋','宋诗','song-poetry','','[]','丈夫氣自磨牛斗，正似豐城獄屋刀。',64,'全唐诗/poet.song.75000.json','["丈夫氣自磨牛斗，正似豐城獄屋刀。", "富貴豈終憑鐵硯，功名先看擲霜毫。", "蘆鞭未稱迎風帽，紫綬從來賽綠袍。", "杖策軍門君記取，祖宗漢室舊勳勞。"]'),
('708ca4ec-1089-4b6c-a071-b968bc8e6ed7','崇勝寺後竹千餘竿獨一根秀出呼爲竹尊者','釋德洪','宋','宋诗','song-poetry','','[]','高節長身老不枯，平生風骨自清癯。',64,'全唐诗/poet.song.75000.json','["高節長身老不枯，平生風骨自清癯。", "愛君脩竹爲尊者，却笑寒松作大夫。", "不見同行木上座，空餘聽法石爲徒。", "戲將秋色供齋鉢，抹月披雲得飽無。"]'),
('95fbf594-744b-46e0-b10b-d7059fa2e22d','童子名道員年五歲餘不茹葷隨母往來禪林旦夕稍長即與落髪覓詩作此授之','釋德洪','宋','宋诗','song-poetry','','[]','氣與秋容一倍清，出塵風骨自天成。',64,'全唐诗/poet.song.76000.json','["氣與秋容一倍清，出塵風骨自天成。", "逢僧論性人皆說，指佛高談母亦驚。", "已覺君家鍾善慶，從來我法付豪英。", "他年勘徧諸方老，古寺編蒲更道情。"]'),
('c5a2bf89-ce7a-4ec7-a5de-ac160c172cc6','題水鏡軒','釋德洪','宋','宋诗','song-poetry','','[]','小軒明快照巖阿，得道幽人喜氣多。',64,'全唐诗/poet.song.76000.json','["小軒明快照巖阿，得道幽人喜氣多。", "但視世間如水鏡，方知夢境有山河。", "佳眠不礙林光入，清坐何妨夜月過。", "我亦思歸老丘壑，結鄰西崦肯容麽。"]'),
('c22c0a64-9245-4ccc-a256-53d39fc71ce7','同吳家兄弟游東山約仲誠不至','釋德洪','宋','宋诗','song-poetry','','[]','東山重到讀題名，勝踐清游此合并。',64,'全唐诗/poet.song.76000.json','["東山重到讀題名，勝踐清游此合并。", "霧雨開晴秋滿眼，暮雲欲合句先成。", "走禪璧月寒林靜，來客蘭叢玉樹清。", "我老吐詞如朽木，蒸成芝菌報升平。"]'),
('e3c49ec5-56fc-4522-8639-cbd92b82990d','器之示巽中見懷次韻','釋德洪','宋','宋诗','song-poetry','','[]','折脚鐺尋穩處安，對君此夕久盟寒。',64,'全唐诗/poet.song.76000.json','["折脚鐺尋穩處安，對君此夕久盟寒。", "狐裘不合須羊袖，藥簏何妨缺夜干。", "秋壟此時驅健犢，道山何日跨歸鸞。", "仙鑪只隔數邱耳，上水船方厄瀨湍。"]'),
('6eb5d467-b19a-4457-b038-54b51299b4c3','書鑒上人香嚴堂','釋德洪','宋','宋诗','song-poetry','','[]','堂前叢玉知誰種，叢下高人自掃除。',64,'全唐诗/poet.song.76000.json','["堂前叢玉知誰種，叢下高人自掃除。", "未論擊聲回顧眄，先欣秀色上眉鬚。", "隨宜萬偈風宣說，頓現千身月寫摹。", "就地對誰曾畫餠，當年饞水救饑無。"]'),
('66b2ce94-f262-4a05-8648-20da2fcea185','冷然齋','釋德洪','宋','宋诗','song-poetry','','[]','以身爲舌毗尼藏，儼此空齋鏡面清。',64,'全唐诗/poet.song.76000.json','["以身爲舌毗尼藏，儼此空齋鏡面清。", "蟬蜕塵埃軒蓋集，蝶成魂夢篆煙輕。", "蘆圖世界分遺境，玉麈天花委落英。", "鉢在道山歸去好，摩挲風馭笑平生。"]'),
('fc99b2f8-0fd7-4c99-94af-c69ed2077216','謝性之惠茶','釋德洪','宋','宋诗','song-poetry','','[]','午窗石碾哀怨語，活火銀瓶暗浪翻。',64,'全唐诗/poet.song.76000.json','["午窗石碾哀怨語，活火銀瓶暗浪翻。", "射眼色隨雲脚亂，上眉甘作乳花繁。", "味香已覺臣雙井，聲價從來友壑源。", "却憶高人不同試，暮山空翠共無言。"]'),
('9c89e04a-4476-4379-85c8-2b5693d7e44f','訪友人二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','海棠雨過尚嬌春，袖手來尋林下人。',64,'全唐诗/poet.song.76000.json','["海棠雨過尚嬌春，袖手來尋林下人。", "未話柳條堪結紐，且欣梅子可嘗新。", "孤蹤袞袞風中絮，萬事紛紛夢裏塵。", "他日别山重會面，定知談笑絕鮮陳。"]'),
('14f9139f-290f-4371-9ea1-ccfcfedd7c88','訪友人二首  其二','釋德洪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','日暮荒城倚瘦藤，江南春思倍添增。',64,'全唐诗/poet.song.76000.json','["日暮荒城倚瘦藤，江南春思倍添增。", "那知淮水黄塵路，忽見廬山綠髪僧。", "乞食久辭煙際寺，連牀今對夜深燈。", "明年我亦尋君去，同陟天池最上層。"]'),
('4d77670a-2c99-4ee1-87b0-dc69605a90e1','石臺夜坐二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','故鄉乃有此叢林，下板何妨著寂音。',64,'全唐诗/poet.song.76000.json','["故鄉乃有此叢林，下板何妨著寂音。", "永與世遺他日志，尚嫌山淺暮年心。", "凍雲未放僧窗曉，折竹方知夜雪深。", "琢句自應清似玉，更宜坡字硬黄臨。"]'),
('10b12359-b293-41af-96fe-ad100e6caaf8','石臺夜坐二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','歲晚山深過客稀，一燈清坐夜同誰。',64,'全唐诗/poet.song.76000.json','["歲晚山深過客稀，一燈清坐夜同誰。", "滴階寒響雪消後，通火活紅灰陷時。", "歛目舊游真可數，蓋棺前事尚難知。", "古今不隔諸緣淨，畫出巖中道者詩。"]'),
('9246b544-84de-4345-a57b-159b44f4e77d','胡卿才時思亭','釋德洪','宋','宋诗','song-poetry','','[]','祇今冢木上雲雨，想見音容無恙時。',64,'全唐诗/poet.song.76000.json','["祇今冢木上雲雨，想見音容無恙時。", "竟作懷歸戀雲舍，空餘淚眼看風枝。", "功名未洗終天恨，歲月難忘罔極悲。", "已覺夜林無觸鹿，但看几硯出靈芝。"]'),
('ac24ec5a-14da-40a0-bd94-73bff736087f','題此君軒','釋德洪','宋','宋诗','song-poetry','','[]','解知無竹令人俗，日報平安候起居。',64,'全唐诗/poet.song.76000.json','["解知無竹令人俗，日報平安候起居。", "所以此君揖冰雪，長吟餘翠滿衣裾。", "瘦行清坐搜詩處，雨葉風枝解籜初。", "試作小軒聊寄傲，愛君生計未爲疏。"]'),
('32835a27-1ca7-46c4-ae2c-727c21ec7daf','喜文首座至','釋德洪','宋','宋诗','song-poetry','','[]','機鋒不減矮師叔，聞說叢林最飽參。',64,'全唐诗/poet.song.76000.json','["機鋒不減矮師叔，聞說叢林最飽參。", "無暇對人收冷涕，却能爲我出寒巖。", "春江柔櫓何時聽，夜雨山房且對談。", "掣電一懽端可貴，此生俱是再眠蠶。"]'),
('e66ee3d2-d4d5-4453-b22c-17b42a777292','超然自見軒','釋德洪','宋','宋诗','song-poetry','','[]','叢林爭致致不得，繭足徑來尋儼師。',64,'全唐诗/poet.song.76000.json','["叢林爭致致不得，繭足徑來尋儼師。", "幽境自能情外見，高懷獨出世間癡。", "清晨倚檻臨黄卷，五月亂山聞子規。", "夙習尚嗟消未盡，壁間時錄和陶詩。"]'),
('eed3dc28-8459-48fa-a0e2-6fdfd0246954','清大師還姑蘇塔其師骨石弔之兼簡其弟','釋德洪','宋','宋诗','song-poetry','','[]','聞說高懷照雪霜，道容一見自清涼。',64,'全唐诗/poet.song.76000.json','["聞說高懷照雪霜，道容一見自清涼。", "今隨生死晦心月，空使湖山藹德香。", "故紙不堪看竹籠，凝塵那忍拂繩牀。", "安門弟子真持遠，獨爲斯人未始亡。"]'),
('8fa5d461-e7bb-4494-a2a9-220b22461056','閩僧不食已四十年贈之','釋德洪','宋','宋诗','song-poetry','','[]','銀髪齊眉衲半肩，相逢古寺獨欣然。',64,'全唐诗/poet.song.76000.json','["銀髪齊眉衲半肩，相逢古寺獨欣然。", "自云出嶺三千里，人見空餘四十年。", "擬欲就君求此術，預憂臨食必流涎。", "何如萬事隨緣過，饑即須餐困即眠。"]'),
('5c5cca04-1fcd-4e53-b465-284fe5c4678c','元祐五年秋嘗宿獨木爲詩以自遣今復過此追舊感歎用韻示超然二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','獨木江頭纜客船，暮江秋色兩依然。',64,'全唐诗/poet.song.76000.json','["獨木江頭纜客船，暮江秋色兩依然。", "落霞片段紅綳水，危岫參差碧挂天。", "名利到頭成底事，田園歸得是何年。", "崢嶸壯志消磨盡，滿目西風只自憐。"]'),
('00ffc85d-1135-4566-9b79-d5991c7acb0f','元祐五年秋嘗宿獨木爲詩以自遣今復過此追舊感歎用韻示超然二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','蹤跡漂流不繫船，舊游曾到意茫然。',64,'全唐诗/poet.song.76000.json','["蹤跡漂流不繫船，舊游曾到意茫然。", "玉笙哀怨初涼夜，秋月嬋娟落木天。", "往事已嗟如昨夢，壯懷無復似當年。", "鑪峰當眼空相向，因念區區想見憐。"]'),
('40b1e482-7e4a-4cca-865e-a8f4b76b5ca0','與客啜茶戲成','釋德洪','宋','宋诗','song-poetry','','[]','道人要我煮温山，似識相如病裏顔。',64,'全唐诗/poet.song.76000.json','["道人要我煮温山，似識相如病裏顔。", "金鼎浪翻螃蟹眼，玉甌絞刷鷓鴣斑。", "津津白乳衝眉上，拂拂清風產腋間。", "喚起晴窗春書夢，絕憐佳味少人攀。"]'),
('aa4dbf86-87f9-4ec5-bede-67a002032c6d','宿香城寺','釋德洪','宋','宋诗','song-poetry','','[]','夜晴風細月華清，遶寺霜筠雪竹聲。',64,'全唐诗/poet.song.76000.json','["夜晴風細月華清，遶寺霜筠雪竹聲。", "錫響僧歸帝青寶，夢香人宿水沉城。", "古今不隔塵都盡，心境俱忘鏡對明。", "枕臂曉猿三叫絕，小窗燈暗讀殘經。"]'),
('e45e9a86-a847-4779-b26a-588525272067','自張平道入瑤谿','釋德洪','宋','宋诗','song-poetry','','[]','衝虎曾經落照村，千峰盤盡始登門。',64,'全唐诗/poet.song.76000.json','["衝虎曾經落照村，千峰盤盡始登門。", "慣聞跛脚阿師法，喜見横行道者孫。", "愛客精神清入畫，游方蹤跡夜重論。", "杖藜又入層雲去，知有安公舊隱存。"]'),
('dedd6fa4-735d-45b0-bec3-5cf8f1182ab4','九峰夜坐','釋德洪','宋','宋诗','song-poetry','','[]','千峰萬峰自雲雨，一宿兩宿心頽然。',64,'全唐诗/poet.song.76000.json','["千峰萬峰自雲雨，一宿兩宿心頽然。", "不知人間歲云暮，但覺澗風吹夜泉。", "地爐火燄水正泣，篝燈委昏僧未眠。", "古人去我不甚遠，何必想像臨遺編。"]'),
('02e1a71c-ffc2-4eb2-8acd-8dfc64c033aa','同世承世英世隆三伯仲蔡定國劉達道登滕王閣','釋德洪','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','承英連璧光照坐，更著阿隆如鼎安。',64,'全唐诗/poet.song.76000.json','["承英連璧光照坐，更著阿隆如鼎安。", "老兵先馳啓關鑰，西山奔走登欄干。", "劉郎端默自凝遠，蔡侯奮髯牙齒寒。", "但餘衰老百無用，搜句倚欄方細看。"]'),
('3329704c-8f9c-454f-bd29-3b8ed3f232c4','寄李大卿','釋德洪','宋','宋诗','song-poetry','','[]','瓶盂又復寄西州，彌勒同龕古寺幽。',64,'全唐诗/poet.song.76000.json','["瓶盂又復寄西州，彌勒同龕古寺幽。", "睡起忽殘三月夏，朝來拾得一簾秋。", "浮雲世事慵料理，斷梗閑蹤任去留。", "投老山林多勝槩，杖藜何日復同游。"]'),
('de12708d-4036-437f-a214-fc2f35d234e3','余居百丈天覺方註楞嚴以書見邀作此寄之二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','風定晴雲欲墮崩，林梢樓閣旋添增。',64,'全唐诗/poet.song.76000.json','["風定晴雲欲墮崩，林梢樓閣旋添增。", "一生高世清閑侣，千尺當門紫翠層。", "對客不妨拴壞衲，倦禪時作靠枯藤。", "暮年古格叢林在，重撥塵龕大智燈。"]'),
('ff07b25a-1c3a-45b3-b543-b2bb16496485','余居百丈天覺方註楞嚴以書見邀作此寄之二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','三世如來尊頂法，覆藏深密碧螺寒。',64,'全唐诗/poet.song.76000.json','["三世如來尊頂法，覆藏深密碧螺寒。", "通身是眼自不見，擘面出頭窺更難。", "四義僅能分肉髻，八還終恐隔花冠。", "爭如劈佛丹霞手，掲露從教覿體看。"]'),
('8e693f50-f075-4e08-89bd-74bbe43a71ea','寄龍安照禪師','釋德洪','宋','宋诗','song-poetry','','[]','隨分叢林古格存，龍安真是泐潭孫。',64,'全唐诗/poet.song.76000.json','["隨分叢林古格存，龍安真是泐潭孫。", "獨持一節無求世，勘破諸方不出門。", "石虎已忘蹲草見，木蛇久滅住山痕。", "遙知百事俱衰落，尚有工夫虱自捫。"]'),
('1e302484-a329-4cda-9032-e08ee5b66dab','聞龍安往夏口迎張左丞遂泝流至鄂渚相别還山作此寄之','釋德洪','宋','宋诗','song-poetry','','[]','無盡龍安兩勍敵，大梅龐老是同參。',64,'全唐诗/poet.song.76000.json','["無盡龍安兩勍敵，大梅龐老是同參。", "近聞赤壁同登賞，想見清風助笑談。", "已作汎舟游夏口，又成横錫過江南。", "歸來萬壑松聲在，依舊閑雲沒草庵。"]'),
('cafb937b-ef2b-405b-ba26-8927db6924bd','别龍安','釋德洪','宋','宋诗','song-poetry','','[]','朅來幕阜峰前寺，彌勒同龕兩見秋。',64,'全唐诗/poet.song.76000.json','["朅來幕阜峰前寺，彌勒同龕兩見秋。", "今日他山生遠念，何年此地復重游。", "主人有道忘欣厭，閑客無求任去留。", "索紙題詩聊贈别，更哦江海一沙鷗。"]'),
('1f65488c-6ef2-43d0-9939-36519fd4bc64','次韻無代送僧歸吳','釋德洪','宋','宋诗','song-poetry','','[]','春掠湓江綠染眸，多情還解向東流。',64,'全唐诗/poet.song.76000.json','["春掠湓江綠染眸，多情還解向東流。", "故應夜夢清蒼勝，欲趁春光爛熳游。", "飽學尚嗟心未死，痛吟已覺鬢先秋。", "何當一棹華亭上，閑唱波寒月滿舟。"]'),
('e1a30ab7-6e74-4f52-82cb-ff3f73173ba2','懷友人','釋德洪','宋','宋诗','song-poetry','','[]','尋常輕别尚消魂，何況交情過弟昆。',64,'全唐诗/poet.song.76000.json','["尋常輕别尚消魂，何況交情過弟昆。", "孰謂此身閑日月，自慚疏跡信乾坤。", "泠泠小雨江邊路，薄薄浮煙竹外村。", "回首舊游方契闊，孤舟何處宿黄昏。"]'),
('10c0f05c-b048-4ac9-9357-5ceba1831867','汪履道家觀古書','釋德洪','宋','宋诗','song-poetry','','[]','風流前輩已成塵，筆跡猶爲世所珍。',64,'全唐诗/poet.song.76000.json','["風流前輩已成塵，筆跡猶爲世所珍。", "促膝猛觀驚盛事，臨風長想見斯人。", "氣生偉逸龍蛇動，秀發精神點畫新。", "破篋尚能多此物，且欣汪子未全貧。"]'),
('00bb3278-9782-4200-a895-db941f687827','悼性上人','釋德洪','宋','宋诗','song-poetry','','[]','三年三過龍安寺，亹亹清談解逼人。',64,'全唐诗/poet.song.76000.json','["三年三過龍安寺，亹亹清談解逼人。", "顧我偷閑久無侣，與君數面自成親。", "轉頭忽作幽冥隔，彈指空驚夢寐新。", "病眼看秋欲淒眩，攀翻投老一傷神。"]'),
('203f9413-ba5e-4855-be83-a5b461770a59','秋日還廬山故人書因以爲寄','釋德洪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','風葉鳴廊夜色晴，隔雲微月稍分明。',64,'全唐诗/poet.song.76000.json','["風葉鳴廊夜色晴，隔雲微月稍分明。", "下簾徒怯衣裳薄，拂榻空驚枕簟清。", "病眼得秋還少睡，壯心於世尚多情。", "何時却作廬山去，渡水穿雲取次行。"]'),
('4025fca6-650b-4596-99b8-14c37163b51b','誠上人求詩','釋德洪','宋','宋诗','song-poetry','','[]','我昔車輪翠裏行，只今懷想似前生。',64,'全唐诗/poet.song.76000.json','["我昔車輪翠裏行，只今懷想似前生。", "那知古寺僧窗下，偶見高人眼倍明。", "秋月半鈎留客意，凍雲千頃欲歸情。", "杖藜笑出千峰去，添得蒼崖響答聲。"]'),
('f883883d-989e-45d9-a2ac-2c7d055649d3','雪夜讀涪翁所作愛之因懷其人和韻奉寄超然','釋德洪','宋','宋诗','song-poetry','','[]','溪雨初收岸草微，柳絲堪入綠羅機。',64,'全唐诗/poet.song.76000.json','["溪雨初收岸草微，柳絲堪入綠羅機。", "望中情遠恨煙樹，何處暖多嫌衲衣。", "却信真人還有夢，豈關禪子未忘機。", "春風痛與傳消息，教憶舊山新翠歸。"]'),
('9660768b-d76e-4354-b770-d046682eb3f7','公亮超然見和因寄復答之','釋德洪','宋','宋诗','song-poetry','','[]','高人秀句入幽微，濯出秦川錦一機。',64,'全唐诗/poet.song.76000.json','["高人秀句入幽微，濯出秦川錦一機。", "剪製未爲春步幛，暗投先作夜行衣。", "語尊九鼎真難荷，意的千鈞善發機。", "早晚杖藜松下見，應疑劉遠谷中歸。"]'),
('ade4ac2b-1705-4a4c-84e4-289a05d966d2','瑞香花','釋德洪','宋','宋诗','song-poetry','','[]','靈根聞是花中瑞，可憐亦肯乘春開。',64,'全唐诗/poet.song.76000.json','["靈根聞是花中瑞，可憐亦肯乘春開。", "色深卷肉淺巴錦，香濃入骨生秦梅。", "也知秀麗不羣品，最宜陰潔幽庭栽。", "落英紅葉不忍掃，從教狼藉蒙蒼苔。"]'),
('0d2b7c2b-6287-4a01-ba19-897f6398e778','别靈源禪師','釋德洪','宋','宋诗','song-poetry','','[]','平生風骨秀琳琅，水鏡胸懷未易量。',64,'全唐诗/poet.song.76000.json','["平生風骨秀琳琅，水鏡胸懷未易量。", "聲利光中忙趣少，煙霞影裏淡心長。", "雲泉隱德無情動，猿鳥侵身不亂行。", "他日定歸當卜築，青藜紫蕨壯詩腸。"]'),
('569b1757-7c91-4543-a86a-faa989295445','贈許秀才','釋德洪','宋','宋诗','song-poetry','','["\u897f\u6e56"]','虬髭鐵面鶴精神，水鑑心胸不受塵。',64,'全唐诗/poet.song.76000.json','["虬髭鐵面鶴精神，水鑑心胸不受塵。", "吹耳松風靠藜杖，敞衣山月岸綸巾。", "虎頭猿臂成何事，道骨方瞳亦可人。", "他日西湖如過我，飲君一味武林春。"]'),
('69c54b31-4f59-47b9-a186-2af07b73256b','送軫上人之匡山','釋德洪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','何處高人雲路迷，相逢忽薦目前機。',64,'全唐诗/poet.song.76000.json','["何處高人雲路迷，相逢忽薦目前機。", "偶逢菜葉隨流水，知有茅茨在翠微。", "瑣碎夜談皆可聽，煙霏秋嶺欲同歸。", "翛然又向諸方去，無數山供玉麈揮。"]'),
('396a8e51-a92c-4f09-a2a4-09fbb817671c','與晦叔至奉新','釋德洪','宋','宋诗','song-poetry','','[]','欲去未成還執手，西風疏雨晚絲絲。',64,'全唐诗/poet.song.76000.json','["欲去未成還執手，西風疏雨晚絲絲。", "暗驚歲月行飄忽，那更人生苦别離。", "君已到心工筆語，我今歸計老茆茨。", "冷齋後夜誰同宿，莫向燈前讀此詩。"]'),
('a7538eb6-33d2-4aa2-81b0-06fb1b254365','送敏上人','釋德洪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','密林病葉强翻紅，已覺清秋夜氣濃。',64,'全唐诗/poet.song.76000.json','["密林病葉强翻紅，已覺清秋夜氣濃。", "懶復小窗邀獨秀，却應歸夢挂雙峰。", "水分淮甸當懸席，路遶匡山可振筇。", "若見虎溪谿上月，爲言相憶作衰容。"]'),
('39eceaee-785c-4349-a0b3-7aa4b91a8896','過孜莫翁','釋德洪','宋','宋诗','song-poetry','','[]','禹穴朝來散晚參，一程隨便達雲巖。',64,'全唐诗/poet.song.76000.json','["禹穴朝來散晚參，一程隨便達雲巖。", "南山任把浮雲蔽，西嶺猶將落日銜。", "幽徑野花開舊菊，石牀楸子下高杉。", "投宵夜永寒無寐，良憶真僧衣不蠶。"]'),
('eca509fe-fe46-403d-9b99-9806ce4fa1e0','次韻二僧題永安壁上','釋德洪','宋','宋诗','song-poetry','','[]','二休書壁詩爭妙，促席吟時愧不同。',64,'全唐诗/poet.song.76000.json','["二休書壁詩爭妙，促席吟時愧不同。", "豪句大鯨秋駕浪，俊才細馬曉追風。", "支筇放蕩千峰裏，萬事收藏一笑中。", "約我清溪老蓮社，茅茨相映小橋東。"]'),
('9dd22a6d-3dc3-4256-819a-1ff7eff627b6','贈王司法','釋德洪','宋','宋诗','song-poetry','','[]','輕帆已有渡江期，高會清游惜此時。',64,'全唐诗/poet.song.76000.json','["輕帆已有渡江期，高會清游惜此時。", "水閣颺煙晴試茗，雪窗剪燭夜論詩。", "衝寒遠鴈來横浦，弄色新梅半糝枝。", "林下自知無一事，亦應風月動關思。"]'),
('8d2ba268-6902-4982-858e-6a98ce6b30a8','和許樂天','釋德洪','宋','宋诗','song-poetry','','[]','滄溟曾見化微塵，花發桃源幾度春。',64,'全唐诗/poet.song.76000.json','["滄溟曾見化微塵，花發桃源幾度春。", "俗眼莫輕狂道士，此身應是謫仙人。", "清彈一曲悲風遠，絕唱千章白雪新。", "異日三茅成卜築，却因瓶錫得爲鄰。"]'),
('84c127bd-592b-421d-b61a-1b25e5aabaef','師復作水餠供出五詩送别謝之','釋德洪','宋','宋诗','song-poetry','','[]','草堂野飯蜀江濱，妥貼寒光刻削人。',64,'全唐诗/poet.song.76000.json','["草堂野飯蜀江濱，妥貼寒光刻削人。", "忽展五篇爭疾讀，便驚四座暖生春。", "已欣蓮社風流在，更覺溪山氣味新。", "放箸翛然廬嶽去，門欄他日夢應頻。"]'),
('84e94189-cd22-4db3-b97c-dd3af6e57e25','贈鑒上人','釋德洪','宋','宋诗','song-poetry','','[]','毗尼藏出清淨寶，精進林生功德香。',64,'全唐诗/poet.song.76000.json','["毗尼藏出清淨寶，精進林生功德香。", "但得身心常寂靜，自然毛孔發靈光。", "蒼苔不厭芒鞵弊，空翠偏宜壞衲荒。", "好在虎溪長不出，阿持何意尚遊方。"]'),
('18aa0411-296b-4af0-85f0-42b9ff6a2408','贈靜上人','釋德洪','宋','宋诗','song-poetry','','[]','雪摧枯慮默如瘖，秋壓寒松老不禁。',64,'全唐诗/poet.song.76000.json','["雪摧枯慮默如瘖，秋壓寒松老不禁。", "一室閉門稀識面，半窗斜照自拴針。", "重城此日留詩别，疊巘何年結伴尋。", "衰退寧堪久塵土，相看滿眼是歸心。"]'),
('3f1b5981-5f60-4a1f-8047-f2c7fba91c6a','表上人久事雲庵過余石門','釋德洪','宋','宋诗','song-poetry','','[]','凍折枯杉已死灰，豈宜安著在塵埃。',64,'全唐诗/poet.song.76000.json','["凍折枯杉已死灰，豈宜安著在塵埃。", "偎衰不入今人眼，精進曾親古佛來。", "愛子渠渠念綈惠，爲余得得出巖隈。", "蒼顔華首供衰暮，未死重逢更幾回。"]'),
('99c0fadc-28fd-4e49-a9c1-f9c2d031c806','次韻超然','釋德洪','宋','宋诗','song-poetry','','["\u897f\u6e56"]','翠寒空覺此生浮，歲月催人鬢易秋。',64,'全唐诗/poet.song.76000.json','["翠寒空覺此生浮，歲月催人鬢易秋。", "忽憶倚天廬嶽去，更尋清境武林遊。", "情親愧與高人别，興發徒煩夜月留。", "他日西湖遠相憶，爲君一笑散沙鷗。"]'),
('368c85ad-3449-436a-b36b-32a0f9951f91','寄楷禪師','釋德洪','宋','宋诗','song-poetry','','[]','龍蛇頭角混埃塵，臨死方知老淨因。',64,'全唐诗/poet.song.76000.json','["龍蛇頭角混埃塵，臨死方知老淨因。", "三度傲辭天子敕，一生甘作淨名身。", "虎皮羊質成何事，牛馬襟裾亦謾陳。", "須信屈原千載後，空門猶有獨醒人。"]'),
('49a1172e-d50a-406e-9512-7dcf16139ac5','璲首座出示巽中詩','釋德洪','宋','宋诗','song-poetry','','[]','左手不仁右手明，懷情亦復棄藜牀。',64,'全唐诗/poet.song.76000.json','["左手不仁右手明，懷情亦復棄藜牀。", "不知門外山花發，但覺君來笑語香。", "頎紹神情掃秋晚，瘦權詩句挾風霜。", "兩翁杖屨相追逐，此夕因依夜話長。"]'),
('d3ba9a2c-16ed-453a-b3cb-b84cf7c2bfc0','贈李秀才','釋德洪','宋','宋诗','song-poetry','','[]','門掩青山相並居，愛君家法不蕭疏。',64,'全唐诗/poet.song.76000.json','["門掩青山相並居，愛君家法不蕭疏。", "錦囊舉子能佳句，瑞鳥隱公多諫書。", "學士八塼聲價在，謫仙千首笑談餘。", "清朝第一他年事，且看歸來著翠裾。"]'),
('3d541b85-0cef-4976-9566-2d91fd2b1356','贈修上人','釋德洪','宋','宋诗','song-poetry','','[]','我愛修公亦自賢，未忻城郭愛林泉。',64,'全唐诗/poet.song.76000.json','["我愛修公亦自賢，未忻城郭愛林泉。", "醉騎鯨背詩遺落，閑把牛毛字細編。", "還我青山當夏晚，乞君佳句著牀前。", "雨餘獨憑煙雲上，目送孤鴻落照邊。"]'),
('e934eccd-a3b8-4af1-8e17-337f74642bfe','次韻超然竹陰秋夕','釋德洪','宋','宋诗','song-poetry','','[]','月脇雲行夜未深，滿庭風露葉辭林。',64,'全唐诗/poet.song.76000.json','["月脇雲行夜未深，滿庭風露葉辭林。", "知誰墻外千竿竹，分我窗西一畒陰。", "山好已無歸國夢，老閑猶有讀書心。", "剩題詩句酬幽隱，歲月翩翩接趐禽。"]'),
('8ae3fc32-a7a6-4156-9654-dfc4f4cbf7ee','廬山寄都下邦基德祖諸故人','釋德洪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','勢占江南三百里，煙霏相映出層樓。',64,'全唐诗/poet.song.76000.json','["勢占江南三百里，煙霏相映出層樓。", "芒鞵竹杖山兼水，坐看行吟春復秋。", "浮世萬途成底事，吾生一飽更何求。", "故人京洛風埃地，能信山中此樂不。"]'),
('0e1a84bf-d2fb-4981-bad9-6a759b34de51','送宗上人歸南泉','釋德洪','宋','宋诗','song-poetry','','[]','燈外佳眠試冷齋，欲成歸夢暗驚回。',64,'全唐诗/poet.song.76000.json','["燈外佳眠試冷齋，欲成歸夢暗驚回。", "一軒秋色侵衣重，半夜波聲拍枕來。", "江國潮平人獨令，海山家在意徘徊。", "倚藤明日秦淮上，看子風帆十幅開。"]'),
('a30b8a29-de3f-4722-954a-1646fb6ad975','晚坐藏勝橋望石門','釋德洪','宋','宋诗','song-poetry','','[]','好山千葉青蓮曉，斫額令人意已消。',64,'全唐诗/poet.song.76000.json','["好山千葉青蓮曉，斫額令人意已消。", "微出樓臺知有寺，倦行雲樹忽逢橋。", "此生未覺叢林負，肯處真教日劫超。", "閒拾墮薪成淺立，細泉幽澗響寒蜩。"]'),
('d2c8507a-07ee-4045-8a50-d04741c036f2','至圓通僧覓詩','釋德洪','宋','宋诗','song-poetry','','[]','漱霧跳珠響澗泉，千峰秀出雨餘天。',64,'全唐诗/poet.song.76000.json','["漱霧跳珠響澗泉，千峰秀出雨餘天。", "共驚繡帽銅腮老，重到香罏石耳邊。", "清境荒涼歸歎息，故人迎笑尚依然。", "明年過此還相見，應及春風社燕前。"]'),
('b3dd5117-30c4-42ca-8eb6-cc0b3ee0e5cd','送僧遊南嶽','釋德洪','宋','宋诗','song-poetry','','["\u8861\u5c71"]','古寺閒關聊作招，夏秋歸思謾迢迢。',64,'全唐诗/poet.song.76000.json','["古寺閒關聊作招，夏秋歸思謾迢迢。", "枕中柔櫓驚鄉夢，門外秦淮漲夜潮。", "想見舊房生薜荔，不堪疏雨在芭蕉。", "何時却理緣雲策，峰頂同誰看石橋。"]'),
('c5d186df-9af5-40c1-8c9b-a67d17cb337a','送隆上人','釋德洪','宋','宋诗','song-poetry','','[]','人生聚散等兒戲，夢境紛然此一時。',64,'全唐诗/poet.song.76000.json','["人生聚散等兒戲，夢境紛然此一時。", "老去漸知爲客味，秋來長作送人詩。", "感君義色分心曲，慰我年華兩鬢絲。", "想見故鄉霜菊後，屋頭千樹橘纍垂。"]'),
('223b9777-46ce-44bb-86f5-cc92cdeadb7c','次韻諒上人南軒避暑','釋德洪','宋','宋诗','song-poetry','','[]','人間酷暑推不去，愛此南軒一榻空。',64,'全唐诗/poet.song.76000.json','["人間酷暑推不去，愛此南軒一榻空。", "眼倦抛書成午睡，夢悠誰復羨王公。", "豈知塵土隨肥馬，但覺熏風掠壞桐。", "起步西園閒倚杖，石榴花出數枝紅。"]'),
('821312d6-51c7-4262-b19d-3570e5368411','贈吳山人','釋德洪','宋','宋诗','song-poetry','','[]','已得希夷旨趣深，平生蹤跡任浮沉。',64,'全唐诗/poet.song.76000.json','["已得希夷旨趣深，平生蹤跡任浮沉。", "壺中景待和煙卧，海上山須带鶴尋。", "月裏一枝慵舉手，人間萬事肯關心。", "出塵風骨憑誰識，且枕焦桐混世吟。"]'),
('e0470274-2fc6-46d5-ab7e-ab9e37841c83','東溪僧聽泉堂','釋德洪','宋','宋诗','song-poetry','','[]','諸方游徧歸來晚，閒構虚堂贖世紛。',64,'全唐诗/poet.song.76000.json','["諸方游徧歸來晚，閒構虚堂贖世紛。", "雷轉空山動林葉，雪飛亂石濺溪雲。", "石橋舊處龍湫吼，漱玉曾看嶽色分。", "拄策眼高雙耳瞶，上方白塔却親聞。"]'),
('404f8a05-fbf6-4e8d-8884-b04f098cceeb','送莊上人歸雲居','釋德洪','宋','宋诗','song-poetry','','[]','青鎖曉開殘雨上，煙鬟春解笑聲中。',64,'全唐诗/poet.song.76000.json','["青鎖曉開殘雨上，煙鬟春解笑聲中。", "叢林今日猶雌伏，膺簡當年是法雄。", "露盌憶嘗安樂味，錦籠曾著瑞香□。", "何時玉鉢青林下，與子婆娑小立同。"]'),
('8c986245-5441-44f4-83ab-f585e8975244','上元宿百丈','釋德洪','宋','宋诗','song-poetry','','[]','上元獨宿寒巖寺，卧看篝燈映薄紗。',64,'全唐诗/poet.song.76000.json','["上元獨宿寒巖寺，卧看篝燈映薄紗。", "夜久雪猿啼嶽頂，夢回清月在梅花。", "十分春瘦緣何事，一掬歸心未到家。", "却憶少年行樂處，軟紅香霧噴京華。"]'),
('a88714f0-04be-491f-87ab-97b4824fdb84','次韻黄次山見寄','釋德洪','宋','宋诗','song-poetry','','[]','君詩清絕似沅湘，寫妙宣心氣味長。',64,'全唐诗/poet.song.76000.json','["君詩清絕似沅湘，寫妙宣心氣味長。", "地僻且爲三徑樂，才高真是萬夫望。", "随流我自分涇渭，賞駿誰能略牝黄。", "自古豐城匿神物，斗牛應覺動光芒。"]'),
('1a2e87cd-70ea-4f45-a081-873f725b9892','春日同祖賢二道人步雲歸亭忽憶東坡此日詩有懷其人次韻','釋德洪','宋','宋诗','song-poetry','','[]','誰家楊柳欲遮門，依約東坡醉處村。',64,'全唐诗/poet.song.76000.json','["誰家楊柳欲遮門，依約東坡醉處村。", "捶地不堪華屋句，仰天空記刻舟痕。", "尚餘千載風流在，乞與三人語笑温。", "歸路松風吹凍耳，共追前事弔英魂。"]'),
('2e6f26c3-2d05-4b06-869c-e3179cab1d93','與客論東坡作此','釋德洪','宋','宋诗','song-poetry','','[]','東坡醉墨浩琳琅，千首空餘萬丈光。',64,'全唐诗/poet.song.76000.json','["東坡醉墨浩琳琅，千首空餘萬丈光。", "雪裏芭蕉失寒暑，眼中騏驥略玄黄。", "機輪妙轉風雷舌，春色濃纒錦繡腸。", "可惜騎魚天上去，斷絃空壁暗淒凉。"]'),
('ae9fe629-f3a8-46fc-9157-414fa5a5fe52','京師上元觀駕二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','及時膏雨已闌珊，黄道新泥曉未乾。',64,'全唐诗/poet.song.76000.json','["及時膏雨已闌珊，黄道新泥曉未乾。", "白面郎敲金鐙過，紅粧人掲繡簾看。", "管絃叫月宣和氣，燈火燒空奪暮寒。", "咫尺鳳樓開雉扇，玉皇仙仗紫雲端。"]'),
('7d18cfd0-bb39-4a99-a73c-df624d40963e','京師上元觀駕二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','閣雨輕寒斂夕氛，青牛畫轂已争奔。',64,'全唐诗/poet.song.76000.json','["閣雨輕寒斂夕氛，青牛畫轂已争奔。", "皇州浩蕩風光裏，紫陌喧闐笑語温。", "冠壓花枝馳萬騎，簾垂繡箔卷千門。", "特傳詔語君恩重，凝睇天階謝至尊。"]'),
('735290e1-7ebc-40ec-a523-2598be1367bb','次韻天覺進喜雪','釋德洪','宋','宋诗','song-poetry','','[]','萬馬天街聽啟關，曉光佳氣潑人寰。',64,'全唐诗/poet.song.76000.json','["萬馬天街聽啟關，曉光佳氣潑人寰。", "春生殿閣玲瓏外，秀發園林頃刻間。", "爲瑞懽聲浮動植，争妍詩句麗江山。", "從教飛上朱藍袂，點綴彤墀玉筍班。"]'),
('314f704e-3383-4586-874e-89baa33b8d07','别天覺左丞','釋德洪','宋','宋诗','song-poetry','','[]','童頬清光已渾圓，共驚玉骨解藏年。',64,'全唐诗/poet.song.76000.json','["童頬清光已渾圓，共驚玉骨解藏年。", "菴中篆縷長凝帳，門外雲濤欲際天。", "道眼從来無異見，微蹤何幸預談禪。", "新詩滿箧江南去，又作叢林盛事傳。"]'),
('5321f654-d68a-494b-9979-aa5a464e5725','李德茂家有磈石如匡山雙劍峰求詩','釋德洪','宋','宋诗','song-poetry','','["\u534e\u5c71", "\u5e90\u5c71"]','胸次能藏大千界，掌中笑看小重山。',64,'全唐诗/poet.song.76000.json','["胸次能藏大千界，掌中笑看小重山。", "飛来華嶽一峰失，幻出匡廬雙劍閒。", "偶觸篆煙雲點綴，戲澆硯滴瀑潺顔。", "莫將道眼生分别，随意聊安几案間。"]'),
('1135bdc3-c16c-48f9-b6d9-738341c3b720','余昔居百丈元夕有詩後十年是夕過京師期子因不至','釋德洪','宋','宋诗','song-poetry','','[]','北游爛熳看幷川，重到皇州及上元。',64,'全唐诗/poet.song.76000.json','["北游爛熳看幷川，重到皇州及上元。", "燈火風光記前事，管絃音節試新翻。", "期人不至情如海，穿市歸来月滿軒。", "忽憶寒巖曾獨宿，雪窗殘夜一聲猿。"]'),
('47014333-f562-4275-a712-a66a801733ed','都下送僧歸閩','釋德洪','宋','宋诗','song-poetry','','[]','汴水悠悠去不回，綠波垂柳眼初開。',64,'全唐诗/poet.song.76000.json','["汴水悠悠去不回，綠波垂柳眼初開。", "日邊無意事迎送，海畔有山歸去来。", "白却人頭忙日月，緇飄山衲亂風埃。", "此行若到忘情處，拂石猿聲後夜哀。"]'),
('e31f8eba-bf9f-4e14-90ed-ff75a1d4403a','夜雨歇懷淵才邦基','釋德洪','宋','宋诗','song-poetry','','[]','劇笑無因見秀眉，勞生會合恨難期。',64,'全唐诗/poet.song.76000.json','["劇笑無因見秀眉，勞生會合恨難期。", "永懷京國舊遊處，伏枕夢魂初破時。", "戰葉蕭蕭山雨後，遶牀唧唧草蟲悲。", "明年定復西歸去，船尾何妨載我随。"]'),
('9b741ced-a1b7-41f0-91cc-b62054f240a6','寄權巽中','釋德洪','宋','宋诗','song-poetry','','[]','摩雲標格久去眼，傳得詩詞錦段新。',64,'全唐诗/poet.song.76000.json','["摩雲標格久去眼，傳得詩詞錦段新。", "雪玉在躬秋滿鬢，風雷爲舌語驚人。", "留連南浦西山雨，棄擲鑪峰繡谷春。", "何日詩肩擁寒帔，對牀聽我說京塵。"]'),
('99e2a5e4-3f0e-4c8c-96b2-c7b8b4dd3d23','書承天寺西齋壁','釋德洪','宋','宋诗','song-poetry','','[]','半年客食毗陵寺，頗厭塵埃污衲裙。',64,'全唐诗/poet.song.76000.json','["半年客食毗陵寺，頗厭塵埃污衲裙。", "雖有一身猶外物，且將萬事付浮雲。", "忽思放浪佳山水，要與頑麻散骨筋。", "凉夜滿庭風露重，竹梢微月欲紛紛。"]'),
('f3d6140a-d3a6-4571-b3bd-6c038d22b415','靈隱送僧還南嶽','釋德洪','宋','宋诗','song-poetry','','["\u8861\u5c71", "\u897f\u6e56"]','海隅相識笑談餘，清境同疑在玉壺。',64,'全唐诗/poet.song.76000.json','["海隅相識笑談餘，清境同疑在玉壺。", "方作靈山棲小嶺，又随苕水出東吴。", "透鬚白雪驚衰老，脱手青春入歎吁。", "懸想他年衡嶽寺，雨窗相對話西湖。"]'),
('ac1d057e-67c1-49cd-a475-6493185caa63','宿靈山示月上人','釋德洪','宋','宋诗','song-poetry','','[]','地靈形勝自天成，山色溪光潑眼明。',64,'全唐诗/poet.song.76000.json','["地靈形勝自天成，山色溪光潑眼明。", "北岫飛来么鳳落，東鄰相去一牛鳴。", "霜筠遶寺秋無數，璧月臨軒夜更清。", "已約高人結蓮社，他年香火寄餘生。"]'),
('b8851ad8-6cbd-41f1-bfe2-6b45d5102c2b','送僧歸石門','釋德洪','宋','宋诗','song-poetry','','["\u897f\u6e56"]','曾學雲菴逸格禪，别来江柳幾春煙。',64,'全唐诗/poet.song.76000.json','["曾學雲菴逸格禪，别来江柳幾春煙。", "相逢水寺初嘗橘，忽憶風簷共擘蓮。", "遥想到山寒食後，却思分首上元前。", "與誰振策西湖路，清曉一聲啼杜鵑。"]'),
('eec72072-4c55-4fdf-8d17-075fec6b81e8','至西湖招廓然遊春','釋德洪','宋','宋诗','song-poetry','','["\u897f\u6e56"]','别後西湖長在夢，相逢氣韻宛清真。',64,'全唐诗/poet.song.76000.json','["别後西湖長在夢，相逢氣韻宛清真。", "劇談要使君頤脱，大笑從教坐客瞋。", "淮海飄零方見友，湖山秀絕更逢春。", "快當火急追清景，莫厭尋幽散策頻。"]'),
('191f73b5-7bd5-4ebd-961b-f814f6fe6b0b','廓然得石門信歎其踵席非其人用韻酬之二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','相對天涯歲月新，石門消息遠難真。',64,'全唐诗/poet.song.76000.json','["相對天涯歲月新，石門消息遠難真。", "乘閑且覓幾場笑，疾惡休生一念瞋。", "襯鷺芙蕖方破暖，藏鴉柳色又殘春。", "光陰如此空搔首，行誦知歸倦鳥頻。"]'),
('a67f5b15-430e-450e-ad45-02e6456403e5','廓然得石門信歎其踵席非其人用韻酬之二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','頽綱安得見重新，紅紫紛紛正亂真。',64,'全唐诗/poet.song.76000.json','["頽綱安得見重新，紅紫紛紛正亂真。", "已矣無才吾自歎，慨然有志子宜瞋。", "閑尋陳迹消磨日，强作新詩挽絆春。", "振策蘇隄朝復暮，路人應笑往来頻。"]'),
('6621fad4-6e4d-4b51-a7b3-f687dc04e5ec','廓然再和復答之六首  其一','釋德洪','宋','宋诗','song-poetry','','[]','獨立湖邊一笑新，紛紛世事信非真。',64,'全唐诗/poet.song.76000.json','["獨立湖邊一笑新，紛紛世事信非真。", "竹林逢寺端須往，藜杖敲門不怕瞋。", "僮僕見人空自若，軒窗幽處亦藏春。", "老僧那識閑来興，怪我時時過此頻。"]'),
('c4c9e450-2e99-4749-bc49-7bcc25509efa','廓然再和復答之六首  其二','釋德洪','宋','宋诗','song-poetry','','[]','與君藉草湖邊坐，聽我論懷句句真。',64,'全唐诗/poet.song.76000.json','["與君藉草湖邊坐，聽我論懷句句真。", "慵鬭睡魔强分怯，懶酬詩債不須瞋。", "亦知人壽一百歲，已識老来三十春。", "相見幾回開口笑，憂愁風雨可勝頻。"]'),
('198e80d6-cc32-4b9f-9da4-d078e326b932','廓然再和復答之六首  其三','釋德洪','宋','宋诗','song-poetry','','[]','湖水行歌鴨綠新，吴音清軟十分真。',64,'全唐诗/poet.song.76000.json','["湖水行歌鴨綠新，吴音清軟十分真。", "但知客子幽情快，不管游人醉眼瞋。", "戈昔曾聞能倒日，筆今猶喜解收春。", "剩將詩句藏深篋，歸去須知展玩頻。"]'),
('79533235-c683-4452-9063-e5b759516c80','廓然再和復答之六首  其四','釋德洪','宋','宋诗','song-poetry','','[]','處處山川俱勝絕，滿村風物自純真。',64,'全唐诗/poet.song.76000.json','["處處山川俱勝絕，滿村風物自純真。", "横舟隔岸殊堪喚，吠犬随人不識瞋。", "歸鳥獨飛當晚照，鳴鳩相應正深春。", "心期卜築藏幽隱，忽笑行行指劃頻。"]'),
('59d0c79c-e7d1-4c2c-ac51-6aee93aab676','廓然再和復答之六首  其五','釋德洪','宋','宋诗','song-poetry','','[]','湖山昔夢雖非實，開睫今游未必真。',64,'全唐诗/poet.song.76000.json','["湖山昔夢雖非實，開睫今游未必真。", "久客情多空自厭，故山歸晚欲誰瞋。", "聊將愁裏十分興，更賞湖邊一半春。", "君儻肯来尤所願，莫辜日日作詩頻。"]'),
('6e7de2cf-1a0a-431a-9760-c2c96556a79b','廓然再和復答之六首  其六','釋德洪','宋','宋诗','song-poetry','','[]','繞舍初晴對意新，出門幽鳥語如真。',64,'全唐诗/poet.song.76000.json','["繞舍初晴對意新，出門幽鳥語如真。", "催耕布穀殊堪聽，勸客提壺却莫瞋。", "壠麥約風遠有浪，海棠經雨匆添春。", "可憐好景無人共，回首斜陽太息頻。"]'),
('7648ee47-a826-47b7-9f38-93ee0fa93c15','明日欲往龍華瞻大士像廓然和前詩叙其事又用韻答之','釋德洪','宋','宋诗','song-poetry','','[]','雙林大士不復見，聞說龍華畫像真。',64,'全唐诗/poet.song.76000.json','["雙林大士不復見，聞說龍華畫像真。", "要向冰霜識風骨，願求清冷洗貪瞋。", "空庭再拜儼如在，扣几重看喜勝春。", "我亦鈍根期聽法，質疑他日故應頻。"]'),
('cc131d3b-7c4f-4727-ba16-4341a4616e45','又和前韻二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','頭白逢人宛似新，自嗟世態不容真。',64,'全唐诗/poet.song.76000.json','["頭白逢人宛似新，自嗟世態不容真。", "君才廓落宜無合，我語剛强屢被瞋。", "千里来尋非愛雪，一時行樂謾遊春。", "鄰居冷淡應相笑，數夕温然語話頻。"]'),
('b9baca77-1ea9-4d95-b12c-d0f05dd53faf','又和前韻二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','篇篇俊逸間清新，老閲羣才始見真。',64,'全唐诗/poet.song.76000.json','["篇篇俊逸間清新，老閲羣才始見真。", "秀却採蓮溪畔態，豪吞指壁柱邊瞋。", "肺腸舊信能纒錦，文字今知解鬭春。", "筆力肯低容我和，詩成無惜寄来頻。"]'),
('746305c4-da8d-4de4-a28f-45e26e4c2596','偶讀和靖集戲書小詩卷尾云長愛東坡眼不枯解將西子比西湖先生詩妙真如畫爲作春寒出浴圖廓然見詩大怒前詩規我又和二首  其一','釋德洪','宋','宋诗','song-poetry','','["\u897f\u6e56"]','居士多情工比類，先生詩妙解傳真。',64,'全唐诗/poet.song.76000.json','["居士多情工比類，先生詩妙解傳真。", "只知信口從頭詠，那料高人作意瞋。", "雲墮鬂垂初破睡，山低眉促欲嬌春。", "何須夢境生分别，笑我忘懷歎愛頻。"]'),
('8fc0d2b5-3500-4aa7-9eda-31c925fbda89','偶讀和靖集戲書小詩卷尾云長愛東坡眼不枯解將西子比西湖先生詩妙真如畫爲作春寒出浴圖廓然見詩大怒前詩規我又和二首  其二','釋德洪','宋','宋诗','song-poetry','','["\u897f\u6e56"]','輕狂舉世誰非僞，遲鈍知余却甚真。',64,'全唐诗/poet.song.76000.json','["輕狂舉世誰非僞，遲鈍知余却甚真。", "未把僻懷投俗好，且將狂語博君瞋。", "已嗟心折垂垂老，忍看花飛片片春。", "滿眼閑愁圖不得，江南無奈到心頻。"]'),
('1837e367-c2a3-4676-9f86-bcffc317f628','錢濟明作軒於古井旁名冰華賦此','釋德洪','宋','宋诗','song-poetry','','[]','刮地陰風翦玉塵，那知此井解藏春。',64,'全唐诗/poet.song.76000.json','["刮地陰風翦玉塵，那知此井解藏春。", "折膠墮指嗟時事，秀骨温顔似主人。", "碧甃湛明堪數髪，小軒深静可收身。", "超然高趣真難及，浪士愚溪一笑新。"]'),
('430a16e9-ffb5-461f-a628-2697770660b0','鍾山悟真菴西竹林間蒼崖千尺歲久折裂余與敦素行山中至此未嘗不徘徊菴僧爲開軒向之盡收其形勝名曰兩翁作此','釋德洪','宋','宋诗','song-poetry','','[]','水邊脩竹纔堪數，竹外蒼崖已半頽。',64,'全唐诗/poet.song.76000.json','["水邊脩竹纔堪數，竹外蒼崖已半頽。", "我輩自追方外樂，軒窗誰爲此間開。", "待邀山月三人共，要聽松風萬壑哀。", "坐久篆畦香遶遍，碧消煙縷雪殘灰。"]'),
('11c97200-5138-449e-b5c9-b255256a8cf2','次韻敦素兩翁軒見寄','釋德洪','宋','宋诗','song-poetry','','[]','識暗長嗟未燭微，坐令歸夢遶巖扉。',64,'全唐诗/poet.song.76000.json','["識暗長嗟未燭微，坐令歸夢遶巖扉。", "忽驚塵土登須鬂，已覺雲山負衲衣。", "孤坐知君扶瘦策，此詩慰我脱危機。", "天藏鍾阜一區勝，乞與君儕爲發揮。"]'),
('38468cdb-fe02-46bd-af66-1db3b414306b','大風夕懷道夫敦素','釋德洪','宋','宋诗','song-poetry','','[]','病覺春寒花信重，起来散策夕陽中。',64,'全唐诗/poet.song.76000.json','["病覺春寒花信重，起来散策夕陽中。", "方收一霎挂龍雨，忽作千林攧鷂風。", "淮水粘天雪翻浪，吴山吐月鏡緣空。", "二豪詩眼應驚嘆，覓句遥知與我同。"]'),
('8d145367-de70-4ede-a342-b5a203d9c635','宿鹿苑書松上人房二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','數峰煙翠疊黄昏，忽見松間窈窕門。',64,'全唐诗/poet.song.76000.json','["數峰煙翠疊黄昏，忽見松間窈窕門。", "好境未將佳句寫，幽懷先與故人論。", "隔林每恨音容阻，此夕相逢笑語温。", "雪意不成應有月，夜深同看湧金盆。"]'),
('aabfe405-7f61-4088-b57f-da1803fa1609','宿鹿苑書松上人房二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','冷齋託宿自携衾，卧聽松風度栗林。',64,'全唐诗/poet.song.76000.json','["冷齋託宿自携衾，卧聽松風度栗林。", "黄卷青燈紙窗下，白灰紅火地罏深。", "夢回清響春巖溜，夜久幽香噴水沈。", "慣作横刀眠下板，爲君令有住庵心。"]'),
('2121c45d-a4a4-4f2c-9766-e3e9fd38a588','李師尹以端硯見遺作此謝之','釋德洪','宋','宋诗','song-poetry','','[]','歙珍先數刷絲紋，那料端溪更逸群。',64,'全唐诗/poet.song.76000.json','["歙珍先數刷絲紋，那料端溪更逸群。", "已作退閑今似我，温然自重尚如君。", "豈宜禪室埋聲價，合在文場著策勳。", "忍垢風櫺應有夢，夢随筆陣掃煙雲。"]'),
('5706fd10-8e8e-46e0-81ad-94a287a0205f','次韻王節推安道見過雲蓋二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','湘山名與故山齊，寺在沙村斷岸西。',64,'全唐诗/poet.song.76000.json','["湘山名與故山齊，寺在沙村斷岸西。", "繫馬槐根秋雨歇，倚欄雲際暮猿啼。", "公宜談笑光臺閣，我合摧頽老澗谿。", "袖有新詩如瀉出，逼人駿氣不容覊。"]'),
('e16ad29a-1ca4-4384-ab29-750902502672','次韻王節推安道見過雲蓋二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','睡起春衫取次披，髻雲随從倚欄時。',64,'全唐诗/poet.song.76000.json','["睡起春衫取次披，髻雲随從倚欄時。", "生憎柳底鶯聲巧，不分花前日影移。", "伊昔笑来憂易老，而今思去恨難追。", "林梢懸挂團團日，無語東風玉箸垂。"]'),
('6dfd6e9b-1726-452d-837b-c269c0baa19a','宿石霜山前莊夢拜普賢像明日到院見壁間畫如所夢有作','釋德洪','宋','宋诗','song-poetry','','[]','十幅蛾眉紫翠寒，何人逸想發毫端。',64,'全唐诗/poet.song.76000.json','["十幅蛾眉紫翠寒，何人逸想發毫端。", "匆驚瑞色雲間相，曾向清宵夢裏看。", "影像不真心自寂，悟迷無隔指空彈。", "了然一念非新故，我與羣生入正觀。"]'),
('054ee9cb-2c52-40a6-b74f-4e1455fee0a8','贈湧上人乃仁老子也','釋德洪','宋','宋诗','song-poetry','','[]','照人風骨玉頎然，来慰衰途亦自賢。',64,'全唐诗/poet.song.76000.json','["照人風骨玉頎然，来慰衰途亦自賢。", "肝膽秋光磨洞徹，齒牙嶽色嚼芳鮮。", "應傳畫裏風煙句，更學詩中文字禪。", "已作一燈長到曉，定然百衲不知年。"]'),
('d6878c78-b2e9-4cf9-af6c-9792671591f9','道林喜見故人','釋德洪','宋','宋诗','song-poetry','','[]','十年一别今重見，風度依然照映人。',64,'全唐诗/poet.song.76000.json','["十年一别今重見，風度依然照映人。", "韻勝折松秋露骨，氣和寒谷夜生春。", "三都君已傳名譽，萬事吾今付欠伸。", "夢境樓鐘同此聽，獨尋陳迹記前身。"]'),
('b65d60b7-a64e-4feb-be1a-468bb5e62043','送日上人歸石門','釋德洪','宋','宋诗','song-poetry','','[]','三界無家誰適從，大千俱集笑談中。',64,'全唐诗/poet.song.76000.json','["三界無家誰適從，大千俱集笑談中。", "江南湖外夢到曉，宴坐經行月運空。", "狐死懷生正丘首，鳥棲知暖擇南風。", "石門今日名天下，想見沿崖一徑通。"]'),
('83076e0e-f4d5-490f-8442-3bce496c6f72','靈隱山次超然韻時超然歸南嶽住菴勸之','釋德洪','宋','宋诗','song-poetry','','["\u8861\u5c71"]','君亦工詩苦入神，冥捜物象故應貧。',64,'全唐诗/poet.song.76000.json','["君亦工詩苦入神，冥捜物象故應貧。", "客兒亭下纔相見，巾子峰前便卜鄰。", "夢裏筆期生蘂蕚，胸中鏡懶拂埃塵。", "何當鈯斧住山去，要看青原一角麟。"]'),
('7508f158-3a79-4fe1-b678-0efa6da75b80','湘山獨宿聞雨','釋德洪','宋','宋诗','song-poetry','','[]','殷牀鐘静自垂簾，庭樹無聲欲雪天。',64,'全唐诗/poet.song.76000.json','["殷牀鐘静自垂簾，庭樹無聲欲雪天。", "山寺凄凉容我宿，地罏深暖枕肱眠。", "銅瓶秋蚓爲誰泣，蠟燭春花亦自妍。", "夜半夢回聞驟雨，十年蹤跡一茫然。"]'),
('d0f5783e-6711-458d-b671-45dda6eee69a','讀三國志','釋德洪','宋','宋诗','song-poetry','','[]','無計酬勞夏簟凉，遺編枕上閲興亡。',64,'全唐诗/poet.song.76000.json','["無計酬勞夏簟凉，遺編枕上閲興亡。", "氣增髥竟從元德，笑裏瞞徒造子將。", "漢鼎未移存北海，蜀兵已挫失南陽。", "莫將勝敗論人物，忠義千年有耿光。"]'),
('6f066298-20f4-48a9-a07b-c608c584f453','妙高老人卧病遣侍者以墨梅相迓','釋德洪','宋','宋诗','song-poetry','','[]','高絲纔歇轉輕雷，無數晴峰笑靨開。',64,'全唐诗/poet.song.76000.json','["高絲纔歇轉輕雷，無數晴峰笑靨開。", "大士已聞方卧疾，小空端遣出山来。", "寶方世路知無隔，俗駕山靈故勒回。", "多謝高情餞春色，十分渾在一枝梅。"]'),
('9cd8b167-a00d-43af-a5ff-b1d0e92e5bf8','別李公弱','釋德洪','宋','宋诗','song-poetry','','[]','殘紅換得綠陰成，随分閑愁取次生。',64,'全唐诗/poet.song.76000.json','["殘紅換得綠陰成，随分閑愁取次生。", "須信百年終有別，未能一日便無情。", "何時嶽色君同看，後夜湘晴我獨行。", "好在西園行樂處，爲誰依舊月華清。"]'),
('eff6f110-85ad-4eed-9f63-6ce256799b4d','贈關西温上人','釋德洪','宋','宋诗','song-poetry','','[]','鐵面關西氣逸群，平生蹤跡付浮雲。',64,'全唐诗/poet.song.76000.json','["鐵面關西氣逸群，平生蹤跡付浮雲。", "爪州渡口曾同泛，石廪峰前又見君。", "荔子招呼閩嶺外，白粳留滯汝江濆。", "拄藤更入西川去，要讀豐碑未見文。"]'),
('28759fd1-1605-4896-be09-b33bef16f7b1','將登南嶽絕頂而志上人以小團鬭夸見遺作詩謝之','釋德洪','宋','宋诗','song-poetry','','["\u8861\u5c71"]','壑源獨步寶带夸，官焙無雙小月團。',64,'全唐诗/poet.song.76000.json','["壑源獨步寶带夸，官焙無雙小月團。", "未作濃甘生齒頬，先飛微白上眉端。", "湯聲蜂穉秋窗晚，乳面鵝兒春甕寒。", "飲罷爲君登絕頂，俯臨落日看跳丸。"]'),
('cd19274f-ce18-4158-ab85-a2d4f5681616','題草衣巖','釋德洪','宋','宋诗','song-poetry','','[]','鉏頭當枕草爲氈，曾與高人說任緣。',64,'全唐诗/poet.song.76000.json','["鉏頭當枕草爲氈，曾與高人說任緣。", "豈料大嫌沽世價，未應虚費買山錢。", "閑編木葉輕于紙，細葺蘆花軟勝綿。", "石室至今增壯觀，可知千載得人傳。"]'),
('120b17f7-71ad-4883-a493-9af701dcb50b','與僧遊石頭菴','釋德洪','宋','宋诗','song-poetry','','[]','我攜骨面潛谿子，来訪西山鈯斧菴。',64,'全唐诗/poet.song.76000.json','["我攜骨面潛谿子，来訪西山鈯斧菴。", "夢蝶人驚猶栩栩，藏鴉柳暗已毿毿。", "峰連小閣宜春望，水遶重城隔夜談。", "欲喚扁舟尋熟路，與君支策上千巖。"]'),
('b4edccd7-fb40-490c-bbc1-2533a2d7c540','題還軒','釋德洪','宋','宋诗','song-poetry','','[]','老去情枯道自肥，大刀破鏡露全機。',64,'全唐诗/poet.song.76000.json','["老去情枯道自肥，大刀破鏡露全機。", "山邊湖水無行路，枝上春禽亦倦飛。", "半夜舟移空壑在，故鄉家是昔人非。", "炷香閲徧楞嚴義，坐看煙消一縷微。"]'),
('ca4fe3eb-c3ef-4661-a83a-ac9c8e9b4767','送曉上人歸西湖白閣所居','釋德洪','宋','宋诗','song-poetry','','["\u897f\u6e56"]','我憶錢塘雪鬢新，三年東望肺生塵。',64,'全唐诗/poet.song.76000.json','["我憶錢塘雪鬢新，三年東望肺生塵。", "那知南浦清湘岸，忽見西湖白閣人。", "熟視音姿疑夢寐，便驚風物有精神。", "倐然又入千峰去，惆悵孤雲野鶴身。"]'),
('51c74dd9-3363-4e98-a481-5ccdfd295b88','法輪齊禪師開軒于薝蔔叢名曰薝蔔二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','人世百年蝴蝶夢，紛紛栩栩逐春繁。',64,'全唐诗/poet.song.76000.json','["人世百年蝴蝶夢，紛紛栩栩逐春繁。", "觀根戯掃旃檀座，随意爲開薝蔔園。", "君每據梧深有味，我来欲問自忘言。", "叢林何必猶迷照，香在枝頭不在軒。"]'),
('b3047943-6acf-4479-85ce-3baf10a8e387','法輪齊禪師開軒于薝蔔叢名曰薝蔔二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','響石岣嶁峰下寺，小軒開處近山房。',64,'全唐诗/poet.song.76000.json','["響石岣嶁峰下寺，小軒開處近山房。", "苾芻来問宗風事，薝蔔爲薰知見香。", "聊復淡然成獨坐，從教此語徧諸方。", "鈍根不識金輪轉，摘葉尋枝謾嗅芳。"]'),
('80990d49-6536-46af-840f-f3844f2568a5','南嶽法輪寺與西林比居長老齊公築堂於丈室之西名曰雪堂作此寄之','釋德洪','宋','宋诗','song-poetry','','["\u8861\u5c71"]','法道陵夷賴典刑，此堂真有救時心。',64,'全唐诗/poet.song.76000.json','["法道陵夷賴典刑，此堂真有救時心。", "坐令衡嶽爲嵩嶽，便覺西林近少林。", "面壁高風知獨振，薝花細雨爲誰深。", "故應弟子分皮髄，未愧駒兒善古今。"]'),
('da7fe5d5-e6e2-48bd-9d45-7a1e7315eecb','送覺先大師覺先參佛照圓通二老','釋德洪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','浮玉道人雷電舌，法雲老師冰雪顔。',64,'全唐诗/poet.song.76000.json','["浮玉道人雷電舌，法雲老師冰雪顔。", "後来事聽諸方外，先數君游二老間。", "只把黑甜酬世味，從教螺鬢有詩斑。", "乘秋曳杖歸何處，萬疊匡廬是故山。"]'),
('bf060c45-538e-4abe-945c-6c6412545a94','宿慈雲','釋德洪','宋','宋诗','song-poetry','','[]','門前便是小曹谿，只欠孤猿嶺上啼。',64,'全唐诗/poet.song.76000.json','["門前便是小曹谿，只欠孤猿嶺上啼。", "水磨自鳴當濬澮，漁舟閑泊近沙隄。", "經游况是閑心遠，富覽誰能與物齊。", "一宿少留終未足，會須移錫向高棲。"]'),
('aa48837d-7d51-487e-ad5e-e1f8f7c5a139','和答素首座','釋德洪','宋','宋诗','song-poetry','','[]','勘破諸方剩得閑，歸来嶽寺掩深關。',64,'全唐诗/poet.song.76000.json','["勘破諸方剩得閑，歸来嶽寺掩深關。", "我行淺麓驚回地，君在翔鸞杳靄間。", "契闊獨期當再見，峻嚴争說不容攀。", "勿矜出岫無心久，弱羽衝風亦欲還。"]'),
('a4a4d589-d8fd-4185-9346-75a4115bc66a','道林送鴻禪者江陵乞食','釋德洪','宋','宋诗','song-poetry','','[]','一篙湘水碧于螺，瑩净無痕不受磨。',64,'全唐诗/poet.song.76000.json','["一篙湘水碧于螺，瑩净無痕不受磨。", "曉霧有情呵素鏡，東風作惡卷纖羅。", "老来談笑追随少，歲晚别離頭緒多。", "浦口送君聊倚杖，會看歸棹掠晴波。"]'),
('15ee4aec-93c4-42f3-88ed-220c6d3dbd03','還太首座詩卷','釋德洪','宋','宋诗','song-poetry','','[]','料理詩情難復難，縈心結思傾毫端。',64,'全唐诗/poet.song.76000.json','["料理詩情難復難，縈心結思傾毫端。", "奪回天地英秀氣，坐令落紙生風寒。", "老猿夜月叫蒼壁，孤鶴曉霜疏羽翰。", "精神清韻知幾許，付與後来能者看。"]'),
('7f20318f-916e-4803-90c0-1eea603db809','送秦少逸','釋德洪','宋','宋诗','song-poetry','','["\u8861\u5c71"]','秦郎毛骨玉壺秋，望見令人忘百憂。',64,'全唐诗/poet.song.76000.json','["秦郎毛骨玉壺秋，望見令人忘百憂。", "便覺宗之未瀟灑，肻容如晦獨風流。", "来爲南嶽翛然别，去作東華爛熳遊。", "想見醉圍紅粉處，雪牋佳句挽銀鈎。"]'),
('2f5c23cb-55df-4329-84dc-92d200f38a2c','送僧歸筠','釋德洪','宋','宋诗','song-poetry','','[]','西津渡口唐朝寺，到眼瀟湘饜飫看。',64,'全唐诗/poet.song.76000.json','["西津渡口唐朝寺，到眼瀟湘饜飫看。", "誰遣松聲環坐榻，更令嶽色墮欄干。", "君如鳥倦今知返，我與鷗盟久已寒。", "想見若耶溪上路，正嘗盧橘带甘酸。"]'),
('16ef192e-c570-45e7-ba0d-b2ab9bb955e1','宿臨川禪居寺書方丈壁','釋德洪','宋','宋诗','song-poetry','','[]','雨過沙村繫客船，行間樓殿带晴煙。',64,'全唐诗/poet.song.76000.json','["雨過沙村繫客船，行間樓殿带晴煙。", "夜深霜月凉于水，門外雲濤遠際天。", "禾稻豐登如棄土，菱蓮甘美不論錢。", "好峰不住猶行役，匆憶鍾山掬澗泉。"]'),
('786bc92d-19d7-4a5f-bee2-3d080e970f33','朱世英守臨川新開軒而軒有槐高數尺因名之作此','釋德洪','宋','宋诗','song-poetry','','[]','聖朝賢佐蔚如林，天獨於君著意深。',64,'全唐诗/poet.song.76000.json','["聖朝賢佐蔚如林，天獨於君著意深。", "喜氣欲傳黄閣信，夏窗先露綠槐陰。", "望雲匆起懷親念，隱几難忘濟世心。", "他日此軒成故事，壁間應載野僧吟。"]'),
('c63e739e-64b1-4fd3-9337-6231696a5564','世英梅軒','釋德洪','宋','宋诗','song-poetry','','[]','平生忠孝兩難忘，乞得鄰州近故鄉。',64,'全唐诗/poet.song.76000.json','["平生忠孝兩難忘，乞得鄰州近故鄉。", "清白夜晴千里月，肅嚴秋迥一天霜。", "數行徑徹臨清曉，半印香消倚夕陽。", "記取東軒談笑處，庭梅他日似甘棠。"]'),
('c641c781-61d4-4ffb-8295-b705e99b9a89','送琳上人','釋德洪','宋','宋诗','song-poetry','','["\u8861\u5c71"]','髯琳身小膽崔嵬，嚴冷中藏熱肺懷。',64,'全唐诗/poet.song.76000.json','["髯琳身小膽崔嵬，嚴冷中藏熱肺懷。", "京洛歸来嘗自說，湘山游徧與誰偕。", "解將骨董藏涪叟，又負籚篅訪了齋。", "更說開春南嶽去，要尋浯水看磨崖。"]'),
('6307ae9d-1621-49e3-b329-67d817acfe0d','次韻信民教授謝無逸游南湖','釋德洪','宋','宋诗','song-poetry','','[]','春游每覺客愁消，最愛晴湖漲柳橋。',64,'全唐诗/poet.song.76000.json','["春游每覺客愁消，最愛晴湖漲柳橋。", "鴨綠皺寒初拍岸，鵝黄照影自垂條。", "惱人風物今如許，著意春光已不撩。", "但得與君同一醉，何辭日日作詩招。"]'),
('189140b5-3591-42d8-90af-ea7295d8d4c2','思禹兄生日','釋德洪','宋','宋诗','song-poetry','','[]','文章瑞世本奇豪，風鑒霜天夜月高。',64,'全唐诗/poet.song.76000.json','["文章瑞世本奇豪，風鑒霜天夜月高。", "且袖玉堂批誥手，戲来山邑試牛刀。", "意長千里奔頳尾，恩重三山壓巨鼇。", "滿薦壽觴何所祝，祝公親見折蟠桃。"]'),
('712ed2b9-5b1c-47f2-a1f2-535bd4ff51d1','崇仁縣與思禹閑游小寺啜茶聞棋','釋德洪','宋','宋诗','song-poetry','','[]','平生閲世等虚舟，臨汝重来又少留。',64,'全唐诗/poet.song.76000.json','["平生閲世等虚舟，臨汝重来又少留。", "攜弟来逃三伏暑，入門拾得一軒秋。", "隔墻晝永聞棋響，陰屋凉生見樹幽。", "又值能詩王主簿，飯餘春露啜深甌。"]'),
('7d6cce96-ac1c-451e-afbd-39503759c1e1','余居臨汝與思禹和酬甌字韻數首後寓居湘山思禹復和見寄又答之','釋德洪','宋','宋诗','song-poetry','','[]','涔蹄小邑著吞舟，未起風雷更少留。',64,'全唐诗/poet.song.76000.json','["涔蹄小邑著吞舟，未起風雷更少留。", "饌客酒酣顋玉纈，侍兒歌送眼波秋。", "詩成槲葉江村處，想見楊花院落幽。", "綺席憶曾蒙設醴，預聞談笑把空甌。"]'),
('9c226de1-a1d8-45f6-9709-5593a06e5402','次韻蔡儒効見寄','釋德洪','宋','宋诗','song-poetry','','[]','獨宿圓廬意自清，夜凉林木寂無聲。',64,'全唐诗/poet.song.76000.json','["獨宿圓廬意自清，夜凉林木寂無聲。", "鏡中白髪今慵剃，夢裏浮華已嬾争。", "故國别来空好境，舊游誰共讀題名。", "遙知他日重相見，握手應驚太瘦生。"]'),
('fe7d0c94-2fd3-4cea-9a16-4f1e4183bca2','金陵初入制院','釋德洪','宋','宋诗','song-poetry','','[]','依然收付建康獄，拴索瓏璁驚市人。',64,'全唐诗/poet.song.76000.json','["依然收付建康獄，拴索瓏璁驚市人。", "寄語小兒休嬲相，未妨大士戲分身。", "懶於夢境分能所，枉把情緣比客塵。", "笑視死生無可揀，目前刀鋸若爲神。"]'),
('0b8af51d-c522-41da-99d5-e13049843618','寄超然弟','釋德洪','宋','宋诗','song-poetry','','[]','深掩圜扉夜向闌，夢驚清境慰辛酸。',64,'全唐诗/poet.song.76000.json','["深掩圜扉夜向闌，夢驚清境慰辛酸。", "卧聞瓦壠集微霰，起覺衾裯壓薄寒。", "憂患飽經心老大，雲泉歸晚鬢凋殘。", "書空偶爾成詩句，寄與西林阿永看。"]'),
('5655d50c-cb71-4dca-aab0-a018f93a4c71','初至海南呈張子修安撫','釋德洪','宋','宋诗','song-poetry','','[]','南来稍復召驚魂，知有留侯異代孫。',64,'全唐诗/poet.song.76000.json','["南来稍復召驚魂，知有留侯異代孫。", "未即解衣甘九死，試令騎馬賦千言。", "瓊山有月光相射，玉海無風浪自翻。", "戲下應傳獲羅什，秃頭争看戴華軒。"]'),
('f351b063-484d-427f-89fe-b5b6ac5dd01c','抵瓊夜爲颶風吹去所居屋','釋德洪','宋','宋诗','song-poetry','','[]','貪看長鯨吸舟楫，忽驚嬌蜃吐樓臺。',64,'全唐诗/poet.song.76000.json','["貪看長鯨吸舟楫，忽驚嬌蜃吐樓臺。", "朦朧醉憶王城别，汗漫游從海國来。", "夜半颶風攜屋去，朝来瘴霧放天回。", "會須横笛騎雲背，笑響從教落九垓。"]'),
('20c342d8-d5ef-4c97-bba8-aca1d01083bc','出朱崖驛與子修','釋德洪','宋','宋诗','song-poetry','','[]','投老南来雪滿顛，覊囚不自憶生全。',64,'全唐诗/poet.song.76000.json','["投老南来雪滿顛，覊囚不自憶生全。", "久爲白骨今重肉，已卧黄泉復見天。", "報德定應追結草，効忠那肯愧餐氈。", "此詩清絕如冰雪，乞與江山洗瘴煙。"]'),
('515f62c8-5f40-4837-b9d1-21412ccfa700','别子修二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','疆埸探騎斷犇埃，院落棠陰暗綠苔。',64,'全唐诗/poet.song.76000.json','["疆埸探騎斷犇埃，院落棠陰暗綠苔。", "上疏乞閑追鮑靘，載書歸老繼吴恢。", "争懷父母三年化，愁見風帆十幅開。", "勿剪青青堤下柳，念公遺愛手親栽。"]'),
('db7cea41-2f3d-4b48-b153-bbb9a58fb878','别子修二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','漂泊孤蹤一轉蓬，語音雖在變形容。',64,'全唐诗/poet.song.76000.json','["漂泊孤蹤一轉蓬，語音雖在變形容。", "瘴鄉猿鳥今爲伍，螘穴王侯昔夢封。", "海闊盲龜登木孔，山高纖芥落鍼鋒。", "公歸不得參行馭，心折淮南紫翠重。"]'),
('bc2d9016-0567-48cd-863f-73ee42f4eb27','蔡州道中','釋德洪','宋','宋诗','song-poetry','','[]','北来行盡關山道，梁宋郊墟眼力微。',64,'全唐诗/poet.song.76000.json','["北来行盡關山道，梁宋郊墟眼力微。", "飲食甘酸雜淮甸，語音清軟近京畿。", "黄塵又向九天去，槁項新從萬里歸。", "投老不堪行役苦，手遮西日想巖扉。"]'),
('8c50c574-52d4-4410-a473-8faa384a15a1','余號甘露滅所至問者甚多作此','釋德洪','宋','宋诗','song-poetry','','[]','老儼化身甘露滅，不妨須髪著伽梨。',65,'全唐诗/poet.song.76000.json','["老儼化身甘露滅，不妨須髪著伽梨。", "虚舟閲世鴟夷子，彗箒囗囗除王伯齊。", "香火共修心老大，樓鐘重聽意凄迷。", "餘生未覺全無累，折脚鐺猶手自提。"]'),
('715f0953-e4c9-456c-8099-721510a7ac52','海上初還至南嶽寄方廣首座','釋德洪','宋','宋诗','song-poetry','','["\u8861\u5c71"]','天風吹笑落人間，白髪新從死地還。',64,'全唐诗/poet.song.76000.json','["天風吹笑落人間，白髪新從死地還。", "往事暗驚如昨夢，此生重復見名山。", "倦禪想見堆危坐，知法應抛放縱閑。", "初嚼芳鮮動詩思，一篇先寄倩君刪。"]'),
('35608193-fd85-4b5a-bcde-4e475b7aa047','陳生攜文見過','釋德洪','宋','宋诗','song-poetry','','[]','海外歸来兩鬂秋，自嗟無地可逃羞。',64,'全唐诗/poet.song.76000.json','["海外歸来兩鬂秋，自嗟無地可逃羞。", "攜筇肯過驚時聽，炊黍能爲信宿留。", "睡觸屏風譏富貴，笑分臠社致公侯。", "遺編家世丹青著，鐵硯磨穿未肯休。"]'),
('69504f17-0331-4014-865e-53086a1d95f5','至筠二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','乞漿問路到筠溪，天氣清和得所宜。',64,'全唐诗/poet.song.76000.json','["乞漿問路到筠溪，天氣清和得所宜。", "父老相逢班草坐，風光初過採茶時。", "摩挲禪榻營春睡，想像齋厨辦晚炊。", "白首不知舟壑走，壁間来讀舊題詩。"]'),
('afd715a7-7b7a-45fe-9f85-68be1eae6b5d','至筠二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','偶喚歸舟隔亂谿，春山偏與晚相宜。',64,'全唐诗/poet.song.76000.json','["偶喚歸舟隔亂谿，春山偏與晚相宜。", "自尋熟路懸崖去，正是新秧刺水時。", "身健已如秋社燕，夢回猶看客亭炊。", "雨窗燈火清相對，畫出淵明五字詩。"]'),
('a05488f6-7622-4c3b-a01b-1ae995c79fb7','示超然','釋德洪','宋','宋诗','song-poetry','','[]','秋光滿鬢萬事死，慚愧眼明牙齒牢。',64,'全唐诗/poet.song.76000.json','["秋光滿鬢萬事死，慚愧眼明牙齒牢。", "野寺閑眠聽風雨，海山猶夢渡雲濤。", "事非白傅方驚鼎，迹隱庖丁已善刀。", "一徑莓苔三十載，未容此老獨奇豪。"]'),
('4afa26ec-a276-47bd-a6c4-ff0d1b73dfb4','九日','釋德洪','宋','宋诗','song-poetry','','[]','去歲重陽瘴海濱，病拈霜蘂嗅清晨。',64,'全唐诗/poet.song.76000.json','["去歲重陽瘴海濱，病拈霜蘂嗅清晨。", "身閑已斷思歸夢，山好仍逢稱意人。", "卯飯露葵欣旋摘，夜窗風栗共嘗新。", "妙年衲子應相笑，癡鈍耽源老應真。"]'),
('dc462da7-8198-4112-9f62-8b4cbe5d961f','二十日偶書二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','春林院落曲欄東，小立初迎到面風。',64,'全唐诗/poet.song.76000.json','["春林院落曲欄東，小立初迎到面風。", "冰齒寒生花坼信，濕梅煙重雨毛空。", "病衰老去登臨倦，節物年時氣味同。", "却掩罏煙閉深閣，匆驚西日借窗紅。"]'),
('67b28a3d-1aed-4e42-a5ac-3dad436ee0a3','二十日偶書二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','此生早衰坐世故，末路易歸驚嶮艱。',64,'全唐诗/poet.song.76000.json','["此生早衰坐世故，末路易歸驚嶮艱。", "臨事無疑知道力，讀書有味覺身閑。", "解醫憂患臂三折，難隱文章豹一斑。", "永媿山赤頭璨，不令姓氏落人間。"]'),
('cd97652e-a9eb-4f63-a6f3-a3c8617e8ee7','陳瑩中左司自丹丘欲家豫章至湓浦而止余自九峰往見之二首  其一','釋德洪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','雁蕩天台看得足，却搬兒女寄蓬窗。',64,'全唐诗/poet.song.76000.json','["雁蕩天台看得足，却搬兒女寄蓬窗。", "徑来漳水謀三頃，偶愛廬山家九江。", "名節逼真如醉白，生涯領畧類湘龐。", "向来萬事都休理，且聽樓鐘一夜撞。"]'),
('846df993-54ce-4e7c-aaea-c21bfa127e71','陳瑩中左司自丹丘欲家豫章至湓浦而止余自九峰往見之二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','與公靈鷲曾聽法，游戲人間知幾生。',72,'全唐诗/poet.song.76000.json','["與公靈鷲曾聽法，游戲人間知幾生。", "夏口甕中藏畫像，孤山月下認歌聲。", "翳消已覺華無蒂，鑛盡今知珠自明。", "遠壑夕陽殘雨後，作數抹夕陽殘雨外一番飛絮滿江城。"]'),
('a94f24e5-7ea5-4e54-bbea-134f946a5524','次韻李端叔見寄','釋德洪','宋','宋诗','song-poetry','','[]','一官游戲且同塵，夢寐江湖亦可人。',64,'全唐诗/poet.song.76000.json','["一官游戲且同塵，夢寐江湖亦可人。", "軒冕久知身是寄，魚鰕纔說口生津。", "解嘲鏡裏蕭疏髪，時吐毫端浩蕩春。", "自古浯溪好風月，買山終欲與君鄰。"]'),
('b6241442-cff1-4ba1-8ed6-38ee32688d14','赴太原獄別上藍禪師','釋德洪','宋','宋诗','song-poetry','','[]','平昔巾盂共空壁，只今樓觀礙層霄。',64,'全唐诗/poet.song.76000.json','["平昔巾盂共空壁，只今樓觀礙層霄。", "道心針水妙應在，俗眼雲泥謾覺遥。", "道路爲家身是寄，死生如夢意全消。", "明年五頂東游徧，来聽吴音發海潮。"]'),
('a667ac72-3251-4abf-b62d-36282cdb98c1','太原還見明於洪水上藍問明别後嘗寓則曰十年客雲居感歎其高遁作此','釋德洪','宋','宋诗','song-poetry','','[]','清軟吴音笑展眉，芳鮮猶在雪霜姿。',64,'全唐诗/poet.song.76000.json','["清軟吴音笑展眉，芳鮮猶在雪霜姿。", "十年不下歐峰頂，一旦肯来漳水湄。", "湘巘春深重記處，風甌雨歇對聞時。", "紅塵未可因藏跡，要卜雲泉結後期。"]'),
('d798509c-1df7-48b6-9954-21bddb9a55c0','温上人自廬山見過','釋德洪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','雀羅門巷榻凝塵，千里相尋駭四鄰。',64,'全唐诗/poet.song.76000.json','["雀羅門巷榻凝塵，千里相尋駭四鄰。", "好事真誠虹貫日，照人清氣水含春。", "忽驚我禍今無比，高笑君癡亦絕倫。", "此别遥知想標格，淺雲東崦對冰輪。"]'),
('4494fb05-c3cf-41ab-9ddd-de7571a777e3','荷塘暑雨過凉甚宜之見訪作此','釋德洪','宋','宋诗','song-poetry','','[]','居近池塘春意在，路穿空翠夕陽多。',64,'全唐诗/poet.song.76000.json','["居近池塘春意在，路穿空翠夕陽多。", "隔林放鹿哀怨語，掠水幽禽撲摝過。", "得雨村囂覺風味，分秧天氣愛清和。", "莫辭坐穩相尋數，酣戰難回指日戈。"]'),
('768b6de5-cce1-4a7a-9015-b5bb4f4bbbb1','重會言上人乞詩','釋德洪','宋','宋诗','song-poetry','','[]','海外歸来五見春，梨衣兩識帝京塵。',64,'全唐诗/poet.song.76000.json','["海外歸来五見春，梨衣兩識帝京塵。", "此生已覺渾無累，爲累空驚尚有身。", "厚善最憐山解事，歲寒更愛月情親。", "鷲峰峰下重相見，雪作飛花一笑新。"]'),
('9ebbda67-2487-4002-92ad-eaaca835c172','誠心二上人見過','釋德洪','宋','宋诗','song-poetry','','[]','破夏来尋甘露滅，快人如對水晶輪。',64,'全唐诗/poet.song.76000.json','["破夏来尋甘露滅，快人如對水晶輪。", "煙雲掃盡詞傳意，知見不生情透塵。", "旋縛茅茨吞遠壑，偶臨簷隙見歸人。", "露芽便覺如浮雪，品坐同分一盞春。"]'),
('9a910128-989b-4e2b-bdca-5d5c83a68f76','秋夕示超然','釋德洪','宋','宋诗','song-poetry','','[]','殿閣知誰燒夜香，矮窗燈火試新凉。',64,'全唐诗/poet.song.76000.json','["殿閣知誰燒夜香，矮窗燈火試新凉。", "草蟲對語僧臨砌，露葉翻光月轉廊。", "補綴高風三襪綫，破除清夢一匡牀。", "與君遊徧人間世，折脚鐺中滋味長。"]'),
('db77650a-e6f8-4b41-8c2c-597311698f03','鞦韆','釋德洪','宋','宋诗','song-poetry','','[]','畫架雙裁翠絡偏，佳人春戲小樓前。',64,'全唐诗/poet.song.76000.json','["畫架雙裁翠絡偏，佳人春戲小樓前。", "飄揚血色裙拖地，斷送玉容人上天。", "花板潤霑紅杏雨，綵繩斜挂綠楊煙。", "下来閑處從容立，疑是蟾宫謫降仙。"]'),
('4d125d1e-43c2-4687-b654-85ae10305373','謁靈源塔','釋德洪','宋','宋诗','song-poetry','','[]','高颿駕浪過南溟，那料歸来掃此亭。',64,'全唐诗/poet.song.76000.json','["高颿駕浪過南溟，那料歸来掃此亭。", "桃李成陰春老大，谿山好在鬢凋零。", "瓦燈已照宫商石，卵塔分藏服匿瓶。", "春雪尚能知客意，蕩除毛孔瘴煙腥。"]'),
('65ffc1b0-d5a1-4726-a105-53a5a33164a7','春日會思禹兄於谿堂','釋德洪','宋','宋诗','song-poetry','','[]','門前谿水蒲萄綠，風掠松窗料峭寒。',64,'全唐诗/poet.song.76000.json','["門前谿水蒲萄綠，風掠松窗料峭寒。", "忽憶十年同禍福，那知今日共盤餐。", "盡籖書策齊幽架，已買漁舟泊小灘。", "君會不嫌村落僻，乘閑来此弄漁竿。"]'),
('5dae82ef-0cfa-40b6-b23d-89d78bd3a912','招夏均父','釋德洪','宋','宋诗','song-poetry','','[]','北山深轉青松壑，萬疊煙霏空翠堆。',64,'全唐诗/poet.song.76000.json','["北山深轉青松壑，萬疊煙霏空翠堆。", "元亮果堪中路竢，子猷那敢棹舟回。", "鳥工魂夢尋公去，蟬蜕塵埃出郭来。", "他日荆林談笑處，行人應指兩翁臺。"]'),
('12d907ac-10c3-447f-a416-3dc46eddcdde','贈僧','釋德洪','宋','宋诗','song-poetry','','[]','欹枕無人夢自驚，回廊廣殿午風清。',64,'全唐诗/poet.song.76000.json','["欹枕無人夢自驚，回廊廣殿午風清。", "已浮春露澆詩膽，更炷水沉熏道情。", "憂患撼牀聞螘鬭，功名殷鬢作蚊聲。", "欲依浄社陪香火，僻處安排折脚鐺。"]'),
('6f03bdb7-6e0d-4769-923d-3b0ad58500ad','資國寺西齋示超然二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','對眠偶此風雨夕，又近寒巖槲葉村。',64,'全唐诗/poet.song.76000.json','["對眠偶此風雨夕，又近寒巖槲葉村。", "謝晝未焚風鑑在，韋郎不見語言存。", "歲時暗覺持山去，憂患空驚斫水痕。", "綠髪彫零心已死，成蹊桃李落華分。"]'),
('bb5cbe33-b8b9-4f0a-bbf3-241a246c7db2','資國寺西齋示超然二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','人間炊黍未及熟，萬事只今歸欠申。',64,'全唐诗/poet.song.76000.json','["人間炊黍未及熟，萬事只今歸欠申。", "巳織青駒餞華騮，更披白帢稱閑身。", "遺編終不求甚解，故人但願長相親。", "去年此日瓊南岸，漲海翻天探騎塵。"]'),
('bc0334f6-ba3c-4053-a73e-94276f589880','贈寄老菴僧','釋德洪','宋','宋诗','song-poetry','','[]','自憐玉鉢雙峰信，来訪牛頭懶比丘。',64,'全唐诗/poet.song.76000.json','["自憐玉鉢雙峰信，来訪牛頭懶比丘。", "山色深濃過夜半，月華清亮近中秋。", "已欣境勝如龍阜，更覺菴幽占鳳頭。", "夢幻此身猶且在，杖藜投老得追遊。"]'),
('25f4135a-0cc6-4be0-84b0-18ddafd474cf','懷李道夫','釋德洪','宋','宋诗','song-poetry','','[]','半篙晚漲綠楊灣，接翅鷗歸霧雨殘。',64,'全唐诗/poet.song.76000.json','["半篙晚漲綠楊灣，接翅鷗歸霧雨殘。", "數疊吴山圍楚夢，一番花信釀春寒。", "别時小語依然在，隔歲来書展復看。", "補衮胸中五色線，只今應作怒蜺蟠。"]'),
('c2030fbf-a376-4e1f-b247-eb2b9b7ddf6d','余所居連超然自見軒日多啜茶其上二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','三生事辦吾知要，一室香凝獨掩門。',64,'全唐诗/poet.song.76000.json','["三生事辦吾知要，一室香凝獨掩門。", "睡足便驚清晝夜，火紅消盡白灰存。", "巷無俗駕螘紛繞，鄰有高人玉粹温。", "隱比价膺猶可媿，會茶時復到幽軒。"]'),
('4efbfa0e-301e-484a-8d35-8976ad6bb1a2','余所居連超然自見軒日多啜茶其上二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','功名今古一雞肋，美味那知是禍根。',64,'全唐诗/poet.song.76000.json','["功名今古一雞肋，美味那知是禍根。", "掃迹世途龜曳尾，僻居烟霧豹埋文。", "如期見訪穿窗月，不吿而行出岫雲。", "火浴未爲無伴助，塔吾遺骨尚煩君。"]'),
('694bbd0f-a23f-4f4d-a2b2-998023653823','徐師川罪余作詩多恐招禍因焚去筆硯入居九峰投老菴讀高僧曇諦傳忽作數語是足成之以寄師川師川讀之想亦見赦二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','歸来卧起有餘適，老去消磨無雜緣。',64,'全唐诗/poet.song.76000.json','["歸来卧起有餘適，老去消磨無雜緣。", "門外不知何歲月，夢中亦覺在雲泉。", "千年高道誰酬價，一世清閑我賣錢。", "安得道人江北去，此詩先錄寄師川。"]'),
('13a7616d-1671-45ce-a5cf-18d411d1ab9f','徐師川罪余作詩多恐招禍因焚去筆硯入居九峰投老菴讀高僧曇諦傳忽作數語是足成之以寄師川師川讀之想亦見赦二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','古書漫滅字斕斑，眼倦頽然整頓閑。',64,'全唐诗/poet.song.76000.json','["古書漫滅字斕斑，眼倦頽然整頓閑。", "以法爲親疏世相，視身如幻寄人間。", "業緣有盡今脱手，老態無因日上顔。", "已辦一瓢期澗飲，要刳餘潤到崑山。"]'),
('3ed92f83-e495-4046-af68-43ccec9fd291','雲巖寶鏡三昧','釋德洪','宋','宋诗','song-poetry','','[]','寶鏡當機不密傳，纖毫滲漏墮言詮。',64,'全唐诗/poet.song.76000.json','["寶鏡當機不密傳，纖毫滲漏墮言詮。", "圓伊三點分賓主，妙挟雙明絕正偏。", "暗裏丹青元異色，句中涇渭本同川。", "嬰兒索物哆啝耳，與物寧瞋語未全。"]'),
('a62a6681-4351-4d7a-b5a0-4a171e8ab8f2','過永寧寺','釋德洪','宋','宋诗','song-poetry','','[]','已背荒南過永寧，犯寒呵手捉枯藤。',64,'全唐诗/poet.song.76000.json','["已背荒南過永寧，犯寒呵手捉枯藤。", "雪如鏡底頷絲白，山學誰家眉黛青。", "射影風光知脱離，伐冰門巷覺添增。", "故人不用驚風帽，我是前身卧像僧。"]'),
('50a3a854-386a-4f64-9705-6777d9511d0e','十一月十七日發豫章歸谷山','釋德洪','宋','宋诗','song-poetry','','[]','急景窮冬一千里，筍輿部曲去匆匆。',64,'全唐诗/poet.song.76000.json','["急景窮冬一千里，筍輿部曲去匆匆。", "候船班草江津岸，曝日探簷山店中。", "袖手歸休今日是，隔生冤債轉頭空。", "湘西雪後青松徑，想見聲盤萬壑風。"]'),
('6408444f-7fff-45c2-9447-527e8ddcd97e','立春前一日雪','釋德洪','宋','宋诗','song-poetry','','[]','明日立春今日雪，雪中殘響滴虚簷。',64,'全唐诗/poet.song.76000.json','["明日立春今日雪，雪中殘響滴虚簷。", "方增謾說寒威在，不絕潛知煖氣添。", "客去旋開書對語，閑多偏與懶相兼。", "湘山自古愁眉淺，縱御鉛華不到尖。"]'),
('5f036a88-095e-4aec-a05e-c286080d368e','明年湘西大雪次韻送僧吴','釋德洪','宋','宋诗','song-poetry','','[]','夜殘陡覺寒生骨，夢斷空驚月轉簷。',64,'全唐诗/poet.song.76000.json','["夜殘陡覺寒生骨，夢斷空驚月轉簷。", "瓶響卧聞秋蚓泣，火紅起撥白灰添。", "欲酬清景尋儂去，更棹扁舟與子兼。", "要倩新詩寫愁絕，笑呵凍硯蘸毫尖。"]'),
('643abbbb-ee17-42a7-80ac-447b32ab760a','題清富堂','釋德洪','宋','宋诗','song-poetry','','[]','此堂冠絕湘西勝，枯木名多道不窮。',64,'全唐诗/poet.song.76000.json','["此堂冠絕湘西勝，枯木名多道不窮。", "用谷量雲當衣鉢，以江盛月展家風。", "買山歸隱真寒乞，借竹爲軒落笑中。", "綠錦漲連青玉浦，剪裁磨琢費詩工。"]'),
('90125b57-1a95-419b-a9a1-17929e9dbd33','湘西暮歸','釋德洪','宋','宋诗','song-poetry','','[]','筍輿鼓角背層城，湘水涸盡行沙汀。',64,'全唐诗/poet.song.76000.json','["筍輿鼓角背層城，湘水涸盡行沙汀。", "嶽麓雪雲獻樓閣，橘洲煙雨學丹青。", "此生多艱付跛挈，投老餘閑到寂惺。", "蒼鬛萬身門窈窕，歸来風葉掃空庭。"]'),
('3e756ec4-d8e6-4c37-ba93-b90ef1defcb6','効李白湘中體','釋德洪','宋','宋诗','song-poetry','','[]','夕光江揺魚尾紅，何處扁舟開晚篷。',64,'全唐诗/poet.song.76000.json','["夕光江揺魚尾紅，何處扁舟開晚篷。", "雁字初成春有信，烟鬟空好雨無蹤。", "荒寒數葦橘洲岸，領略半窗湘寺鐘。", "浦口行人已争渡，林下歸僧欣一逢。"]'),
('56d377b3-e2cf-4a93-b2eb-b19fd72e7f50','次韻王舍人蘭室','釋德洪','宋','宋诗','song-poetry','','[]','起爇清香試返魂，松花閑泛刷絲紋。',64,'全唐诗/poet.song.76000.json','["起爇清香試返魂，松花閑泛刷絲紋。", "幽齋事業誰同辦，小斛蘭叢手自分。", "家世到今猶玉食，交朋强半在青雲。", "笑談麈尾延僧宿，要聽清言洗俗氛。"]'),
('e223bca2-c757-4756-a487-753876e81c07','次韻熏堂','釋德洪','宋','宋诗','song-poetry','','[]','無言桃李已垂陰，小雨南風自滿襟。',64,'全唐诗/poet.song.76000.json','["無言桃李已垂陰，小雨南風自滿襟。", "佳客偶来持茗盌，寶書看罷整瑤琴。", "未容絲竹陶閑適，盡把雲山付醉吟。", "圖畫麒麟他日事，不將行樂負初心。"]'),
('8a207f21-7fb8-4c22-87ae-6263e10a3bda','次韻寄傲軒','釋德洪','宋','宋诗','song-poetry','','[]','道夫飛鳥倦知還，一鉢安巢又故山。',64,'全唐诗/poet.song.76000.json','["道夫飛鳥倦知還，一鉢安巢又故山。", "無累自然增逸興，有名終恐廢長閑。", "背時生計風煙上，随意園林指顧間。", "應笑市朝争奪者，暗驚清鏡失朱顔。"]'),
('3fc6072d-a58c-4eb2-9236-ed455914d9d2','次韻吏隱堂二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','拄笏西山爽氣新，萬人如海一閑身。',64,'全唐诗/poet.song.76000.json','["拄笏西山爽氣新，萬人如海一閑身。", "堂中自蠟登山屐，門外從增沒馬塵。", "美祿方辭緣肆志，華軒偶羡見清真。", "遺編半掩思標致，未必今人愧古人。"]'),
('c55ff70b-2722-4dde-bc4f-f8d2c3fee2cb','次韻吏隱堂二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','此堂華構面層城，意趣追回萬古情。',64,'全唐诗/poet.song.76000.json','["此堂華構面層城，意趣追回萬古情。", "落帽被嘲真有道，買金償謗亦求名。", "黄庭卷掩凝香縷，畫戟門深列衛兵。", "安用山林笑朝市，戲將軒冕寄餘生。"]'),
('3190f4fe-fb32-46ee-af96-68173241d66c','次韻集虚堂','釋德洪','宋','宋诗','song-poetry','','[]','從来鮑靚有仙風，腦滿方知氣自冲。',64,'全唐诗/poet.song.76000.json','["從来鮑靚有仙風，腦滿方知氣自冲。", "萬事收藏微笑裏，十虚俱集一塵中。", "乾城不礙丹青色，天女何殊大小空。", "滿地落花春寂寂，岸巾時倚曲欄東。"]'),
('68e06c8d-22b8-4d87-bc8b-6c5445a184b8','次韻宿東安','釋德洪','宋','宋诗','song-poetry','','[]','淡雲缺月兩微茫，獨酌沽来竹葉香。',64,'全唐诗/poet.song.76000.json','["淡雲缺月兩微茫，獨酌沽来竹葉香。", "已把功名比雞肋，更驚世路似羊腸。", "心情老去俱消盡，詩律年来覺倍强。", "解誦東坡北歸曲，此身安處是吾鄉。"]'),
('a455c227-26b0-48fc-ba11-bea265056ec3','次韻宿黄沙','釋德洪','宋','宋诗','song-poetry','','[]','無計遮攔歲月飛，歲除江寺老垂垂。',64,'全唐诗/poet.song.76000.json','["無計遮攔歲月飛，歲除江寺老垂垂。", "自圍紅火堆危坐，熟讀黄沙感歎詩。", "已笑因山論肥瘠，更驚逢水說分離。", "重湖去國三千里，想見殘缸夢斷時。"]'),
('acb7ce84-9edb-4c16-9ce6-1440023f9826','次韻雙秀堂','釋德洪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','窗戶青紅花木繁，午陰脩徑接深關。',64,'全唐诗/poet.song.76000.json','["窗戶青紅花木繁，午陰脩徑接深關。", "人如巢許逃名迹，山學娥英露髻鬟。", "採菊悠然常獨見，望雲時復對僧閑。", "夜聞松雨驚飛瀑，疑宿匡廬黄石間。"]'),
('a9222340-7d86-4ef8-b08a-082d5ace25fd','次韻垂金館','釋德洪','宋','宋诗','song-poetry','','[]','風簷負日背胡牀，千顆初驚昨夜霜。',64,'全唐诗/poet.song.76000.json','["風簷負日背胡牀，千顆初驚昨夜霜。", "噀霧香争和露擘，過墻枝作照林光。", "佳名曾用題書尾，小字仍呼背藥囊。", "先與兒曹爲美兆，讀書窗映笏頭黄。"]'),
('90a2f1da-c96b-4a99-bd27-efcefef8e0da','次韻贈慶代禪師','釋德洪','宋','宋诗','song-poetry','','[]','蓮峰千葉吐晴烟，玉頬遥知一粲然。',64,'全唐诗/poet.song.76000.json','["蓮峰千葉吐晴烟，玉頬遥知一粲然。", "梅塢雪消香錯莫，菴僧老盡氣完全。", "暗驚夢蝶人間世，回看醯雞甕裏天。", "誰見清言横麈尾，滿庭風露竹娟娟。"]'),
('251d4a73-c382-4949-976b-6fe86fcde21f','次韻宿清修寺','釋德洪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','湘山也學廬山好，落瀑聲飛繡谷風。',64,'全唐诗/poet.song.76000.json','["湘山也學廬山好，落瀑聲飛繡谷風。", "正欲來歸向兒說，戲將收拾入詩中。", "浪驚醉枕寒松響，春滿茶鐺活火紅。", "清景骨飛嗟未到，故應唯許夢魂通。"]'),
('29a303b6-914b-4b09-b726-2503e81959c9','次韻自清修過大溈亂山間作','釋德洪','宋','宋诗','song-poetry','','[]','行盡湘南盡處山，愛公高韻不容攀。',64,'全唐诗/poet.song.76000.json','["行盡湘南盡處山，愛公高韻不容攀。", "會當拭目瞻雙闕，應笑尋幽到百蠻。", "甚欲解鞍休犖确，更能揎手弄潺顔。", "定知醉看千巖曉，大字題名石壁間。"]'),
('5e0cf0bb-52a4-4938-bbd4-5b2acff00573','次韻郴江有作','釋德洪','宋','宋诗','song-poetry','','[]','持節南来喜欲狂，弄舟時得棹清湘。',64,'全唐诗/poet.song.76000.json','["持節南来喜欲狂，弄舟時得棹清湘。", "然膏獨宿牽牛洞，枕玉曾眠錦瑟傍。", "未可便尋閑作伴，不須先以醉爲鄉。", "金城馳至陳方略，要指先鋒一破羌。"]'),
('26467624-3d68-4b63-9965-c38a2423080b','次韻題罷徭亭','釋德洪','宋','宋诗','song-poetry','','[]','聞君新構罷徭亭，邂逅河源又報清。',64,'全唐诗/poet.song.76000.json','["聞君新構罷徭亭，邂逅河源又報清。", "郡郭不輸天子賦，谿山偏協野人情。", "唐虞暇日饒耕鑿，秦漢當年浪戰争。", "風月倚欄如可借，待攜斗酒話昇平。"]'),
('bfbd962d-431d-4ffd-9a34-50ff70fd76e7','次韻題西林廓然亭','釋德洪','宋','宋诗','song-poetry','','[]','堂堂葉脱露遥天，自炷臨軒一穗煙。',64,'全唐诗/poet.song.76000.json','["堂堂葉脱露遥天，自炷臨軒一穗煙。", "貴客獨遊聊爾耳，道人相見亦欣然。", "是身已悟浮漚久，萬象中觀寶鏡圓。", "寄語横機莫相試，刻舟甘作小乘禪。"]'),
('188ae1da-7f7b-4a70-aabf-891cd8a25f90','次韻題方廣靈源洞','釋德洪','宋','宋诗','song-poetry','','[]','萬峰剔卓起孤峰，慚愧靈源與世通。',64,'全唐诗/poet.song.76000.json','["萬峰剔卓起孤峰，慚愧靈源與世通。", "花異空懷上林苑，夢清疑宿廣寒宫。", "泄雲吐雨遮金地，濺雪跳珠落石□。", "忙裏爲君成妙語，豐碑正欲就崖礱。"]'),
('5eb1af6e-8d0d-4d95-b1f1-86313dab7969','次韻題高臺','釋德洪','宋','宋诗','song-poetry','','[]','午梵知藏釋梵宫，危臺遥喜石橋通。',64,'全唐诗/poet.song.76000.json','["午梵知藏釋梵宫，危臺遥喜石橋通。", "下無俗駕攀緣至，中有高人笑語同。", "解執易爲摩詰語，經行難續德雲風。", "千巖萬壑吹松雨，替說儂家勝義空。"]'),
('7316caac-32bf-461d-b2c5-115be90cd308','次韻題上封','釋德洪','宋','宋诗','song-poetry','','[]','天柱唯連紫蓋峰，路危不與衆峰通。',64,'全唐诗/poet.song.76000.json','["天柱唯連紫蓋峰，路危不與衆峰通。", "瓢沽狭徑疑相值，芋火何人想此風。", "借榻醉魂窺凍螘，憑欄詩眼送飛鴻。", "空嗟千偈出山去，半摺遺編看未終。"]'),
('fca8d9ef-9e6e-4bc4-af73-e52623e78890','次韻邵陵道中書懷','釋德洪','宋','宋诗','song-poetry','','[]','邵陵山水麗風光，游徧歸来夜話長。',64,'全唐诗/poet.song.76000.json','["邵陵山水麗風光，游徧歸来夜話長。", "秋翠等閑開雉堞，驚湍哀怨韻笙簧。", "随鞍此景憑詩寫，他日塵紛一笑忘。", "上閣與誰同小立，墜金拄笏說三湘。"]'),
('9528f177-2184-4ebf-9290-8f83892fe487','次韻雨中書懷','釋德洪','宋','宋诗','song-poetry','','[]','剩雨殘晴暴所長，客窗花氣噀餘香。',64,'全唐诗/poet.song.76000.json','["剩雨殘晴暴所長，客窗花氣噀餘香。", "每懷追逐雲泉慣，無計遮攔歲月忙。", "誰謂伐冰連戚里，年来盡室泛沅湘。", "詔書行看椎門至，已覺眉間一點黄。"]'),
('7900fe8f-c36e-4859-a0d1-d6e4e3d9fc2a','次韻題化鶴軒','釋德洪','宋','宋诗','song-poetry','','[]','當年舉網得雙舄，想見胎仙風度幽。',64,'全唐诗/poet.song.76000.json','["當年舉網得雙舄，想見胎仙風度幽。", "朱頂顧吾今未識，長身意子是其流。", "山家趣味無人共，王事經過作意游。", "千里帝城何日去，不妨佳處且遲留。"]'),
('c28428f5-1dee-4093-904a-63e3ba957526','次韻題澹山巖','釋德洪','宋','宋诗','song-poetry','','[]','華屋張燈展畫屏，當年纖手指巖扃。',64,'全唐诗/poet.song.76000.json','["華屋張燈展畫屏，當年纖手指巖扃。", "宦游那料重湖隔，醉裏空驚疊嶂青。", "繡口詞章人復見，筆華聲價夢通靈。", "詩成獨立西風晚，滿眼歸心插羽翎。"]'),
('5d44d7e6-a3aa-4d75-97c7-4ebc17bad123','次韻遊浯谿','釋德洪','宋','宋诗','song-poetry','','[]','浯谿山水今無恙，浪士曾爲爛熳游。',64,'全唐诗/poet.song.76000.json','["浯谿山水今無恙，浪士曾爲爛熳游。", "大字中興餘斷碣，小舟空此醉垂鈎。", "詞源不減無雙譽，人品當時第一流。", "地坐摩挲增歎息，高標想見尚横秋。"]'),
('fd27cfd4-0a74-4db5-b381-d7a99e43bd01','次韻題南明山凌雲閣','釋德洪','宋','宋诗','song-poetry','','[]','獨上凌雲百尺樓，欄干一曲一遲留。',64,'全唐诗/poet.song.76000.json','["獨上凌雲百尺樓，欄干一曲一遲留。", "丁丁樵斧空山裏，泛泛漁舟古渡頭。", "蔽日綠陰鳴好鳥，際天芳草牧青牛。", "回頭城市分塵土，堪笑王孫取次游。"]'),
('19621509-9456-4095-8212-6dfe08cdd0c0','次韻言懷','釋德洪','宋','宋诗','song-poetry','','[]','此身已覺此生浮，去作雲山老比丘。',64,'全唐诗/poet.song.76000.json','["此身已覺此生浮，去作雲山老比丘。", "古寺閑門人莫問，寒綃蒙首涕慵收。", "道林風月心能了，子美工夫志未酬。", "爲問太原王處士，一甌春露可同不。"]'),
('1f8bd0b0-d1f6-482b-b630-bc35d312f60b','次韻宿聖谿莊','釋德洪','宋','宋诗','song-poetry','','[]','家聲十輩擁朱輪，更畜青牛解鬭犇。',64,'全唐诗/poet.song.76000.json','["家聲十輩擁朱輪，更畜青牛解鬭犇。", "應念高樓閑舞袖，故憑山月洗吟魂。", "助舂泉落量雲谷，輸税人歸吠甑村。", "被冷夜晴成好夢，馬随香霧入修門。"]'),
('058d1ee8-6076-4b2e-9495-060e633a0520','次韻拉空印游芙蓉','釋德洪','宋','宋诗','song-poetry','','[]','翰墨平生氣吐霓，詩成先喜示筠谿。',64,'全唐诗/poet.song.76000.json','["翰墨平生氣吐霓，詩成先喜示筠谿。", "山中見客應偏好，筆力知公不肯低。", "夜寂據梧饑鼠出，巖空同聽怪禽啼。", "上方聞說非人世，更陟緣雲第幾梯。"]'),
('e1d31b46-812f-4131-a3e4-f2c961fcb716','次韻縱目亭','釋德洪','宋','宋诗','song-poetry','','[]','高情與客憑欄處，便覺身藏語笑中。',64,'全唐诗/poet.song.76000.json','["高情與客憑欄處，便覺身藏語笑中。", "已許此生當樂死，不辭老去坐詩窮。", "遙知兵衛戎衣盛，只欠花輪小袖紅。", "絕境天藏今日獻，千峰登睫豈人工。"]'),
('721228a9-7a63-424c-a82e-0a12ccaf48b8','次韻游鹿頭山','釋德洪','宋','宋诗','song-poetry','','[]','吐詞秀似出盆絲，好古幽情八詠思。',64,'全唐诗/poet.song.76000.json','["吐詞秀似出盆絲，好古幽情八詠思。", "論字来尋魯公碣，因詩曾訪少陵祠。", "留題楚俗争傳去，懶賦山靈必有詞。", "定價文章比珠玉，此篇不獨慰吾私。"]'),
('11b2989c-bb69-4b89-a5dc-f4145c0f6eae','次韻題清風亭','釋德洪','宋','宋诗','song-poetry','','[]','特築飛臺丈室傍，便驚形勝發天藏。',64,'全唐诗/poet.song.76000.json','["特築飛臺丈室傍，便驚形勝發天藏。", "登臨時作一聲嘯，已覺翛然兩袖凉。", "待月拭除昏霧色，看雲入得野花香。", "君看抖擻鈴幡意，欲替禪翁爲舉揚。"]'),
('cd3c0c27-1030-4a90-92b1-8ac57cfad905','次韻法林禪寺','釋德洪','宋','宋诗','song-poetry','','[]','聞道高人願力深，幽居端與法爲林。',64,'全唐诗/poet.song.76000.json','["聞道高人願力深，幽居端與法爲林。", "風泉松雨随宜說，密室晴軒共一音。", "意妙故應人不薦，地偏還喜我相尋。", "夜闌更入詩三昧，消盡平生未死心。"]'),
('0d64687c-8dcc-445b-9c23-fb3539b02a1f','次韻憑欄有作','釋德洪','宋','宋诗','song-poetry','','[]','金殿誰焚南海香，靄然芬馥撲回廊。',64,'全唐诗/poet.song.76000.json','["金殿誰焚南海香，靄然芬馥撲回廊。", "數枝銀燭高低照，兩箇清螢上下光。", "風度素秋驚宿鳥，水舂碧澗濯游舫。", "欄干獨倚無人問，細細孤吟月滿堂。"]'),
('e7c85a06-14de-4829-a766-6daca8bb3e78','次韻渡江有作','釋德洪','宋','宋诗','song-poetry','','[]','棄舟植杖首重回，隔岸遥聞津鼓催。',64,'全唐诗/poet.song.76000.json','["棄舟植杖首重回，隔岸遥聞津鼓催。", "淮上梅傳春信至，江南山逐笑聲来。", "行瞻瑞霧籠雙闕，更看神光發五臺。", "王事幸陪方外樂，爲君點筆走風雷。"]'),
('e0f0452d-766b-4e0d-8861-c1d59bc816c2','題善化陳令蘭室','釋德洪','宋','宋诗','song-poetry','','[]','種性難教草掩藏，蒼然小室爲誰芳。',64,'全唐诗/poet.song.76000.json','["種性難教草掩藏，蒼然小室爲誰芳。", "槲培几案軒窗碧，坐款賓朋笑語香。", "糝地露英猶潔白，快人風度更纖長。", "議郎嗜好清無滓，獨有幽蘭可比方。"]'),
('4dd51041-6008-45f5-9769-640ca04358f2','快亭','釋德洪','宋','宋诗','song-poetry','','[]','太丘作邑付絃歌，剩得清閑可奈何。',64,'全唐诗/poet.song.76000.json','["太丘作邑付絃歌，剩得清閑可奈何。", "滿地棠陰驚晝永，小亭詩眼覺天多。", "佳眠夏簟便光滑，醉耳松風喜再過。", "想見句成書棐几，侍兒濃笑出微渦。"]'),
('30a2d506-e156-4995-84d8-3a41f9f1dc92','次韻郤子中學句游嶽山攜怪石歸','釋德洪','宋','宋诗','song-poetry','','[]','衡嶽乘春著意游，詩詞不獨錦囊收。',64,'全唐诗/poet.song.76000.json','["衡嶽乘春著意游，詩詞不獨錦囊收。", "又攜峰頂雲房石，歸致閑齋夏簟秋。", "塵下笑談且同夢，胸中涇渭自分流。", "忽驚几案寒層出，卧看令人憶故丘。"]'),
('03104185-1539-4fc0-bd42-7c9580a0cb3e','和周達道運句題怪石韻','釋德洪','宋','宋诗','song-poetry','','[]','愛山心志如君少，王事何妨陟翠微。',64,'全唐诗/poet.song.76000.json','["愛山心志如君少，王事何妨陟翠微。", "怪石方欣典刑在，新詩仍寫畫圖歸。", "客来一室煙光滿，掌上千巖眼力稀。", "頗怪周郎賞音者，獨於此境尚彈機。"]'),
('c89db9c6-4ad6-4f6e-9009-abaed88a3493','次韻見寄喜雨','釋德洪','宋','宋诗','song-poetry','','[]','議郎詩膽久崔嵬，敏句無煩急雨催。',64,'全唐诗/poet.song.76000.json','["議郎詩膽久崔嵬，敏句無煩急雨催。", "玉局波瀾嗟已絕，少陵風力賴追回。", "蕩晴香霧吹紅藕，迥地花茵疊紫苔。", "静極凉生聞剝啄，渡湘知有道人来。"]'),
('31b73676-01c2-4a0e-ac86-b0d6be3c7504','次韻題方圓菴','釋德洪','宋','宋诗','song-poetry','','[]','比物曾聞知姓名，樹間斛懸林百升。',64,'全唐诗/poet.song.76000.json','["比物曾聞知姓名，樹間斛懸林百升。", "此菴外圓似盂覆，其地中方如鏡平。", "善不近名真有道，高非絕俗更幽情。", "會當目擊維摩老，端作毗耶問法行。"]'),
('0db17ab0-f397-4950-8291-68352ca422e0','贈許彦周宣教游嶽彦周參機道者','釋德洪','宋','宋诗','song-poetry','','[]','一幅紗巾九節筇，翛然生計似龐公。',64,'全唐诗/poet.song.76000.json','["一幅紗巾九節筇，翛然生計似龐公。", "孤雲野鶴登空去，萬壑千巖墮笑中。", "岣嶁晴披應獨往，懶瓉醉卧與誰同。", "遙知勘破癡禪老，想見臨機面發紅。"]'),
('e1004de0-427f-46b4-9d6f-95c24dc74a98','次韻游南嶽','釋德洪','宋','宋诗','song-poetry','','["\u8861\u5c71"]','天迥游絲百尺輕，水寒時覺縠紋生。',64,'全唐诗/poet.song.76000.json','["天迥游絲百尺輕，水寒時覺縠紋生。", "琢磨佳句輸吾弟，文點春眠付老兄。", "山寺獨来無一事，竹軒相對有餘清。", "永懷東院成千古，寂子難忘叔姪情。"]'),
('e08ab69d-0f7a-4a9b-b033-ee9706fffc7e','次韻彦周見寄二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','詩先春色附湘船，来與幽人結浄緣。',64,'全唐诗/poet.song.76000.json','["詩先春色附湘船，来與幽人結浄緣。", "句好空驚碧雲合，韻高疑在白鷗前。", "君應歸誦陶彭澤，我亦南尋率子廉。", "想見江頭同握手，採茶時節雨餘天。"]'),
('1dd01a6c-7abe-48ed-a6e6-5cdc78cf6891','次韻彦周見寄二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','歸思啼禽日夜催，寶書臨罷意徘徊。',64,'全唐诗/poet.song.76000.json','["歸思啼禽日夜催，寶書臨罷意徘徊。", "榆錢滿地買春去，嶽色渡江排闥来。", "行樂風光清夢曉，卧披煙雨曲屏開。", "興来敏速詩千首，落筆人驚挟怒雷。"]'),
('4c04812e-78f4-4bb0-a733-b4e12dcad073','彦周借書','釋德洪','宋','宋诗','song-poetry','','[]','湘上清山爽氣浮，開軒相對亦風流。',64,'全唐诗/poet.song.76000.json','["湘上清山爽氣浮，開軒相對亦風流。", "但工酣寢成疏懶，甚拙謀生太謬悠。", "數筆江村供晚望，一蓑煙雨助詩愁。", "借書知子能醫國，有志常先天下憂。"]'),
('2704546d-96f3-4dec-9205-486c70ba5cba','彦周法地弟作出家菴又自爲銘作此寄之','釋德洪','宋','宋诗','song-poetry','','[]','迂闊菴成又自誇，要令妙語發天葩。',64,'全唐诗/poet.song.76000.json','["迂闊菴成又自誇，要令妙語發天葩。", "未容臨濟終仆地，正賴雲門已出家。", "少日浪曾參泐水，暮年端合在丹霞。", "贈君革屣游山去，勘破諸方一笑譁。"]'),
('84148b7e-8d75-449d-bdfd-ec9ea6e836d8','二月大雨江漲晚晴作三首  其一','釋德洪','宋','宋诗','song-poetry','','[]','春寒作意攪吟魂，欲出雲濤已濺門。',64,'全唐诗/poet.song.76000.json','["春寒作意攪吟魂，欲出雲濤已濺門。", "入畫瀟湘連雉堞，落梅煙雨暗江村。", "依蒲覓句壯心在，附火抄書老眼昏。", "一掬幽懷收拾得，謾題窗紙與誰論。"]'),
('fcd4689d-d10a-49fb-a9c1-6782abe4ef20','二月大雨江漲晚晴作三首  其二','釋德洪','宋','宋诗','song-poetry','','[]','我在湘西畫牒中，時高時作送飛鴻。',64,'全唐诗/poet.song.76000.json','["我在湘西畫牒中，時高時作送飛鴻。", "事治山翠經旬雨，印可春晴盡日風。", "引步幽探聊自適，滿懷疏快與誰同。", "東君傾寫無餘藴，都放山茶稱意紅。"]'),
('f7381ece-4894-4767-9cc9-61b332dcb152','二月大雨江漲晚晴作三首  其三','釋德洪','宋','宋诗','song-poetry','','[]','投老歸来椘水濱，水清聊可濯衣塵。',64,'全唐诗/poet.song.76000.json','["投老歸来椘水濱，水清聊可濯衣塵。", "拚心樂事都還汝，入手清閑不與人。", "尚有笑談消白晝，更無情緒管青春。", "暗驚少日王城外，走馬争先看寶津。"]'),
('e5f82297-a9e2-43b5-adc8-137ab1041aad','陳大夫見和春日三首用韻酬之  其一','釋德洪','宋','宋诗','song-poetry','','[]','詠君好句欲消魂，想見朱轓畫戟門。',64,'全唐诗/poet.song.76000.json','["詠君好句欲消魂，想見朱轓畫戟門。", "解組正當强健日，載書歸老水雲村。", "虚堂風撼牙籖響，密室嵐蒸畫牒昏。", "偶在湘山最佳處，舊遊閑與野僧論。"]'),
('d5e2f716-42fc-48b3-9b5b-9bacaec42fc5','陳大夫見和春日三首用韻酬之  其二','釋德洪','宋','宋诗','song-poetry','','[]','無復捜詩慘淡中，便能落筆敏驚鴻。',64,'全唐诗/poet.song.76000.json','["無復捜詩慘淡中，便能落筆敏驚鴻。", "高情不在兩疏後，句法追回二謝風。", "傾蓋未論桑梓舊，忘年先喜唱酬同。", "朱顔長覺清光溢，不學東坡是醉紅。"]'),
('d3c4170f-414b-4e61-956f-35bb3c6ff810','陳大夫見和春日三首用韻酬之  其三','釋德洪','宋','宋诗','song-poetry','','[]','詩軸来尋寂寞濱，把看字字蜕埃塵。',64,'全唐诗/poet.song.76000.json','["詩軸来尋寂寞濱，把看字字蜕埃塵。", "江南家世休相問，陳氏文章不乏人。", "嶽色渡江長自好，桃花滿縣不勝春。", "克家有子如麟鳳，骨相吾驚是要津。"]'),
('1cdabcba-3602-4111-b43d-aba3bb595f87','過溈山陪空印禪師夜話','釋德洪','宋','宋诗','song-poetry','','[]','濃翠濕衣三十里，渡谿知背幾重雲。',64,'全唐诗/poet.song.76000.json','["濃翠濕衣三十里，渡谿知背幾重雲。", "忽驚寶構從空墮，便覺風光與世分。", "夜久天香凝錯莫，庭閑花雨自繽紛。", "他生曾伴安禪地，此夕樓鐘復共聞。"]'),
('09895de6-fdbe-479f-a3c8-a8fdcab3576d','空印以新茶見餉','釋德洪','宋','宋诗','song-poetry','','[]','喊山鹿蓛社前摘，出焙新香麥粒光。',64,'全唐诗/poet.song.76000.json','["喊山鹿蓛社前摘，出焙新香麥粒光。", "撼樹師應懷大仰，傳甌我欲學南陽。", "要看雪乳急停筅，旋碾玉塵深住湯。", "今日城中雖獨試，明年林下定分嘗。"]'),
('caabe126-9da5-4d5a-a3b8-5f963db969ea','空印見招住菴時未能往作此寄之','釋德洪','宋','宋诗','song-poetry','','[]','獨立天衣四世孫，作家手段典刑存。',64,'全唐诗/poet.song.76000.json','["獨立天衣四世孫，作家手段典刑存。", "大溈路峻諸方讓，空印風高四海聞。", "有願欲依龍象衆，無求羞逐鶩雞群。", "此生一聚灰中骨，終葬千峰頂上雲。"]'),
('293011fa-0af1-4c9d-878f-3271883a2eee','空印見和用韻答之','釋德洪','宋','宋诗','song-poetry','','[]','棋布諸方盡子孫，道緣渾似雪峰存。',64,'全唐诗/poet.song.76000.json','["棋布諸方盡子孫，道緣渾似雪峰存。", "全提蓋色騎聲句，直要臨機以眼聞。", "圍繞千僧名冠世，指揮萬象語驚群。", "獨能收此無家客，分占溈源一塢雲。"]'),
('dff0ba54-583f-4c1c-9cfc-7e24e0082aac','龍興禪師大陽的孫居枯木堂新植楚竹余愛其家風爲賦之','釋德洪','宋','宋诗','song-poetry','','[]','門外追犇沒馬塵，堂中安頓自由身。',64,'全唐诗/poet.song.76000.json','["門外追犇沒馬塵，堂中安頓自由身。", "脩筠有淚知誰恨，枯木開花爲我春。", "隔岸雲山猶可借，滿懷風月未全貧。", "小詩勿笑清如畫，聊爲高人戲寫真。"]'),
('6e46df22-ad18-4c23-8fc4-b34e1d491569','題德明都護熏堂','釋德洪','宋','宋诗','song-poetry','','[]','占叢濃碧繞虚堂，堂上仙郎戲比芳。',64,'全唐诗/poet.song.76000.json','["占叢濃碧繞虚堂，堂上仙郎戲比芳。", "香並蕙蘭終漏泄，色同草木浪遮藏。", "過墻山潑軒窗翠，吹鬂風生燕寢凉。", "敏豆才高家法在，要看落筆擁紅粧。"]'),
('dff1f31d-c261-4fde-8bab-329dd9655c1b','題季長冰壺軒','釋德洪','宋','宋诗','song-poetry','','[]','閑軒清似冰壺水，軒上人如元紫芝。',64,'全唐诗/poet.song.76000.json','["閑軒清似冰壺水，軒上人如元紫芝。", "坐覺秋光潄毛髪，客来春色滿談詞。", "寶書讀罷依蒲久，玉麈經行曳履遲。", "卷挂一聲林葉動，黄昏月出雪消時。"]'),
('5b44901d-c3f9-4dd6-99a1-1ed3cd9050a4','明應仲出季長近詩二首次韻寄之  其一','釋德洪','宋','宋诗','song-poetry','','[]','露葉朝陽沃棗桑，暑風吹鬢蕩蓮香。',64,'全唐诗/poet.song.76000.json','["露葉朝陽沃棗桑，暑風吹鬢蕩蓮香。", "已欣點水蜻蜓款，更覺營巢燕子忙。", "翠浪舞翻争漲壟，黄雲割盡想登場。", "小樓楯瓦誰庭院，弱柳多情故掩藏。"]'),
('0fa926cb-62dd-4c43-b9c1-9ffa3d7f6f88','明應仲出季長近詩二首次韻寄之  其二','釋德洪','宋','宋诗','song-poetry','','[]','偶尋鄰叟問桑麻，踏盡山礬糝徑花。',64,'全唐诗/poet.song.76000.json','["偶尋鄰叟問桑麻，踏盡山礬糝徑花。", "傳得新辭春爛熳，更驚行草醉欹斜。", "遙知小縣少公事，想見高情照物華。", "尚念無家甘露滅，一蓑煙雨似玄沙。"]'),
('cc76f993-e189-4e38-89a3-6b9507c42a4f','和傅彦濟知縣','釋德洪','宋','宋诗','song-poetry','','[]','句法疑君每太高，湘南山水助揮毫。',64,'全唐诗/poet.song.76000.json','["句法疑君每太高，湘南山水助揮毫。", "暫臨小邑聊觀政，未見全牛可受刀。", "珠玉光難藏瓦礫，芝蘭香豈掩蓬蒿。", "坐令百里清如鏡，吏猾民姦豈易逃。"]'),
('96f33927-ec1f-4aa6-bf09-1d79bce1875b','寄題劉居士環翠菴','釋德洪','宋','宋诗','song-poetry','','[]','平生不識劉居士，想見茅菴枯瘁姿。',64,'全唐诗/poet.song.76000.json','["平生不識劉居士，想見茅菴枯瘁姿。", "百八珠輪紅瑪瑙，萬千峰遶碧瑠璃。", "笑人經卷鑽故紙，彼世金珠似笊籬。", "折脚鐺中誰共過，小龐真是出家兒。"]'),
('f75d4335-8fd2-4dae-95ec-b52ba6e31b9c','次韻思禹兄見懷','釋德洪','宋','宋诗','song-poetry','','[]','刺桐花映野薔薇，湘水侵門過客稀。',64,'全唐诗/poet.song.76000.json','["刺桐花映野薔薇，湘水侵門過客稀。", "此日音書經歲隔，何時麈尾對君揮。", "樓高三楚天空闊，夜久千巖月正暉。", "我託叢林如越鳥，南枝雖穩亦思歸。"]'),
('9e062477-918d-4601-adae-8f8ff3cae88a','次韻思禹題方竹','釋德洪','宋','宋诗','song-poetry','','[]','不改平生歲寒操，近来随世解方圓。',64,'全唐诗/poet.song.76000.json','["不改平生歲寒操，近来随世解方圓。", "知君出異驚群聽，顯我尋常是一偏。", "但見蒼官遭寵錫，那知青士亦超遷。", "水花院落春風晚，庭種連蕉怪石前。"]'),
('30ed76ef-c67b-4d22-b253-5df258910299','蜀道人明禪過余甚勤久而出東山高弟兩勤送行語句戲作此塞其見即之意','釋德洪','宋','宋诗','song-poetry','','[]','衆中聞語識巴音，京洛沅湘久訪尋。',64,'全唐诗/poet.song.76000.json','["衆中聞語識巴音，京洛沅湘久訪尋。", "張口茹拳君聚落，垂膺拭涕我山林。", "碧巖花墮鳥飛去，蒲坐葉飄針正紝。", "袖裏兩勤太饒舌，丈夫聲價老婆心。"]'),
('5f6a91cf-980f-490b-b69e-72c537ecd530','送珠上人重修五宗語要','釋德洪','宋','宋诗','song-poetry','','[]','五宗抄語挟風雷，佛日將傾賴取回。',64,'全唐诗/poet.song.76000.json','["五宗抄語挟風雷，佛日將傾賴取回。", "薝蔔花香已零落，旃檀塔坐更塵埃。", "鈍根厭看摩挲去，妙手端能拂拭開。", "當有異人来荷法，叢林因子見奇瑰。"]'),
('ee3bda66-ef2a-4814-9155-a8d0502ed013','光上人送墨梅来求詩還鄉','釋德洪','宋','宋诗','song-poetry','','["\u8861\u5c71"]','南嶽有雲留不住，東歸結伴過湘湄。',64,'全唐诗/poet.song.76000.json','["南嶽有雲留不住，東歸結伴過湘湄。", "解將疏影横斜句，不換垂珠的皪詩。", "癯甚鳶肩寒入畫，清哉鶴骨老難醫。", "定知入嶺風煙暮，正及追胥餽歲時。"]'),
('3d1d7a52-935e-48e7-8d98-90ed3f8d868d','送瓊大師歸禪寂','釋德洪','宋','宋诗','song-poetry','','[]','近聞禪寂似叢林，縂衆能爲世所欽。',64,'全唐诗/poet.song.76000.json','["近聞禪寂似叢林，縂衆能爲世所欽。", "百巧難磨真實行，兩塗不改歲寒心。", "衣今椹色如栗色，語未吴音變楚音。", "盛夏入城緣厎事，扁舟湘水獨相尋。"]'),
('2e8681de-d316-4d22-be7a-f3e735c6bee3','贈道法師','釋德洪','宋','宋诗','song-poetry','','[]','道公膽大過身軀，敢逆龍鱗上諫書。',64,'全唐诗/poet.song.76000.json','["道公膽大過身軀，敢逆龍鱗上諫書。", "獨欲袒肩擔佛法，故甘引頸受誅鉏。", "三年竄逐心無愧，萬里歸来貌不枯。", "他日教門綱紀者，近聞靴笏趁朝趨。"]'),
('a5972255-d8a2-4700-b872-457d408f58fe','谷山沙彌求詩','釋德洪','宋','宋诗','song-poetry','','[]','十里松風長不老，一庭秋色爲誰閑。',64,'全唐诗/poet.song.76000.json','["十里松風長不老，一庭秋色爲誰閑。", "偶逢此日休新夏，偏見耆年憶故山。", "貧裏有秋同舉箸，法中添口共開顔。", "偶然弄筆成詩句，乘興留題屋壁間。"]'),
('2a9d0dab-603b-4044-9507-774feb907522','贈羅道人','釋德洪','宋','宋诗','song-poetry','','[]','蜕塵標韻矯翔鸞，鬢髪樓颼風露寒。',64,'全唐诗/poet.song.76000.json','["蜕塵標韻矯翔鸞，鬢髪樓颼風露寒。", "脱舄骨飛何日見，解衣沐浴萬人看。", "肯来從我翛然住，皆說他人屈致難。", "戲作猫聲行聚落，自忘身是晉郎官。"]'),
('19b0bfac-93f7-4037-a6e3-9009838030ee','次韻張司錄見寄','釋德洪','宋','宋诗','song-poetry','','[]','不曾識面已傾倒，便覺胸中涇渭分。',64,'全唐诗/poet.song.76000.json','["不曾識面已傾倒，便覺胸中涇渭分。", "句精不減李長吉，才高大類沈休文。", "看山詩眼湛如水，拄笏爽氣高摩雲。", "他年竹屋夜連榻，妙語懸知過所聞。"]'),
('f850a873-34d6-46c2-a638-37f91f33b6da','郭伯成榮登','釋德洪','宋','宋诗','song-poetry','','[]','快馬東風走帝京，歸来門巷綠陰成。',64,'全唐诗/poet.song.76000.json','["快馬東風走帝京，歸来門巷綠陰成。", "頃知一第文章貴，能致三公衮冕榮。", "子涉風波方箠探，我閑几硯覺塵生。", "贈詩誰似王摩詰，翰墨場中獨策名。"]'),
('eb82d3d6-aa7a-4440-855f-e7124a562144','題天王圓證大師房壁','釋德洪','宋','宋诗','song-poetry','','[]','閉戶不妨依聚落，開軒随分有山林。',64,'全唐诗/poet.song.76000.json','["閉戶不妨依聚落，開軒随分有山林。", "殘經半掩世情斷，好鳥一聲村意深。", "籬外霜筠森束玉，屋頭露橘欲垂金。", "能營野飯羮紅醬，渡水何辭數訪尋。"]'),
('7e2c625d-3c76-4d99-9b11-39d71e135e54','寄題達軒','釋德洪','宋','宋诗','song-poetry','','[]','羊腸世路替人愁，袖手歸来事事休。',64,'全唐诗/poet.song.76000.json','["羊腸世路替人愁，袖手歸来事事休。", "只有信緣唯得計，不過随分復何求。", "數聲屬玉滄浪晚，一塢黄雲𥝧稏秋。", "寄語封侯塞垣外，何如高卧小軒幽。"]'),
('8099f681-5aeb-42ce-97b7-af4475211ac0','題雲巖筠軒','釋德洪','宋','宋诗','song-poetry','','[]','雨葉風枝小徑通，拂砧清坐有誰同。',64,'全唐诗/poet.song.76000.json','["雨葉風枝小徑通，拂砧清坐有誰同。", "粉衣香滑秋叢瘦，泉珮丁東夜壑空。", "半世已歸彈指內，前途都付枕肱中。", "隄防老境猶多事，折脚鐺炊腐顆紅。"]'),
('20045db9-98b1-49d0-8f74-134c14517187','逍遥遊山歸見示唱和詩軸口占和之','釋德洪','宋','宋诗','song-poetry','','[]','游遍名山過水西，夜談奇語盡横機。',64,'全唐诗/poet.song.76000.json','["游遍名山過水西，夜談奇語盡横機。", "君如檻鹿猶思奮，我似棲禽已倦飛。", "聞道老禪能眷舊，更煩諸衲借餘輝。", "欲知勝踐多佳思，懷得新詩滿袖歸。"]'),
('4d60c181-e66f-4666-85d9-d2a0683f472f','送誼叟歸北山','釋德洪','宋','宋诗','song-poetry','','[]','南臺山淺北山深，深處開軒更茂林。',64,'全唐诗/poet.song.76000.json','["南臺山淺北山深，深處開軒更茂林。", "作夏懸知成契闊，扁舟乘興一相尋。", "燈青竹屋風雨夕，谿遶石門鄉井心。", "投老都忘身是客，坐中談笑盡吴音。"]'),
('298903aa-ddd0-4a5d-bcbe-1b034a0111b1','偶書寂音堂壁三首  其一','釋德洪','宋','宋诗','song-poetry','','[]','巾瓶挂壁亦翛然，無所營爲地自偏。',64,'全唐诗/poet.song.76000.json','["巾瓶挂壁亦翛然，無所營爲地自偏。", "句法不能醫老病，夢游時解到林泉。", "扶持瘦玉筇随步，堆疊荒雲衲半肩。", "小住閒庭數歸鳥，從教人作畫圖傳。"]'),
('51a0f2db-d5e5-4d30-bb83-bd84c100d23f','偶書寂音堂壁三首  其二','釋德洪','宋','宋诗','song-poetry','','[]','寂音閒殺益風流，寒涕垂膺懶更收。',64,'全唐诗/poet.song.76000.json','["寂音閒殺益風流，寒涕垂膺懶更收。", "得失是非都放却，死生窮達信緣休。", "湘中戲劇三千首，海上歸来十二秋。", "齋罷展單吾自課，暮年眠食更何求。"]'),
('4e74f60a-3ecd-442c-a1b3-73fdc4727a23','偶書寂音堂壁三首  其三','釋德洪','宋','宋诗','song-poetry','','[]','霜須瘴面老垂垂，瘦搭詩肩古佛依。',64,'全唐诗/poet.song.76000.json','["霜須瘴面老垂垂，瘦搭詩肩古佛依。", "滅跡尚嫌身是累，此生永與世相違。", "殘經倦讀閑憑几，幽鳥獨聞常掩扉。", "寢處法華安樂行，蕩除五十二年非。"]'),
('a64fe730-c406-479a-945f-9a2a6444f592','元正一日示阿慈','釋德洪','宋','宋诗','song-poetry','','[]','季真少儼三十歲，儼入新年五十三。',64,'全唐诗/poet.song.76000.json','["季真少儼三十歲，儼入新年五十三。", "疑我滿懷揣佛法，解腰抖擻破裙衫。", "大瞻終老同香火，小朗平生共石巖。", "深炷罏香待清旦，偶聞殘雪落高杉。"]'),
('343bca2d-763f-4106-afe6-0c6071e7026c','上元夜病起欲寫法華安樂行品無力呼阿慈爲錄作此','釋德洪','宋','宋诗','song-poetry','','[]','重城車馬氣成霧，隔水巖叢冷欲冰。',64,'全唐诗/poet.song.76000.json','["重城車馬氣成霧，隔水巖叢冷欲冰。", "昨夜窺窗先有月，今宵對語偶無僧。", "臘高鶴骨柴崖露，病起霜鬚逐旋增。", "欲寫寶書驚力乏，阿慈能爲掃寒藤。"]'),
('15acfa35-4278-4c5b-8bf3-bfc8ef7fba50','上元後候季長不至作此寄之','釋德洪','宋','宋诗','song-poetry','','[]','和風凍雨上元後，斷岸橘洲春水生。',64,'全唐诗/poet.song.76000.json','["和風凍雨上元後，斷岸橘洲春水生。", "村寺獨歸江路熟，竹籬誰繫小舟横。", "偶成詩句長哦罷，謾折梅花一嗅清。", "想見連牀成夜語，此篇先慰遠来情。"]'),
('6fdbd1a7-c1da-4f49-887a-7c36fe666c25','夏日偶書','釋德洪','宋','宋诗','song-poetry','','[]','草樹扶疏夏簟清，夢驚鬭雀墮空庭。',64,'全唐诗/poet.song.76000.json','["草樹扶疏夏簟清，夢驚鬭雀墮空庭。", "過墻雌竹已數子，出屋耄蕉終百齡。", "雷後怒雲魚尾赤，林梢剩水鴨頭青。", "都無伎倆酬閑寂，謾搭伽梨自誦經。"]'),
('59855ea9-3ec4-4cea-9c78-07cac673db31','與忠子晚步登臺有作','釋德洪','宋','宋诗','song-poetry','','[]','僧殘寺僻游人少，草滿池塘筍過籬。',64,'全唐诗/poet.song.76000.json','["僧殘寺僻游人少，草滿池塘筍過籬。", "盧橘带酸春去後，榴花出葉雨晴時。", "一年事辦秧齊徧，連日江寒水退遲。", "偶上高臺成遠眺，兹游更得子追随。"]'),
('b8ebb36d-f75a-4608-a229-1e601a3ebb01','和人鴈字','釋德洪','宋','宋诗','song-poetry','','[]','劃然斜去和天曉，夜火相驚事已虛。',64,'全唐诗/poet.song.76000.json','["劃然斜去和天曉，夜火相驚事已虛。", "春信寫来無款識，東君胸次亦恢疏。", "最難讀似成文蠧，不亂行如水上魚。", "勿訝羲之筆神駿，換鵝瘞鶴是臨書。"]'),
('2dc692ee-d22b-4179-a43f-68e682712b55','大雪','釋德洪','宋','宋诗','song-poetry','','[]','今年未雪今日雪，地迥眼新人不囂。',64,'全唐诗/poet.song.76000.json','["今年未雪今日雪，地迥眼新人不囂。", "永巷掃除聞屐響，暮林翔集看鴉嬌。", "韻高雒下應難畫，興發山陰未覺遥。", "想見茅齋已摧壓，曲肱清夢到山椒。"]'),
('8a9d3989-acf0-4751-ad34-ffcbcd865396','宣和四年十二月二十四日大雪珠禪客忽至渠以谷山退院来審是否作此示之','釋德洪','宋','宋诗','song-poetry','','[]','翻空漸密呵不止，刷我當門螺髻峰。',64,'全唐诗/poet.song.76000.json','["翻空漸密呵不止，刷我當門螺髻峰。", "銀椀滿盛談類墮，徑松深覆示藏鋒。", "因徒逃去寧知褊，顯自何来不見蹤。", "獨擁衲衣成坐睡，地罏瓶泣伴疏慵。"]'),
('5ee58203-b7fa-4209-bb29-88cda7470190','題鹿苑虎岑堂','釋德洪','宋','宋诗','song-poetry','','[]','平生文彩照諸方，暗谷行藏草木光。',64,'全唐诗/poet.song.76000.json','["平生文彩照諸方，暗谷行藏草木光。", "要使叢林想高韻，故將名字挂虚堂。", "笑拈倚壁過頭杖，閑坐當年折脚牀。", "進步竿頭如不薦，草深門徑未相妨。"]'),
('02c5966f-90f6-4455-80db-0a4d2f23788f','次韻湖山居士見過','釋德洪','宋','宋诗','song-poetry','','[]','平昔雲岑在懷抱，而今懷抱在雲岑。',64,'全唐诗/poet.song.76000.json','["平昔雲岑在懷抱，而今懷抱在雲岑。", "聞泉偶爾成詩句，班草相看坐木陰。", "古鼎自然無俗韻，朱絃真是有遺音。", "羊欣不肯踏城市，背郭江村獨見尋。"]'),
('7ea42d1f-a2ae-445e-9426-64656c4529ac','題使園眄柯亭','釋德洪','宋','宋诗','song-poetry','','[]','吏散東園勝踐多，落花起舞鳥能歌。',64,'全唐诗/poet.song.76000.json','["吏散東園勝踐多，落花起舞鳥能歌。", "故應毛穎曾同泛，不獨龍文慣自磨。", "弄影風枝空掩冉，困人天氣近清和。", "倚欄欲去猶回首，奈此霄晴月色何。"]'),
('a51c0b9d-1a20-4b31-bc4e-33751b2511ce','題翠靄堂','釋德洪','宋','宋诗','song-poetry','','[]','虚簷碧瓦臨無地，吐月吞風六月寒。',64,'全唐诗/poet.song.76000.json','["虚簷碧瓦臨無地，吐月吞風六月寒。", "簾捲烟光揺户牖，雨餘嶽色墮闌干。", "侍兒自炷真龍腦，座客同分小鳳團。", "誰謂太平本無象，規模堪入畫圖看。"]'),
('5a09eac7-45f5-4e66-b121-45108046c262','迎爽樓','釋德洪','宋','宋诗','song-poetry','','[]','危樓華構倚青冥，卷盡晴嵐獨自登。',64,'全唐诗/poet.song.76000.json','["危樓華構倚青冥，卷盡晴嵐獨自登。", "去雁横斜紛點點，好峰青碧露層層。", "勝游與客同清賞，佳處題名在翠筠。", "憑檻不堪衰眼力，候船津渡見歸僧。"]'),
('934006b2-915a-4ebc-bf0d-e1834d92e8c4','送太淳長老住明教','釋德洪','宋','宋诗','song-poetry','','[]','三玄三要古難分，劈破從教剔突崙。',64,'全唐诗/poet.song.76000.json','["三玄三要古難分，劈破從教剔突崙。", "父母未生前一笑，言詮不到處重論。", "椎開臨濟百年意，推出汾陽六世孫。", "何用老婆更饒舌，暗中五色自成文。"]'),
('96b69fa6-69b1-4a28-8fec-8b35b9384ec8','送英長老住石谿','釋德洪','宋','宋诗','song-poetry','','[]','三玄三要沈埋久，正令重煩振此宗。',64,'全唐诗/poet.song.76000.json','["三玄三要沈埋久，正令重煩振此宗。", "陷虎機關須毒手，活人眼目貴藏鋒。", "真誠莫負叢林志，大願當追佛祖風。", "覆頂把茅休取相，同安曾著老黄龍。"]'),
('b384602e-5d14-4294-9fa7-edc99b715650','次韻李方叔水宿','釋德洪','宋','宋诗','song-poetry','','[]','高視世波增眼寒，公如砥柱捍驚湍。',64,'全唐诗/poet.song.76000.json','["高視世波增眼寒，公如砥柱捍驚湍。", "市中一虎成三口，醉裏扁舟過百灘。", "佳處每煩詩句寫，勝游宜作畫圖看。", "遙知二老相逢處，拾得風前一笑懽。"]'),
('789427ca-cec7-499e-80fe-a69b040fafe8','次韻曹彦清教授見寄','釋德洪','宋','宋诗','song-poetry','','[]','泮宫授道最馳名，想見經筵玉麈横。',64,'全唐诗/poet.song.76000.json','["泮宫授道最馳名，想見經筵玉麈横。", "學問有源堪景仰，行藏無地受譏評。", "門前江浪銀山攧，醉裏詩篇錦段明。", "遠宦不須嗟白眼，只今臺閣半書生。"]'),
('4c67cd55-ba0a-4698-aee3-aa22b6ddfe9b','胥啟道次韻見寄復和之','釋德洪','宋','宋诗','song-poetry','','[]','少年翰墨擅時名，老愛江鄉翠巘横。',64,'全唐诗/poet.song.76000.json','["少年翰墨擅時名，老愛江鄉翠巘横。", "聞道異書常自校，近来佳句與誰評。", "幽尋湘水映衣碧，小寢晴窗潑眼明。", "寄我三詩争妙麗，疑公曾夢筆花生。"]'),
('2f459959-b1ee-4a43-95bf-0cca07313910','寄黄龍来道者','釋德洪','宋','宋诗','song-poetry','','[]','問訊黄龍来道者，住山况味定何如。',64,'全唐诗/poet.song.76000.json','["問訊黄龍来道者，住山况味定何如。", "齒牢未怯和沙飯，眼倦應嫌夹注書。", "但見衣勝寒薜荔，不妨心賽白芙蕖。", "都疑生近楂田市，時覺淮南語未除。"]'),
('3f3f8f06-6839-4676-94ae-672ed0092157','禪首座自海公化去見故舊未嘗忘追想悼嘆之情季真游北游大梁聞其病憂得書輙喜爲人重鄉義久要不忘湘西時訪史資深亦或見尋此外閉門高卧耳宣和二年三月日風雨有懷其人戲書寄之','釋德洪','宋','宋诗','song-poetry','','[]','前時無際曾入夢，近日真游又得書。',64,'全唐诗/poet.song.76000.json','["前時無際曾入夢，近日真游又得書。", "一味歲寒甘淡薄，十分懽喜說鄉閭。", "閑尋老儼臺南寺，更過史髯湖上居。", "想見朝来閉深閤，卧聽簷雨滴階除。"]'),
('1cea8683-b020-4d8f-927f-994b7e348924','次韻閻資欽提舉東安道中','釋德洪','宋','宋诗','song-poetry','','[]','父老扶攜看使華，那知勳業在咨嗟。',64,'全唐诗/poet.song.76000.json','["父老扶攜看使華，那知勳業在咨嗟。", "人生安得顔長少，歲暮今驚日欲斜。", "謾有清詩敏風雨，空餘醉墨走龍蛇。", "應憐妙語如芝菌，不吐青林吐卧槎。"]'),
('3c845d64-48b8-42cb-a652-7d48c44d27ac','次韻遊福嚴寺','釋德洪','宋','宋诗','song-poetry','','[]','下臨煙雨憑危欄，游客新辭禁從班。',64,'全唐诗/poet.song.76000.json','["下臨煙雨憑危欄，游客新辭禁從班。", "露濕衣巾近雲漢，風吹笑語落人間。", "曾聞詩律如彭澤，想見風神似魯山。", "何日三人成品坐，夜窗參論到更闌。"]'),
('7bf4b252-f676-40b3-9282-bb8fbd83fb7e','次韻寧鄉道中','釋德洪','宋','宋诗','song-poetry','','[]','夹道傳呼部曲奔，遥知秋色動吟魂。',64,'全唐诗/poet.song.76000.json','["夹道傳呼部曲奔，遥知秋色動吟魂。", "黄柑綠橘平蕪路，剩水殘山夕照村。", "似鏡此心清自迥，如雲往事去無痕。", "鐘聲有寺藏煙翠，忽見林間窈窕門。"]'),
('51015d5e-0b12-4a66-95db-174096754197','次韻題雲峰齊雲閣','釋德洪','宋','宋诗','song-poetry','','[]','綠玉霜筇喜自提，芒鞵初試得攀躋。',64,'全唐诗/poet.song.76000.json','["綠玉霜筇喜自提，芒鞵初試得攀躋。", "欲窮深谷一區勝，更上齊雲百級梯。", "物外名山長好在，人間樂事自難齊。", "遙知太息出山去，一笑無人悟過谿。"]'),
('905ad971-c246-461c-82eb-ddada9cc5ef5','次韻題必照軒','釋德洪','宋','宋诗','song-poetry','','[]','曈曨曉日出蒼凉，草木欣欣露葉光。',64,'全唐诗/poet.song.76000.json','["曈曨曉日出蒼凉，草木欣欣露葉光。", "千里穠纖上眉睫，一區形勝發天藏。", "有詩摹寫江山美，無計遮攔歲月忙。", "韻險暗驚才力短，坐令毛穎秃鋒鋩。"]'),
('f7bc9dda-c9ba-4b67-80d6-3cf137073445','宿資欽楚山堂','釋德洪','宋','宋诗','song-poetry','','[]','故人持節在三湘，白首相逢話更長。',64,'全唐诗/poet.song.76000.json','["故人持節在三湘，白首相逢話更長。", "挂錫曾憐道林寺，携衾来宿楚山堂。", "意消忽覺風敲竹，夢斷空驚月轉廊。", "常恨出門無所詣，敢辭時此夜連牀。"]'),
('74f20115-9a3c-4ba2-bda0-9f74cce4a7e8','次韻資欽元府判見寄','釋德洪','宋','宋诗','song-poetry','','[]','茗盌閑窗不厭過，暮年歸計定如何。',64,'全唐诗/poet.song.76000.json','["茗盌閑窗不厭過，暮年歸計定如何。", "我思杖履游嵩少，公輩家山近洛河。", "具茨功名關意少，穎皋丘壑賦情多。", "二詩俱可鐫崖石，乞與雲煙相蕩摩。"]'),
('a391c45e-c9de-4476-9c58-01e0880af8a8','次韻王覺之裕之承務二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','問法能来渾聖凡，毗耶丈室未曾關。',64,'全唐诗/poet.song.76000.json','["問法能来渾聖凡，毗耶丈室未曾關。", "解分鉢飯如摩詰，欲散天花欠阿蠻。", "屬稿新詩追鮑謝，抗行醉墨似楊顔。", "遥知穿市聽歸馭，及我昏鴉落照間。"]'),
('3e7315f4-eeba-46dc-b5dc-3eb2d52b26de','次韻王覺之裕之承務二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','兄弟令人眼倍明，六經心醉幾時醒。',64,'全唐诗/poet.song.76000.json','["兄弟令人眼倍明，六經心醉幾時醒。", "韻高山嶽横南極，機妙鯤鵬化北溟。", "麗句重逢天下白，俊才今見海東青。", "數篇秀色凌千嶂，来慰摧頽病掩扃。"]'),
('c9b6cc92-d29f-47cd-b927-0637f4c43c2c','宣和五年四月十二日余館湘陰之興化徐質夫自土山来一昔夜語甚顛倒且日前嘗夢見東坡今復見子何清事相聯耶吾所居有亭名閑美嘗有白燕巢梁間屢見鶴翔舞於層霄嘱予爲詩紀其事質夫大梁人賢而有文佳公子也','釋德洪','宋','宋诗','song-poetry','','[]','徐侯官舍土山邊，頗爲看書廢晝眠。',64,'全唐诗/poet.song.76000.json','["徐侯官舍土山邊，頗爲看書廢晝眠。", "偶見畫梁巢雪乙，更驚雲漢舞胎僊。", "致坡入夢殊堪紀，與儼忘形亦自賢。", "聞道小亭時縦目，江山信美似斜川。"]'),
('f2912e9f-9a2c-4710-9eb8-abe58158d5f4','送丕上人歸黄蘗','釋德洪','宋','宋诗','song-poetry','','[]','萬身馬鬛轉龍腰，十里風聲捲海潮。',64,'全唐诗/poet.song.76000.json','["萬身馬鬛轉龍腰，十里風聲捲海潮。", "翠靄晴時飛畫棟，蒼崕斷處見朱橋。", "老驚鄉井心空在，說著巖叢意已消。", "慚愧東風知此恨，夜来吹夢到山椒。"]'),
('cb10b5d4-b27b-446b-a8ef-b821707b750d','同希先遊石鞏','釋德洪','宋','宋诗','song-poetry','','[]','良辰美景古難幷，且趁身閑稻雨晴。',64,'全唐诗/poet.song.76000.json','["良辰美景古難幷，且趁身閑稻雨晴。", "鳥語猿歌留我在，水聲山色益人清。", "得幽詩句聊題壁，遇好峰巒即住程。", "回首十年塵事裏，與君今日夢魂驚。"]'),
('2a6a369b-066b-4509-84a9-6912880b066d','題胥大夫欣欣堂','釋德洪','宋','宋诗','song-poetry','','[]','議郎粹和色無求，繞屋江山秀氣浮。',64,'全唐诗/poet.song.76000.json','["議郎粹和色無求，繞屋江山秀氣浮。", "弱柳嬌眠禽喚起，異花含笑草忘憂。", "閉門不放青春去，解榻長令佳客留。", "摹冩高情無好句，謾横詩眼付冥捜。"]'),
('ef9a89bd-66ce-4d2e-add9-6a83080f23fd','次韻嘉言機宜','釋德洪','宋','宋诗','song-poetry','','[]','幽尋野外興何如，蠶市村囂憶故墟。',64,'全唐诗/poet.song.76000.json','["幽尋野外興何如，蠶市村囂憶故墟。", "煮繭生涯春老大，餉田時節意蘇舒。", "吹開麥浪南風至，落盡花房小雨餘。", "暫借僧窗聊假寐，夢驚身世兩蘧蘧。"]'),
('95f208d7-b9dc-4167-8e56-e142b2a31804','玉池禪師以紙衾見遺作此謝之','釋德洪','宋','宋诗','song-poetry','','[]','紙衾来自玉峰前，旋坼封題一粲然。',64,'全唐诗/poet.song.76000.json','["紙衾来自玉峰前，旋坼封題一粲然。", "便覺室廬增道氣，不憂風雨攪閑眠。", "就牀堆疊明如雪，引手模蘇軟似綿。", "擁被並罏和夢暖，全勝白㲲紫茸氈。"]'),
('d0a7794c-3abc-4119-b055-f170f15ace99','立秋日偶書','釋德洪','宋','宋诗','song-poetry','','[]','秋入紗厨夏簟空，頽然瘦坐一衰翁。',64,'全唐诗/poet.song.76000.json','["秋入紗厨夏簟空，頽然瘦坐一衰翁。", "聲凉亂葉紅蕉雨，香暗分叢紫菊風。", "清境净緣慚獨享，幽懷佳句與誰同。", "平生垢習消磨盡，只有文章氣吐虹。"]'),
('b7427303-e713-473b-83b5-685b16d073da','游太平古寺讀舊題用惠上人韻','釋德洪','宋','宋诗','song-poetry','','[]','步盡長廊覺倦遊，叢蕉出屋小軒幽。',64,'全唐诗/poet.song.76000.json','["步盡長廊覺倦遊，叢蕉出屋小軒幽。", "壁間詩在紅埃滿，窗下香殘碧縷浮。", "喜有繩牀容我借，更因茗盌爲君留。", "忽驚林杪湘山露，誰作江天數筆秋。"]'),
('ebf5eb2b-a266-4222-92e6-7eb3691a9485','歲窮僧衆米竭自往湘陰乞之舟載夜歸宿橋口寒甚未寢時侍者智觀坐而假寐作此詩有懷資欽提舉','釋德洪','宋','宋诗','song-poetry','','[]','老去生涯無窖子，隔城荒寺到人稀。',64,'全唐诗/poet.song.76000.json','["老去生涯無窖子，隔城荒寺到人稀。", "歲窮百里扣門乞，夜棹孤舟載米歸。", "隅坐小僧寒附火，聯拳羸僕睡和衣。", "故人醉裏聞薌澤，應背銀缸照翠幃。"]'),
('06f24b22-c8c5-4de0-a059-e7a3dce7b991','正月一日送璿維那之新昌乞','釋德洪','宋','宋诗','song-poetry','','[]','春水初生湘岸邊，陰晴城郭上元前。',64,'全唐诗/poet.song.76000.json','["春水初生湘岸邊，陰晴城郭上元前。", "暖消積雪成簷滴，火烈殘香發篆煙。", "念舊十年鄉井夢，試新一首送行篇。", "翛然路入江南去，想見歸時及杜鵑。"]'),
('574ac3a9-21e3-495e-8951-49e3b53f149b','二月二十一日奉陪季長遊嶽麓飯罷登法華臺賦此','釋德洪','宋','宋诗','song-poetry','','[]','法華臺上憑欄久，吹鬢東風晚雨晴。',64,'全唐诗/poet.song.76000.json','["法華臺上憑欄久，吹鬢東風晚雨晴。", "斷岸平横千雉堞，道林遠在一牛鳴。", "喜餐水餅清明近，開徧山茶杜宇聲。", "想見京塵遮便面，應思攜手此中行。"]'),
('d02334cf-3400-49db-8ef9-c6d733942e1a','送興上人之歸宗','釋德洪','宋','宋诗','song-poetry','','[]','紫霄峰下鸞谿上，幻出寶坊金碧開。',64,'全唐诗/poet.song.76000.json','["紫霄峰下鸞谿上，幻出寶坊金碧開。", "沃野不辭常自獻，暮雲無事解歸来。", "永懷香火三生舊，想見松風萬壑哀。", "阿上笑中如問我，爲言詩膽尚崔嵬。"]'),
('fb8dfa01-2501-438e-943a-2914258392d3','贈道禪者','釋德洪','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','大河卷浪雪翻風，橋壓千艘卧彩虹。',64,'全唐诗/poet.song.76000.json','["大河卷浪雪翻風，橋壓千艘卧彩虹。", "岱嶽煙雲連絕域，北門樓閣礙層空。", "浪游荆椘重湖外，更在溈源疊嶂中。", "水餠槐芽動鄉思，近来歸夢與誰同。"]'),
('db74eacc-3796-4fc4-a994-836c8b1959c7','周庭秀愛湘中山水之勝定居十餘年宣和五年夏五月忽思吴中别余於湘上作此送之','釋德洪','宋','宋诗','song-poetry','','[]','詞刃平生工斫伐，探懷每欲取公侯。',64,'全唐诗/poet.song.76000.json','["詞刃平生工斫伐，探懷每欲取公侯。", "朅来世事懶經意，醉看湘山不轉頭。", "忽憶歸吴泛千里，偶然盡室載孤舟。", "却將揮翰風雷手，且釣華亭萬頃秋。"]'),
('261f4563-fe34-454f-81d2-979a3253a5da','題悟宗壁','釋德洪','宋','宋诗','song-poetry','','[]','到寺回身望衆峰，一堂疏快萬緣空。',64,'全唐诗/poet.song.76000.json','["到寺回身望衆峰，一堂疏快萬緣空。", "槲林曲折通幽徑，蓮蕩凋零退晚紅。", "師已灰心增夏臘，我今霜鬢撒秋風。", "亦知旁舍多佳士，香火他年願此同。"]'),
('fe93ed6b-619d-4f66-959a-727d0536fbb3','過陵水縣補東坡遺','釋德洪','宋','宋诗','song-poetry','','[]','白沙翠竹並江流，小縣炊煙晚雨收。',64,'全唐诗/poet.song.76000.json','["白沙翠竹並江流，小縣炊煙晚雨收。", "蒼蘚色侵盤馬地，稻花香入放衙樓。", "過廳客聚觀燈網，趁市人歸旋喚舟。", "意適忽忘身是客，語音無伴始生愁。"]'),
('36b1fb7e-cf87-4a3e-b438-4f30d1dfbb89','夜歸示卓道人','釋德洪','宋','宋诗','song-poetry','','[]','心知家本住仇池，傲睨人間老變衰。',64,'全唐诗/poet.song.76000.json','["心知家本住仇池，傲睨人間老變衰。", "兩鬢京塵初邂逅，一尊川語問歸期。", "勸沽何處禽知我，含笑誰家花隔籬。", "天水摹胡颶風作，夜歸江路月相随。"]'),
('b2416323-8c25-4589-a2c4-f27b7379adcb','雪詩','釋德洪','宋','宋诗','song-poetry','','[]','千巖雨雪黄昏後，一室香燈一寢餘。',64,'全唐诗/poet.song.76000.json','["千巖雨雪黄昏後，一室香燈一寢餘。", "此夕鄉關入歸夢，明朝雲物記曾書。", "地罏不獨聞瓶泣，山果時驚落屋除。", "清境鼎来勞應接，暮年生計未全疏。"]'),
('21f3eeb2-2441-45b3-92e8-476703e9697f','題王教授艇齋','釋德洪','宋','宋诗','song-poetry','','[]','宴居端若寄虚舟，三峡詞源日倒流。',64,'全唐诗/poet.song.76000.json','["宴居端若寄虚舟，三峡詞源日倒流。", "慣與衣冠游泮水，坐看圖史認瀛洲。", "胸中耿耿觀瀾術，物外悠悠涉世謀。", "莫謂縦横止容膝，濟川林葉此中求。"]'),
('015cc0b5-7aef-4f6f-be1e-892d642f2880','吾山風物如故園而甚僻余居月餘愛之將此卜居二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','此生於世已無求，况有村原事事幽。',64,'全唐诗/poet.song.76000.json','["此生於世已無求，况有村原事事幽。", "乞谷住山真素志，栽田博飯是良謀。", "别坡筍蕨春兼採，遶舍桑麻歲倍收。", "强健自能營飽暖，塵埃回首謾悠悠。"]'),
('ea6a8808-11a5-47e5-a3ec-983930c508a4','吾山風物如故園而甚僻余居月餘愛之將此卜居二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','風物淳真似故丘，茅茨結處自深幽。',64,'全唐诗/poet.song.76000.json','["風物淳真似故丘，茅茨結處自深幽。", "竹西鄰舍頗相近，客至須供良甚謀。", "燈火夜窗衣自補，豐登秋畝稻重收。", "安閒有此支餘歲，更欲驅馳亦謬悠。"]'),
('569c3b2e-3373-4e6c-8fe0-0cc5fdc30a36','送楞嚴經珣維那','釋德洪','宋','宋诗','song-poetry','','[]','尸羅清浄心清浄，寄迹南臺亦偶然。',64,'全唐诗/poet.song.76000.json','["尸羅清浄心清浄，寄迹南臺亦偶然。", "室掩香燈見行道，壁懸巾屨伴孤禪。", "寶書獨欲煩君誦，法力真期迨我先。", "細味此詩如實錄，他年僧史定須編。"]'),
('b665f6df-d99f-4065-9bf0-c897b8252883','謝嶽麓光老惠臨濟頂相','釋德洪','宋','宋诗','song-poetry','','[]','瘦骨孤標韻絕倫，傳聞宗派出雲門。',64,'全唐诗/poet.song.76000.json','["瘦骨孤標韻絕倫，傳聞宗派出雲門。", "收藏畫裏三玄老，分付湘中十世孫。", "罵佛風神疑正怒，打僧氣宇尚驚群。", "能言滅却正法眼，不負灘頭毒手恩。"]'),
('ccaa90d0-67bc-4cfa-b6f9-62dbf4860ea0','送珠上人泐潭拜塔','釋德洪','宋','宋诗','song-poetry','','[]','泐潭卧龍今不見，空有遺珠留世間。',64,'全唐诗/poet.song.76000.json','["泐潭卧龍今不見，空有遺珠留世間。", "圓轉自然離鑛穢，光明聊復祕形山。", "随師受嚫前身事，披掌猶存此日還。", "言不走盤無影迹，方知生死不相關。"]'),
('252dc6bb-8cf3-4a81-93ba-4cbec8e896ae','題龍王枯木堂','釋德洪','宋','宋诗','song-poetry','','[]','異種靈苗著四方，謾將名字挂虚堂。',64,'全唐诗/poet.song.76000.json','["異種靈苗著四方，謾將名字挂虚堂。", "道林可惜昏嵐掩，枯木那知在處芳。", "韶石曾聞傲煙瘴，焦山今已飽風霜。", "陽陂且喜根株茂，雪裏花開爛熳香。"]'),
('2fbe05f9-c574-47cc-96b2-6adf869fe60c','送海印奭老住東林','釋德洪','宋','宋诗','song-poetry','','[]','湘容嶽色中秋後，古寺閑房小寢餘。',64,'全唐诗/poet.song.76000.json','["湘容嶽色中秋後，古寺閑房小寢餘。", "掃徑箒粘新落葉，開窗風掩讀殘書。", "吹雲又作他山去，種漆何時伴我居。", "洞上閑名猶在世，未應容易與人除。"]'),
('833bb9fa-ebcb-441b-b017-475541e20b44','余至清修别希一禪師津發如老媪扶女外車其義風可以起頽俗將發作此','釋德洪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','驚風急雨中秋後，回首長沙杳靄間。',64,'全唐诗/poet.song.76000.json','["驚風急雨中秋後，回首長沙杳靄間。", "迎送初辭大藩府，逍遥来看小廬山。", "故人情義千鈞重，行客生涯一葉閑。", "明日旅亭勞晝夢，孤峰標格不容攀。"]'),
('abce4570-7c97-4b8e-a277-0379d2760be7','題壓波閣','釋德洪','宋','宋诗','song-poetry','','[]','雪玉在躬賢令尹，江山約束入宏規。',64,'全唐诗/poet.song.76000.json','["雪玉在躬賢令尹，江山約束入宏規。", "驚波濺岸憑陵□，傑閣控雲彈壓之。", "霧斂塵清閑縦目，蜂争螘分想當時。", "邦人凖擬朱欄外，安著他年惠愛碑。"]'),
('607eeab4-5ec1-463e-9150-89944d0d1763','次韻賈令尹題裴公亭','釋德洪','宋','宋诗','song-poetry','','[]','獨憑危欄眼力窮，當年勝踐想遺風。',64,'全唐诗/poet.song.76000.json','["獨憑危欄眼力窮，當年勝踐想遺風。", "歌喉雲杪殷餘韻，笑靨尊前發醉紅。", "世相難逃朝夕改，山容不老古今同。", "議郎筆力回春色，摹寫都藏畫牒中。"]'),
('9c8b4c46-739c-443f-bf1b-bc41499c1afb','余往漢上清修白鹿二老送至龍牙作此别之','釋德洪','宋','宋诗','song-poetry','','[]','因法相逢亦一時，雲泉所至共娱嬉。',64,'全唐诗/poet.song.76000.json','["因法相逢亦一時，雲泉所至共娱嬉。", "怪君追送不辭遠，知我從来未有期。", "醖造離愁成獨笑，欺凌秋色有新詩。", "閻浮掌上訶梨勒，去住休纒愛見悲。"]'),
('be9a0947-3610-416e-b8e0-2978861ef48b','雪夜至明教寄王路分舍人','釋德洪','宋','宋诗','song-poetry','','[]','雪夜山中還獨宿，地罏深煗紙窗明。',64,'全唐诗/poet.song.76000.json','["雪夜山中還獨宿，地罏深煗紙窗明。", "百年有限身今老，一枕無求夢自清。", "弟子分燈成保社，故人持節頓江城。", "瘴痾疏快諸緣浄，卧聽摧簷瀉竹聲。"]'),
('7fa4132e-8fd8-40aa-8dff-b1dc6105ef27','訪雙池老不遇其子覺先求詩爲作此','釋德洪','宋','宋诗','song-poetry','','[]','芒鞵竹杖快新晴，天迥游絲百尺輕。',64,'全唐诗/poet.song.76000.json','["芒鞵竹杖快新晴，天迥游絲百尺輕。", "沃若柔桑連野綠，炯如白鳥照溪明。", "逢山有寺幽欣集，對客開軒午夢清。", "曦竟未回憑閣久，忽聞高柳子規聲。"]'),
('92374a0a-d967-4d95-aa71-d320099891f5','寂音泉','釋德洪','宋','宋诗','song-poetry','','[]','水靈有源不知處，但見方沼供無窮。',64,'全唐诗/poet.song.76000.json','["水靈有源不知處，但見方沼供無窮。", "俯波下看遠山色，卷霧忽驚清鏡空。", "危亭快若望霜曉，江岸□□□陰風。", "宜呼此泉作檀越，歲致萬斛無凶豐。"]'),
('daecbb35-b648-444c-b1fc-7a2d9dac84c0','燈禪師出蜀住此山十年爲作南食且約同住作此以贈','釋德洪','宋','宋诗','song-poetry','','[]','少年出蜀今耆艾，十見襄陽浩蕩春。',64,'全唐诗/poet.song.76000.json','["少年出蜀今耆艾，十見襄陽浩蕩春。", "山近京畿看愈好，食兼虜饌味尤真。", "君今避世成深隱，我欲移菴結近鄰。", "相對無嫌太岑寂，待添明月作三人。"]'),
('08a5e23e-a887-462e-be4b-6be39dda030d','襄州亂後逢端州依上人','釋德洪','宋','宋诗','song-poetry','','[]','漢上相逢兵火後，蒼顔華髪兩摧頽。',64,'全唐诗/poet.song.76000.json','["漢上相逢兵火後，蒼顔華髪兩摧頽。", "塵清霧斂閑身在，螘分蜂争一笑開。", "志捍叢林山剔卓，義規朋友玉崔嵬。", "瓦精决舌休皮相，曾見淄州古佛来。"]'),
('b0205389-0690-46e2-9a8a-af4e03d99774','和濟之通判日夜懷祖穎諸公','釋德洪','宋','宋诗','song-poetry','','[]','才高自是萬夫望，語妙人疑錦繡腸。',64,'全唐诗/poet.song.76000.json','["才高自是萬夫望，語妙人疑錦繡腸。", "新事驚嗟入詩律，故交契闊付凄傷。", "開書想見湖山好，他日懸知夜語長。", "獄屋豈能埋寶劍，斗牛長覺射龍光。"]'),
('834dce4d-2b13-4f6e-9f21-a9be5cd63a24','送勻工人謁蔡州使君','釋德洪','宋','宋诗','song-poetry','','[]','淮西氣宇蓋三軍，絕似平原舊使君。',64,'全唐诗/poet.song.76000.json','["淮西氣宇蓋三軍，絕似平原舊使君。", "今日孤城獨堅守，疾風勁草昔傳聞。", "龍蛇戲下唯呼姓，翰墨場中亦策勳。", "想見棠陰談我處，笑持茗盌辯如雲。"]'),
('fe663d45-5b35-4886-b482-5072d2aad6ef','寄盛羣玉','釋德洪','宋','宋诗','song-poetry','','[]','平生翰墨到精微，盛氏諸郎最白眉。',64,'全唐诗/poet.song.76000.json','["平生翰墨到精微，盛氏諸郎最白眉。", "氣訐曾窺豪士賦，初交先和野僧詩。", "謾勞清夢思相識，那料孤蹤晚見知。", "君看臨危用心處，何殊晏子解驂時。"]'),
('9abc52f2-ea88-43e9-bc0c-3e5c86304f88','十二月十八夜大雪注蓮經罷有僧来勸歸廬山僧去作此','釋德洪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','煙凝生怕席簾開，快煖偏宜榾柮柴。',64,'全唐诗/poet.song.76000.json','["煙凝生怕席簾開，快煖偏宜榾柮柴。", "夜久饑鼯嗅空案，夢驚鬭虎墮層崖。", "優曇花偈餘殘紙，薝蔔杯香自滿齋。", "折脚鐺安莫嫌穩，地偏人懶遂幽懷。"]'),
('38b95e0b-3625-4750-a906-26b25a4876ce','雪中','釋德洪','宋','宋诗','song-poetry','','[]','勢密連空若推下，随風起舞不容追。',64,'全唐诗/poet.song.76000.json','["勢密連空若推下，随風起舞不容追。", "門閑走犬無深巷，樹暗棲鴉有剩枝。", "旋撥地罏通宿火，却呵凍手寫新詩。", "軒窗秀發驚清晝，萬壑春歸說向誰。"]'),
('8e8b0dba-d65f-464d-9017-360c514f637a','再會莊德祖大夫','釋德洪','宋','宋诗','song-poetry','','[]','平昔才名似孟宗，暮年一鉢並巖叢。',64,'全唐诗/poet.song.76000.json','["平昔才名似孟宗，暮年一鉢並巖叢。", "交朋半在青雲上，意氣都消白眼中。", "龐老尚餘靈照在，伯鸞應許孟光同。", "君看張柬之爲相，不害荆州秃鬢翁。"]'),
('bbb8874d-7587-4ea7-be03-256108db66f0','與蔡楊州','釋德洪','宋','宋诗','song-poetry','','[]','五馬東来數月間，十州人物帖然安。',64,'全唐诗/poet.song.76000.json','["五馬東来數月間，十州人物帖然安。", "池邊芳草新吟罷，樓外遥山晝卧看。", "鈴閣蠟煙秋色晚，譙門銅漏夜聲寒。", "雖然自是雲林客，猶把風流作話端。"]'),
('e8f3ad45-4cf7-4dea-92cf-294d2ef3bc49','唐生能視手文乞詩戲贈之','釋德洪','宋','宋诗','song-poetry','','[]','草蕪門徑過從少，那料秋来夜話同。',64,'全唐诗/poet.song.76000.json','["草蕪門徑過從少，那料秋来夜話同。", "屋漏移牀時發笑，粥稠當飯巧於窮。", "我留癡絕傳身後，君見平生似掌中。", "明日渡江應轉首，數峰無語晚連空。"]'),
('c1dd7013-b54c-48b1-a778-f2c24a2bdded','贈麻城接待僧勝上人','釋德洪','宋','宋诗','song-poetry','','[]','綠髪凋零白業增，住菴随分有規繩。',64,'全唐诗/poet.song.76000.json','["綠髪凋零白業增，住菴随分有規繩。", "爲分一邑人家飯，普供十方雲水僧。", "掃徑客来圓笑靨，開軒雲破露寒層。", "君看擊桶金牛手，坐續山頭柏子燈。"]'),
('180ba8ab-5515-45f6-b888-8c7355aa1ae8','夏日同安示阿崇諸衲子','釋德洪','宋','宋诗','song-poetry','','[]','老眼朅来驚節物，閑同諸子話江鄉。',64,'全唐诗/poet.song.76000.json','["老眼朅来驚節物，閑同諸子話江鄉。", "試茶正要旋烘盞，煮餅且令深注湯。", "忽憶海山餐荔子，更思湘水劈蓮房。", "夏休便可車輪去，菌蕈秋肥趁及嘗。"]'),
('c2b84667-29cb-4b59-8b98-46b1e98f3e97','三月二十八日棗柏大士生辰六首  其一','釋德洪','宋','宋诗','song-poetry','','[]','深觀諸佛刹那際，三世十方無遁形。',64,'全唐诗/poet.song.76000.json','["深觀諸佛刹那際，三世十方無遁形。", "已盡凡情不顛倒，如除目翳自光明。", "意俱大地山河喪，心與空花夢幻生。", "垂手遇緣攜法界，美髯跣足散衣行。"]'),
('1a4dba15-a9bf-4b22-9d34-dc9fc51178ea','三月二十八日棗柏大士生辰六首  其二','釋德洪','宋','宋诗','song-poetry','','[]','二天給侍慈忍象，一虎槖經常寂光。',64,'全唐诗/poet.song.76000.json','["二天給侍慈忍象，一虎槖經常寂光。", "意處世間離生滅，夢中塵刼浪遮藏。", "即真不必冠巾毁，絕染何妨棗柏嘗。", "提起超情無比句，夜来山雨落花香。"]'),
('33cb20b8-f23f-4b9c-adc4-72d26b254173','三月二十八日棗柏大士生辰六首  其三','釋德洪','宋','宋诗','song-poetry','','[]','青春徑去不小住，天迥游絲增眼寒。',64,'全唐诗/poet.song.76000.json','["青春徑去不小住，天迥游絲增眼寒。", "想見手提大千界，翛然身現一毛端。", "若存情見智山隔，但斷攀緣業海乾。", "面目分明今日是，敢將棗柏薦盤餐。"]'),
('2892761f-b3c0-45c6-9951-016a2053b20e','三月二十八日棗柏大士生辰六首  其四','釋德洪','宋','宋诗','song-poetry','','[]','生死鶻崙無背面，摩挲把玩久嗟咨。',64,'全唐诗/poet.song.76000.json','["生死鶻崙無背面，摩挲把玩久嗟咨。", "悟明必藉戒定慧，随順差成老病衰。", "净意即空良顯決，色身對現出思惟。", "千烹萬鍛知恩德，敢忘摩尼在鑛時。"]'),
('48beae9f-8dcc-4b36-aeb5-1d17cfd87ec7','三月二十八日棗柏大士生辰六首  其五','釋德洪','宋','宋诗','song-poetry','','[]','眼蓋人寰撚美髯，年年相見晚春前。',64,'全唐诗/poet.song.76000.json','["眼蓋人寰撚美髯，年年相見晚春前。", "摸蘇緣妄心俱盡，揩拭鮮陳念已圜。", "指下琴方纔發越，眉間毫相見無邊。", "微塵劫海依今住，生死何勞較後先。"]'),
('33cc5e39-e5b8-4418-b0d5-d2a83030c927','三月二十八日棗柏大士生辰六首  其六','釋德洪','宋','宋诗','song-poetry','','[]','一刹那際入正受，互參三世妙難思。',64,'全唐诗/poet.song.76000.json','["一刹那際入正受，互參三世妙難思。", "有情夢境依此住，無量劫海不移時。", "任運行藏難掩覆，随疑語默出思惟。", "大哉無比金剛句，世罕知之我獨知。"]'),
('79f93d69-cae8-43b6-871e-93e49306cbb0','十世觀音生辰六月二十六日二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','十世爲僧皆姓楊，死生游戲自隋唐。',64,'全唐诗/poet.song.76000.json','["十世爲僧皆姓楊，死生游戲自隋唐。", "鐵身自倒汝邪□，寫字無爲我道場。", "異迹著於無量壽，慈風不減普昭王。", "兩川顯化人皆識，今日全身不掩藏。"]'),
('f64f7aa8-4dba-40c8-8799-dbd06c909f31','十世觀音生辰六月二十六日二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','曇相禪師第二身，蟬聯十世姓楊人。',64,'全唐诗/poet.song.76000.json','["曇相禪師第二身，蟬聯十世姓楊人。", "女兄慧辯成勍敵，弟子悲欣記夙因。", "解使邪迷知有佛，自呼名字凛如神。", "平生接物多方便，何似今朝一句親。"]'),
('3ff5ccb2-2b9e-400d-9ae5-c51b6404fea6','蔡藏用生辰','釋德洪','宋','宋诗','song-poetry','','[]','非煙雲子釀新晴，争看麒麟墮地行。',64,'全唐诗/poet.song.76000.json','["非煙雲子釀新晴，争看麒麟墮地行。", "悉達已聞今日誕，優曇知復爲誰榮。", "已驚久視方瞳碧，更覺藏年玉骨清。", "曾伴麻姑家法在，願随風馭到蓬瀛。"]'),
('134053bc-b126-47c2-90b5-8f5f69769450','八月二十三日蔡元中生辰','釋德洪','宋','宋诗','song-poetry','','[]','纔過中秋今幾日，夜来海月上三更。',64,'全唐诗/poet.song.76000.json','["纔過中秋今幾日，夜来海月上三更。", "夢魂傳得天書至，窗户俱明廐馬驚。", "骨相終當爲國器，兒聲初已識人英。", "明年慶節山中友，金屋憐君夜直清。"]'),
('a6426787-4258-4702-8aab-62e29891912f','劉彭年知縣生辰','釋德洪','宋','宋诗','song-poetry','','[]','清規懿德古難陪，秋盡民歌慶節来。',64,'全唐诗/poet.song.76000.json','["清規懿德古難陪，秋盡民歌慶節来。", "瑞應草餘雙葉在，優曇花適一枝開。", "鶯嬌妙管傳佳句，玉膩新粧獻壽杯。", "慈母千齡何所願，早看賢子踐三台。"]'),
('ad15729c-a50b-4a46-b496-ed39d858b7fa','中廬趙令生辰','釋德洪','宋','宋诗','song-poetry','','[]','孟夏南風草木薰，民歌慶節喜傳聞。',64,'全唐诗/poet.song.76000.json','["孟夏南風草木薰，民歌慶節喜傳聞。", "今朝雪乙呈雙瑞，後夜冰輪滿九分。", "材業牛刀試小邑，家聲天派落層雲。", "吞舟豈久容涔足，禁殿論思政要君。"]'),
('c235e674-67af-4da6-aa1f-f1f7f07a2fed','寄黄嗣深使君二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','江夏家聲世所聞，無雙千頃典刑存。',64,'全唐诗/poet.song.76000.json','["江夏家聲世所聞，無雙千頃典刑存。", "肅嚴郡邑霜分曉，照映簪纓玉粹温。", "樓迥峴雲供醉望，夜晴漢月洗吟魂。", "行將補衮調羮手，却執元圭侍至尊。"]'),
('1bfad723-bf78-48c2-a3c7-cff4e9433da0','寄黄嗣深使君二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','身世浮雲偶尚存，白衣蒼狗與誰論。',64,'全唐诗/poet.song.76000.json','["身世浮雲偶尚存，白衣蒼狗與誰論。", "夢中不記金門宿，醉裏曾看玉海翻。", "尚有驚魂纒瘴霧，已甘華髪老江濱。", "枯荄欲藉陽和暖，催發新来雨露恩。"]'),
('a62464e1-5751-45fd-bdf1-9a07c1865aa4','李道夫母挽辭','釋德洪','宋','宋诗','song-poetry','','[]','縉紳家法想清規，平昔高風此一時。',64,'全唐诗/poet.song.76000.json','["縉紳家法想清規，平昔高風此一時。", "居約雲山夫有道，客陪房杜子無疑。", "九原淚濕老莱袂，千字碑傳幼婦詞。", "他日欲尋賢母墓，北山松雨路人悲。"]'),
('8e82da79-d9fe-4580-8123-bd253ea113b7','鄧循道父挽辭二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','苦冰潔蘗是行藏，一節無求老更剛。',64,'全唐诗/poet.song.76000.json','["苦冰潔蘗是行藏，一節無求老更剛。", "好在縉紳師儉德，尚餘閭里說謙光。", "陰功隱祕天應錄，遺訓丁寧世共傷。", "勿謂不身嘗報施，故應遺澤在諸郎。"]'),
('7afc4f23-80ef-417e-95e9-c0b7318e81f5','鄧循道父挽辭二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','一生純德無遺恨，千字埋名有逸辭。',64,'全唐诗/poet.song.76000.json','["一生純德無遺恨，千字埋名有逸辭。", "墓隧嫩泉誰種玉，書齋子硯自生芝。", "音容已作終天痛，歲月真成罔極悲。", "擁鼻功名知不免，空將淚眼看風枝。"]'),
('7510b947-d3a9-4a96-829b-c7e9d4aa900b','代人上李龍圖并廉使致語十首  其一','釋德洪','宋','宋诗','song-poetry','','[]','射圃閑亭酒半醺，手柔弓燥氣超羣。',64,'全唐诗/poet.song.76000.json','["射圃閑亭酒半醺，手柔弓燥氣超羣。", "已驚百步穿楊綵，會看雙鵰落塞雲。", "且集旌旗森畫戟，未輸文字飲金樽。", "治朝文武須兼用，萬壽稱觴祝至尊。"]'),
('6bc0d511-6c46-4c4e-a042-e2f18fd80755','代人上李龍圖并廉使致語十首  其二','釋德洪','宋','宋诗','song-poetry','','[]','太平無象樂年豐，况值疆埸久已空。',64,'全唐诗/poet.song.76000.json','["太平無象樂年豐，况值疆埸久已空。", "賓主獻酬成雅集，江山談笑助清風。", "良辰美景開金斝，緩带輕裘控角弓。", "鼙鼓急催齊指目，大侯的處中飛鴻。"]'),
('b1b4c4ec-2a99-403a-9d68-8bf88e9f9617','代人上李龍圖并廉使致語十首  其三','釋德洪','宋','宋诗','song-poetry','','[]','雨後園林花木新，傳聞千騎出城闉。',64,'全唐诗/poet.song.76000.json','["雨後園林花木新，傳聞千騎出城闉。", "異能未中侯中鵠，佳氣先浮盞面春。", "畫鼓繡鞾筵奏曲，紅粧細馬地無塵。", "長沙萬古民争說，賓主人英伎絕倫。"]'),
('a294d1b5-c9d6-4041-9cab-c9fd612e37da','代人上李龍圖并廉使致語十首  其四','釋德洪','宋','宋诗','song-poetry','','[]','聞道長沙賢太守，漆瞳玉頬照衡湘。',64,'全唐诗/poet.song.76000.json','["聞道長沙賢太守，漆瞳玉頬照衡湘。", "訟庭散後賓朋集，民瘼蘇来禮樂昌。", "且展綺筵陪勝餞，何須檀板閙紅籹。", "曉無探騎？邊檄，願獻君王萬壽觴。"]'),
('6f75be5e-670e-4989-9bfb-98ff5eaefc6f','代人上李龍圖并廉使致語十首  其五','釋德洪','宋','宋诗','song-poetry','','[]','細柳成陰花滿徑，晚来鉦鼓導朱輪。',64,'全唐诗/poet.song.76000.json','["細柳成陰花滿徑，晚来鉦鼓導朱輪。", "河東鸑鷟三英傑，天上麒麟兩俊人。", "閑裏笑談清似玉，盃中賢聖韻如春。", "引弓一箭驚穿札，堵立懽聲快吏民。"]'),
('f70649eb-96b9-4794-a162-fe5b1b46d6d5','代人上李龍圖并廉使致語十首  其六','釋德洪','宋','宋诗','song-poetry','','[]','繡衣天使志澄清，五馬賢侯見典刑。',64,'全唐诗/poet.song.76000.json','["繡衣天使志澄清，五馬賢侯見典刑。", "公退鉦聲聞射圃，日高槐影覆閑庭。", "共看酒蟻浮瓊斝，不廢花輪遶畫屏。", "銀燭紅紗侵夜色，醉歸明月淡疏星。"]'),
('19ccb115-f1b8-48a4-a0a7-4c62665634b2','代人上李龍圖并廉使致語十首  其七','釋德洪','宋','宋诗','song-poetry','','[]','隴西家世到仍雲，許國清忠蓋代聞。',64,'全唐诗/poet.song.76000.json','["隴西家世到仍雲，許國清忠蓋代聞。", "有道風流賢太守，無雙才氣舊將軍。", "整弦使者情和易，承附諸郎藝逸群。", "便好畫圖收拾取，要傳盛事滿湘濱。"]'),
('9c22490f-7b0a-4bf8-9e4c-397410c71d74','代人上李龍圖并廉使致語十首  其八','釋德洪','宋','宋诗','song-poetry','','[]','如雲旌騎照湘江，千里農桑楚大邦。',64,'全唐诗/poet.song.76000.json','["如雲旌騎照湘江，千里農桑楚大邦。", "中鵠才高今有武，射鵰伎巧古無雙。", "錦袍雅稱黄金带，瓊液尤宜白玉霜。", "笑挽雕弓如滿月，萬人驚懾已心降。"]'),
('8775adda-8722-40ef-9a4f-f1f4d3d825a8','代人上李龍圖并廉使致語十首  其九','釋德洪','宋','宋诗','song-poetry','','[]','無雙自昔擅家聲，春色都還細柳營。',64,'全唐诗/poet.song.76000.json','["無雙自昔擅家聲，春色都還細柳營。", "中的聊爲萬人傑，飛觥要使百壺傾。", "三湘父老傳風化，十郡兒童識姓名。", "武緯文經俱不乏，桑弧蓬矢見平生。"]'),
('16d7db43-bef7-45af-8493-840d5d75e790','代人上李龍圖并廉使致語十首  其一○','釋德洪','宋','宋诗','song-poetry','','[]','畫鼓曉晴三擊罷，如雲兵騎整全威。',64,'全唐诗/poet.song.76000.json','["畫鼓曉晴三擊罷，如雲兵騎整全威。", "俄聞畫角胡笳斷，忽覺華堂羽箭飛。", "一百步中精力巧，數重圍內見心機。", "風流太守兼文武，扶路争看踏月歸。"]'),
('54432d1e-c5fa-44c6-8d7a-e1c72b511730','代夏均甫宴人致語一首','釋德洪','宋','宋诗','song-poetry','','[]','九齡風度照峿臺，宴寢香凝畫戟開。',64,'全唐诗/poet.song.76000.json','["九齡風度照峿臺，宴寢香凝畫戟開。", "歸國已傾天下耳，駐軒宜舉故人盃。", "青天白日心常在，附驥攀鱗志未摧。", "累足待公成相業，更随風馭看蓬莱。"]'),
('cd89aafe-694c-4375-8aea-b783197022c5','余在制勘院晝卧念故山經行處用空山無人水流花開爲韻寄山中道友八首  其一','釋德洪','宋','宋诗','song-poetry','','[]','山帔蒙霜頂，跏趺巖石中。',24,'全唐诗/poet.song.76000.json','["山帔蒙霜頂，跏趺巖石中。", "夜寒虎痾痒，林静月升空。"]'),
('c37df6a0-d158-44ef-89c3-ba4bd26667f8','余在制勘院晝卧念故山經行處用空山無人水流花開爲韻寄山中道友八首  其二','釋德洪','宋','宋诗','song-poetry','','[]','掃徑偶停箒，幽懷凝佇間。',24,'全唐诗/poet.song.76000.json','["掃徑偶停箒，幽懷凝佇間。", "暮樵迷向背，餘響答空山。"]'),
('1ae44c49-84c9-44f0-9ec2-6cbdb0687ba9','余在制勘院晝卧念故山經行處用空山無人水流花開爲韻寄山中道友八首  其三','釋德洪','宋','宋诗','song-poetry','','[]','數峰横杳靄，空翠疑有無。',24,'全唐诗/poet.song.76000.json','["數峰横杳靄，空翠疑有無。", "落日誰同看，啼猿我欲呼。"]'),
('98d4bdbe-9ef7-498c-806f-1e0e8f39195a','余在制勘院晝卧念故山經行處用空山無人水流花開爲韻寄山中道友八首  其四','釋德洪','宋','宋诗','song-poetry','','[]','新晴收雨脚，宿霧隔花身。',24,'全唐诗/poet.song.76000.json','["新晴收雨脚，宿霧隔花身。", "睡美不知曉，啼禽解喚人。"]'),
('cad2fe4f-9d57-49ad-ab89-0dfe828aa964','余在制勘院晝卧念故山經行處用空山無人水流花開爲韻寄山中道友八首  其五','釋德洪','宋','宋诗','song-poetry','','[]','舍南一曲溪，春漲半篙水。',24,'全唐诗/poet.song.76000.json','["舍南一曲溪，春漲半篙水。", "去作落崖聲，雪花濺山翠。"]'),
('be5f6a04-69d5-4bbf-885d-eec5cb99025b','余在制勘院晝卧念故山經行處用空山無人水流花開爲韻寄山中道友八首  其六','釋德洪','宋','宋诗','song-poetry','','[]','墮薪行且拾，愛此林徑幽。',24,'全唐诗/poet.song.76000.json','["墮薪行且拾，愛此林徑幽。", "偶坐欹斜石，忽逢清淺流。"]'),
('b56604cd-9ec7-4213-9f61-2318379da832','余在制勘院晝卧念故山經行處用空山無人水流花開爲韻寄山中道友八首  其七','釋德洪','宋','宋诗','song-poetry','','[]','明白菴前路，辛夷樹已花。',24,'全唐诗/poet.song.76000.json','["明白菴前路，辛夷樹已花。", "竊香知犯律，匹練墨翻鴉。"]'),
('d5c1b3ca-f888-4426-a859-a143e577219d','余在制勘院晝卧念故山經行處用空山無人水流花開爲韻寄山中道友八首  其八','釋德洪','宋','宋诗','song-poetry','','[]','棐几自香滑，寶時一開道。',24,'全唐诗/poet.song.76000.json','["棐几自香滑，寶時一開道。", "根根九連絡，清境更壅培。"]'),
('202f93aa-37f4-4cf3-a1b1-87b212af2eea','病中寄山中故舊八首  其一','釋德洪','宋','宋诗','song-poetry','','[]','室空無侍者，唯置一匡牀。',24,'全唐诗/poet.song.76000.json','["室空無侍者，唯置一匡牀。", "萬事俱衰落，但餘常寂光。"]'),
('dcb697b8-ffb4-4535-b87c-2ae0c09bafa6','病中寄山中故舊八首  其二','釋德洪','宋','宋诗','song-poetry','','[]','身心俱寂滅，想念亦紛紜。',24,'全唐诗/poet.song.76000.json','["身心俱寂滅，想念亦紛紜。", "此是維摩老，無生不二門。"]'),
('891354c8-a83f-43fc-95b3-7bddf7eeb4c1','病中寄山中故舊八首  其三','釋德洪','宋','宋诗','song-poetry','','[]','我心若有生，夢境堪把玩。',24,'全唐诗/poet.song.76000.json','["我心若有生，夢境堪把玩。", "目前今洞然，底處藏憂患。"]'),
('99eb1d5f-2cab-4cce-af47-7c9fdbcce96b','病中寄山中故舊八首  其四','釋德洪','宋','宋诗','song-poetry','','[]','雲門達法空，玄沙見根蒂。',24,'全唐诗/poet.song.76000.json','["雲門達法空，玄沙見根蒂。", "兩翁脱生死，一味多爽氣。"]'),
('3f5821b7-8d52-40c9-8829-e772a044e29a','病中寄山中故舊八首  其五','釋德洪','宋','宋诗','song-poetry','','[]','心光本無礙，慳貪空蓋纒。',24,'全唐诗/poet.song.76000.json','["心光本無礙，慳貪空蓋纒。", "一切但仍舊，自然常現前。"]'),
('3e2e2367-0739-4f8a-9589-ee9a15440163','病中寄山中故舊八首  其六','釋德洪','宋','宋诗','song-poetry','','[]','靈源坐癡兀，萬事付天真。',24,'全唐诗/poet.song.76000.json','["靈源坐癡兀，萬事付天真。", "何事禪和子，相逢礙塞人。"]'),
('70841c43-62d2-42df-8a52-cbb3a09f3738','病中寄山中故舊八首  其七','釋德洪','宋','宋诗','song-poetry','','[]','臨濟十世孫，泐潭克家嗣。',24,'全唐诗/poet.song.76000.json','["臨濟十世孫，泐潭克家嗣。", "一唱主中賓，不容留意地。"]'),
('e92530ca-76e8-4143-beb5-0af7af65268e','病中寄山中故舊八首  其八','釋德洪','宋','宋诗','song-poetry','','[]','本色出家兒，機輪盤珠走。',24,'全唐诗/poet.song.76000.json','["本色出家兒，機輪盤珠走。", "須學老華亭，用處無滲漏。"]'),
('36dd3fd5-eafb-4cfa-a5ed-3d8a4247876a','明白菴六首  其一','釋德洪','宋','宋诗','song-poetry','','[]','如来功德力，內外悉清浄。',24,'全唐诗/poet.song.76000.json','["如来功德力，內外悉清浄。", "念起勿随之，自然心無病。"]'),
('5fd9c983-7fe0-4ae9-a8bd-3600ccf44768','明白菴六首  其二','釋德洪','宋','宋诗','song-poetry','','[]','形與佛祖等，道致人天護。',24,'全唐诗/poet.song.76000.json','["形與佛祖等，道致人天護。", "戒浄福人天，心空同佛祖。"]'),
('7ed7924c-e735-4356-b232-b12eb265f722','明白菴六首  其三','釋德洪','宋','宋诗','song-poetry','','[]','石火機鋒上，那容著意根。',24,'全唐诗/poet.song.76000.json','["石火機鋒上，那容著意根。", "透情名出世，離念是知恩。"]'),
('b1344629-65d8-467c-aaef-fd8a2d6db6e6','明白菴六首  其四','釋德洪','宋','宋诗','song-poetry','','[]','瑞鹿吾所慕，勇决敢不勉。',24,'全唐诗/poet.song.76000.json','["瑞鹿吾所慕，勇决敢不勉。", "夜来歸夢清，疑在啼猨巘。"]'),
('06e1b1d0-aad7-48b2-9061-33565ee91965','明白菴六首  其五','釋德洪','宋','宋诗','song-poetry','','[]','老去一菴深，聊將自浄心。',24,'全唐诗/poet.song.76000.json','["老去一菴深，聊將自浄心。", "要當酬佛祖，終不負叢林。"]'),
('f8fe55ca-9231-4cc2-a1a5-058187fd8166','明白菴六首  其六','釋德洪','宋','宋诗','song-poetry','','[]','歸路山花發，欣然折一枝。',24,'全唐诗/poet.song.76000.json','["歸路山花發，欣然折一枝。", "動容揚古路，不墮悄然機。"]'),
